const EDITION_REPLACED_COLLECTIONS = new Set(["tutorialSteps", "rulesChapters", "faqEntries"]);

function applyEdition3Defaults() {
  const edition = window.MILLENNIUM_V3_CONTENT;
  if (!edition) return;
  Object.assign(DEFAULT_CONTENT.settings, edition.settings || {}, { seedVersion: SEED_VERSION });
  Object.entries(edition.collections || {}).forEach(([collection, incoming]) => {
    if (!Array.isArray(incoming)) return;
    if (EDITION_REPLACED_COLLECTIONS.has(collection)) {
      DEFAULT_CONTENT[collection] = incoming.map((entry) => ({ ...entry }));
      return;
    }
    const existing = Array.isArray(DEFAULT_CONTENT[collection]) ? DEFAULT_CONTENT[collection] : [];
    const byId = new Map(existing.map((entry) => [entry.id, entry]));
    incoming.forEach((entry) => {
      if (!entry?.id) return;
      byId.set(entry.id, { ...(byId.get(entry.id) || {}), ...entry });
    });
    DEFAULT_CONTENT[collection] = [...byId.values()];
  });
}

applyEdition3Defaults();
