const $ = (selector) => document.querySelector(selector);
const $$ = (selector) => Array.from(document.querySelectorAll(selector));

function esc(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

const MEDIA_SPECS = Object.freeze({
  avatar: [320, 320],
  portrait: [800, 1000],
  banner: [1600, 900],
  event: [1280, 720],
  map: [1280, 720],
  thumbnail: [400, 300],
  "pet-card": [768, 1024],
  "pet-thumbnail": [320, 320],
  sigil: [512, 512],
  generic: [640, 480],
});

function mediaAttrs(kind = "generic", loading = "lazy") {
  const [width, height] = MEDIA_SPECS[kind] || MEDIA_SPECS.generic;
  const safeLoading = loading === "eager" ? "eager" : "lazy";
  return `width="${width}" height="${height}" loading="${safeLoading}" decoding="async"`;
}

function mediaSpecForImage(image) {
  const source = String(image?.getAttribute?.("src") || image?.currentSrc || "").toLowerCase();
  if (source.includes("sigilo") || image?.closest?.(".auth-sigil, .awakening-sigil-large")) return "sigil";
  if (source.includes("/pets/") || image?.closest?.(".pet-card, .gacha-reveal-art, .hunt-pet-runner")) {
    return source.includes("-thumb.") || image?.closest?.(".gacha-pool-grid, .tower-deck-pet, .featured-pet, .activity-scene") ? "pet-thumbnail" : "pet-card";
  }
  if (source.includes("/maps/") || image?.closest?.(".world-map-node, .hunt-expedition-scene, .cartography-session")) {
    return source.includes("-thumb.") || image?.closest?.(".codex-card-media") ? "thumbnail" : "map";
  }
  if (image?.matches?.(".home-hero-backdrop, .profile-banner") || image?.closest?.(".hero-profile-banner")) return "banner";
  if (image?.matches?.(".avatar") || image?.closest?.(".message-avatar, .home-hero-portrait")) return "avatar";
  if (image?.closest?.(".hero-profile-portrait, .awakening-avatar-shell")) return "portrait";
  if (image?.matches?.(".content-image") || image?.closest?.(".catalog-detail-modal, .registration-preview, .codex-card-media, .guild-card")) return "thumbnail";
  return "generic";
}

function normalizeRenderedImages(root = document) {
  if (!root?.querySelectorAll) return;
  const images = root.matches?.("img") ? [root] : Array.from(root.querySelectorAll("img"));
  images.forEach((image) => {
    const kind = mediaSpecForImage(image);
    const [width, height] = MEDIA_SPECS[kind] || MEDIA_SPECS.generic;
    if (!image.hasAttribute("alt")) image.setAttribute("alt", "");
    if (!image.hasAttribute("width")) image.setAttribute("width", String(width));
    if (!image.hasAttribute("height")) image.setAttribute("height", String(height));
    const eager = image.id === "authHeroImage" || image.matches(".home-hero-backdrop") || image.closest(".awakening-portrait-stage");
    if (!image.hasAttribute("loading")) image.setAttribute("loading", eager ? "eager" : "lazy");
    if (!image.hasAttribute("decoding")) image.setAttribute("decoding", "async");
  });
}


function humanizeAccessibleName(value) {
  return String(value || "")
    .replace(/[-_]+/g, " ")
    .replace(/\b\w/g, (letter) => letter.toUpperCase())
    .trim();
}

function normalizeRenderedAccessibility(root = document) {
  if (!root?.querySelectorAll) return;
  const controls = root.matches?.("input, select, textarea") ? [root] : Array.from(root.querySelectorAll("input, select, textarea"));
  controls.forEach((control) => {
    const hasName = Boolean(control.getAttribute("aria-label") || control.getAttribute("aria-labelledby") || control.labels?.length);
    if (hasName || control.type === "hidden") return;
    const nearby = control.closest("label")?.querySelector("span, strong")?.textContent?.trim();
    const fallback = nearby || control.getAttribute("placeholder") || humanizeAccessibleName(control.name || control.id || control.type || "Campo");
    if (fallback) control.setAttribute("aria-label", fallback);
  });

  const buttons = root.matches?.("button, [role='button']") ? [root] : Array.from(root.querySelectorAll("button, [role='button']"));
  buttons.forEach((button) => {
    const hasName = Boolean(button.getAttribute("aria-label") || button.getAttribute("aria-labelledby"));
    const text = button.textContent?.replace(/\s+/g, " ").trim() || "";
    if (hasName || /[\p{L}\p{N}]/u.test(text)) return;
    const fallback = button.getAttribute("title") || humanizeAccessibleName(button.dataset?.action || button.dataset?.nav || "Ação");
    if (fallback) button.setAttribute("aria-label", fallback);
  });

  const progressBars = root.matches?.("[role='progressbar']") ? [root] : Array.from(root.querySelectorAll("[role='progressbar']"));
  progressBars.forEach((bar) => {
    if (!bar.hasAttribute("aria-valuemin")) bar.setAttribute("aria-valuemin", "0");
    if (!bar.hasAttribute("aria-valuemax")) bar.setAttribute("aria-valuemax", "100");
    if (!bar.hasAttribute("aria-valuenow")) {
      const indicator = bar.querySelector("i, span");
      const width = Number.parseFloat(indicator?.style?.width || "");
      if (Number.isFinite(width)) bar.setAttribute("aria-valuenow", String(Math.max(0, Math.min(100, Math.round(width)))));
    }
  });

  const tabs = root.matches?.("[role='tab']") ? [root] : Array.from(root.querySelectorAll("[role='tab']"));
  tabs.forEach((tab) => {
    const selected = tab.getAttribute("aria-selected") === "true" || tab.getAttribute("aria-current") === "page" || tab.classList.contains("active");
    tab.setAttribute("aria-selected", String(selected));
    tab.tabIndex = selected ? 0 : -1;
  });

  const links = root.matches?.("a[target='_blank']") ? [root] : Array.from(root.querySelectorAll("a[target='_blank']"));
  links.forEach((link) => {
    const rel = new Set(String(link.rel || "").split(/\s+/).filter(Boolean));
    rel.add("noopener");
    rel.add("noreferrer");
    link.rel = [...rel].join(" ");
  });
}

function announceCurrentRoute() {
  const announcer = $("#routeAnnouncement");
  if (!announcer || announcer.dataset.route === state.view) return;
  announcer.dataset.route = state.view;
  announcer.textContent = `Área carregada: ${$("#viewTitle")?.textContent || VIEW_TITLES[state.view] || "Painel"}.`;
}

function syncGameplayVisibility(hidden = document.hidden) {
  state.runtimeSuspended = Boolean(hidden);

  const aim = state.activeAimSession;
  if (aim && !aim.finished) {
    aim.runtimePaused = Boolean(hidden);
    if (hidden && aim.frame) { window.cancelAnimationFrame(aim.frame); aim.frame = 0; }
    if (!hidden && aim.drawFrame && !aim.frame) {
      aim.lastFrame = performance.now();
      aim.frame = window.requestAnimationFrame(aim.drawFrame);
    }
  }

  const seals = state.activeSealSession;
  if (seals && !seals.finished) {
    if (hidden) {
      seals.runtimePaused = true;
      (seals.timers || []).forEach((timer) => window.clearTimeout(timer));
      seals.timers = [];
      document.querySelectorAll("[data-seal-symbol]").forEach((button) => { button.disabled = true; button.classList.remove("active"); });
    } else if (seals.runtimePaused) {
      seals.runtimePaused = false;
      presentSealRound(seals);
    }
  }

  const cartography = state.activeCartographySession;
  if (cartography && !cartography.finished) cartography.runtimePaused = Boolean(hidden);

  const tower = state.activeTowerSession;
  if (tower && !tower.finished) {
    tower.runtimePaused = Boolean(hidden);
    if (hidden && tower.animationFrame) { window.cancelAnimationFrame(tower.animationFrame); tower.animationFrame = null; }
    if (!hidden && tower.looping && !tower.animationFrame) {
      tower.lastFrame = performance.now();
      tower.animationFrame = window.requestAnimationFrame(() => runTowerFrame(tower));
    }
  }

  state.monsterBattleRuntimePaused = Boolean(hidden);
  if (hidden && state.monsterBattleTimer) {
    window.clearTimeout(state.monsterBattleTimer);
    state.monsterBattleTimer = 0;
  } else if (!hidden && state.monsterBattleAnimating && state.monsterBattleStep) {
    state.monsterBattleStep();
  }

  if (hidden) playSound.ctx?.suspend?.().catch(() => {});
}

function syncDocumentVisibility() {
  const hidden = document.hidden;
  document.documentElement.dataset.documentVisibility = hidden ? "hidden" : "visible";
  PERF_RUNTIME.setVisibility?.(hidden);
  syncGameplayVisibility(hidden);
  startGachaRotationTicker();
}

function slug(value) {
  return String(value || cryptoRandom())
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

function cryptoRandom() {
  return window.crypto?.randomUUID?.() || `id-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function toast(message) {
  const el = $("#toast");
  el.textContent = message;
  el.classList.add("show");
  window.clearTimeout(toast.timer);
  toast.timer = window.setTimeout(() => el.classList.remove("show"), 2800);
}

function updateBuildBadge() {
  const badge = $("#buildBadge");
  if (badge) badge.textContent = `Build ${MILLENNIUM_BUILD.version} · ${MILLENNIUM_BUILD.commit}`;
}

function serializableFormDraft(form) {
  const values = {};
  [...form.elements].forEach((field) => {
    if (!field.name || field.disabled || field.dataset?.draftIgnore === "true") return;
    // Identificadores ocultos pertencem ao registro exibido e nunca ao rascunho.
    // Restaurá-los em outra ficha pode enviar uma decisão ao documento errado.
    if (["file", "password", "submit", "button", "hidden"].includes(field.type)) return;
    if (["checkbox", "radio"].includes(field.type) && !field.checked) return;
    values[field.name] = field.value;
  });
  return values;
}

function formDraftIdentity(formOrType, explicitScope = "") {
  if (typeof formOrType === "string") return { type: formOrType, scope: String(explicitScope || "") };
  const form = formOrType;
  const type = String(form?.dataset?.form || "");
  const scope = String(form?.dataset?.draftKey || explicitScope || "");
  return { type, scope };
}

function localDraftKey(formOrType, explicitScope = "") {
  const { type, scope } = formDraftIdentity(formOrType, explicitScope);
  const suffix = scope ? `:scope:${encodeURIComponent(scope)}` : "";
  return `${LOCAL_DRAFT_PREFIX}:${state.user?.uid || "anonymous"}:${type}${suffix}`;
}

function setDraftStatus(message = "") {
  const status = $("#draftStatus");
  if (status) status.textContent = message;
}

function saveLocalFormDraft(form) {
  if (!form?.dataset.form || form.dataset.form === "login") return;
  const key = localDraftKey(form);
  let previous = null;
  try { previous = JSON.parse(localStorage.getItem(key) || "null"); } catch { /* no-op */ }
  const identity = formDraftIdentity(form);
  const payload = {
    build: MILLENNIUM_BUILD.version,
    view: state.view,
    type: identity.type,
    scope: identity.scope,
    values: {
      ...(previous?.values || {}),
      ...serializableFormDraft(form),
    },
    savedAt: new Date().toISOString(),
  };
  try {
    localStorage.setItem(key, JSON.stringify(payload));
    form.dataset.dirty = "true";
    setDraftStatus("Rascunho salvo neste dispositivo");
  } catch {
    setDraftStatus("Rascunho local indisponível");
  }
}

function queueLocalFormDraft(form) {
  if (!form?.dataset.form || form.dataset.form === "login" || state.textComposing) return;
  window.clearTimeout(state.localDraftTimer);
  state.localDraftTimer = window.setTimeout(() => saveLocalFormDraft(form), 600);
}

function restoreLocalFormDrafts() {
  const scopedTypes = new Set(["review-request", "review-report"]);
  document.querySelectorAll("#viewHost form[data-form], #modalContent form[data-form]").forEach((form) => {
    if (form.dataset.form === "login" || form.dataset.restoredLocalDraft === "true") return;
    const identity = formDraftIdentity(form);
    // Remove o rascunho compartilhado das versões anteriores. Ele podia conter
    // requestId/reportId de outro cartão e misturar análises diferentes.
    if (identity.scope && scopedTypes.has(identity.type)) {
      try { localStorage.removeItem(localDraftKey(identity.type)); } catch { /* no-op */ }
    }
    let payload = null;
    try { payload = JSON.parse(localStorage.getItem(localDraftKey(form)) || "null"); } catch { /* no-op */ }
    if (!payload?.values) return;
    Object.entries(payload.values).forEach(([name, value]) => {
      const field = form.elements.namedItem(name);
      if (!field || field.type === "file" || field.type === "hidden" || field.dataset?.draftIgnore === "true") return;
      if (["checkbox", "radio"].includes(field.type)) field.checked = field.value === value;
      else field.value = value;
    });
    form.dataset.dirty = "true";
    form.dataset.restoredLocalDraft = "true";
    setDraftStatus("Rascunho restaurado neste dispositivo");
  });
}

function clearLocalFormDraft(formOrType, explicitScope = "") {
  try { localStorage.removeItem(localDraftKey(formOrType, explicitScope)); } catch { /* no-op */ }
  setDraftStatus("");
}

function hasDirtyForm() {
  return Boolean(document.querySelector('#viewHost form[data-dirty="true"], #modalContent form[data-dirty="true"]'));
}

function persistDirtyForms() {
  document.querySelectorAll('#viewHost form[data-dirty="true"], #modalContent form[data-dirty="true"]').forEach(saveLocalFormDraft);
}

function saveUpdateDrafts() {
  const forms = [...document.querySelectorAll("#viewHost form[data-form], #modalContent form[data-form]")]
    .filter((form) => form.dataset.form !== "login")
    .map((form) => {
      const identity = formDraftIdentity(form);
      return { type: identity.type, scope: identity.scope, values: serializableFormDraft(form) };
    });
  const payload = { build: MILLENNIUM_BUILD.version, uid: state.user?.uid || "", view: state.view, forms, savedAt: new Date().toISOString() };
  try {
    localStorage.setItem(UPDATE_DRAFT_KEY, JSON.stringify(payload));
  } catch {
    // Updating remains optional when browser storage is unavailable.
  }
  return payload;
}

function pendingUpdateDraft() {
  try {
    const payload = JSON.parse(localStorage.getItem(UPDATE_DRAFT_KEY) || "null");
    if (!payload || (payload.uid && state.user?.uid && payload.uid !== state.user.uid)) return null;
    return payload;
  } catch {
    return null;
  }
}

function restoreUpdateDrafts() {
  if (state.updateDraftRestored) return;
  const payload = pendingUpdateDraft();
  if (!payload?.forms?.length) {
    state.updateDraftRestored = true;
    return;
  }
  let restored = false;
  const scopeRequired = new Set(["review-request", "review-report"]);
  const safeForms = payload.forms.filter((entry) => !scopeRequired.has(entry.type) || Boolean(entry.scope));
  if (safeForms.length !== payload.forms.length) {
    payload.forms = safeForms;
    try {
      if (safeForms.length) localStorage.setItem(UPDATE_DRAFT_KEY, JSON.stringify(payload));
      else localStorage.removeItem(UPDATE_DRAFT_KEY);
    } catch { /* no-op */ }
  }
  safeForms.forEach(({ type, scope = "", values }) => {
    const selector = scope
      ? `[data-form="${CSS.escape(type)}"][data-draft-key="${CSS.escape(scope)}"]`
      : `[data-form="${CSS.escape(type)}"]`;
    const form = document.querySelector(selector);
    if (!form) return;
    Object.entries(values || {}).forEach(([name, value]) => {
      const field = form.elements.namedItem(name);
      if (!field || field.type === "file" || field.type === "hidden" || field.dataset?.draftIgnore === "true") return;
      if (["checkbox", "radio"].includes(field.type)) field.checked = field.value === value;
      else field.value = value;
    });
    form.dataset.dirty = "true";
    form.dataset.restoredDraft = "true";
    restored = true;
  });
  if (restored) {
    state.updateDraftRestored = true;
    toast("Rascunho restaurado neste dispositivo.");
  }
}

function clearUpdateDraft(formOrType = "", explicitScope = "") {
  const payload = pendingUpdateDraft();
  if (!payload) return;
  const identity = formDraftIdentity(formOrType, explicitScope);
  if (!identity.type) {
    try { localStorage.removeItem(UPDATE_DRAFT_KEY); } catch { /* no-op */ }
    return;
  }
  const matches = (entry) => entry.type === identity.type
    && (!identity.scope || String(entry.scope || "") === identity.scope);
  if (!payload.forms?.some(matches)) return;
  payload.forms = payload.forms.filter((entry) => !matches(entry));
  try {
    if (payload.forms.length) localStorage.setItem(UPDATE_DRAFT_KEY, JSON.stringify(payload));
    else localStorage.removeItem(UPDATE_DRAFT_KEY);
  } catch {
    // Draft cleanup is best effort.
  }
}

function showUpdateNotice(worker) {
  if (!worker) return;
  state.waitingServiceWorker = worker;
  const notice = $("#updateNotice");
  if (notice) notice.hidden = false;
}

function applyAvailableUpdate() {
  if (!state.waitingServiceWorker) return;
  saveUpdateDrafts();
  state.updateReloadRequested = true;
  state.waitingServiceWorker.postMessage({ type: "SKIP_WAITING" });
}

function handleEmergencyUpdate(settings = state.settings) {
  if (state.role === "admin") return;
  persistDirtyForms();
  saveUpdateDrafts();
  const title = settings.emergencyTitle || "Atualização emergencial";
  const message = settings.emergencyMessage || "A Interface está recebendo uma correção.";
  const action = ["reload", "signout", "maintenance"].includes(settings.emergencyAction) ? settings.emergencyAction : "reload";
  const seconds = Math.max(0, Math.min(30, Number(settings.emergencyCountdown || 5)));
  window.clearTimeout(state.emergencyTimer);
  const notice = $("#updateNotice");
  if (notice) {
    notice.querySelector("strong").textContent = title;
    notice.querySelector("span").textContent = `${message} Rascunhos preservados. Ação em ${seconds}s.`;
    notice.querySelector('[data-action="apply-update"]')?.setAttribute("hidden", "");
    notice.hidden = false;
  }
  state.emergencyTimer = window.setTimeout(() => {
    if (action === "signout") {
      setPresence(false, { force: true });
      cleanupListeners();
      state.auth?.signOut?.();
      state.user = null;
      state.demo = false;
      showAuth();
      return;
    }
    if (action === "maintenance") {
      scheduleRender({ critical: true, reason: "emergency-maintenance" });
      return;
    }
    window.location.reload();
  }, seconds * 1000);
}

async function registerMillenniumServiceWorker() {
  if (!("serviceWorker" in navigator) || location.protocol === "file:") return;
  try {
    const registration = await navigator.serviceWorker.register(`service-worker.js?v=${MILLENNIUM_BUILD.version}`);
    state.serviceWorkerRegistration = registration;
    if (registration.waiting && navigator.serviceWorker.controller) showUpdateNotice(registration.waiting);
    registration.addEventListener("updatefound", () => {
      const worker = registration.installing;
      worker?.addEventListener("statechange", () => {
        if (worker.state === "installed" && navigator.serviceWorker.controller) showUpdateNotice(worker);
      });
    });
    navigator.serviceWorker.addEventListener("controllerchange", () => {
      if (state.updateReloadRequested) window.location.reload();
    });
  } catch (error) {
    console.warn("Service Worker indisponível:", error);
  }
}

function formValues(form) {
  return Object.fromEntries(new FormData(form).entries());
}

function fileToDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(reader.error || new Error("Não consegui ler a imagem."));
    reader.readAsDataURL(file);
  });
}

function mediaInput(name, label, value = "", options = {}) {
  const id = `${name}-${cryptoRandom().slice(0, 8)}`;
  const preview = value ? `<img src="${esc(value)}" alt="${esc(label)}" ${mediaAttrs("generic")} />` : `<span>Prévia</span>`;
  return `
    <label class="media-field">
      <span>${esc(label)}</span>
      <input id="${esc(id)}" name="${esc(name)}" data-media-url="${esc(name)}" value="${esc(value || "")}" placeholder="Cole uma URL ou envie um arquivo" />
      <input type="file" data-media-field="${esc(name)}" accept="${esc(options.accept || "image/*,.gif")}" />
      <div class="media-preview" data-media-preview="${esc(name)}">${preview}</div>
      <small>${esc(options.hint || "Aceita PNG, JPG, WEBP ou GIF. Ao salvar, o arquivo vai para o Cloudinary e a URL fica no Firebase.")}</small>
    </label>
  `;
}

function positionSelect(name, label, selected = "center") {
  const options = [
    ["center", "Centro"],
    ["top", "Topo"],
    ["bottom", "Base"],
    ["left", "Esquerda"],
    ["right", "Direita"],
  ];
  return `
    <label>
      <span>${esc(label)}</span>
      <select name="${esc(name)}">
        ${options.map(([value, text]) => `<option value="${value}" ${selected === value ? "selected" : ""}>${text}</option>`).join("")}
      </select>
    </label>
  `;
}

function objectPosition(value) {
  return {
    top: "center top",
    bottom: "center bottom",
    left: "left center",
    right: "right center",
  }[value] || "center center";
}

function legacyCropCoordinate(position = "center", axis = "x") {
  const values = {
    top: [50, 18],
    bottom: [50, 82],
    left: [18, 50],
    right: [82, 50],
    center: [50, 50],
  }[position] || [50, 50];
  return axis === "y" ? values[1] : values[0];
}

function cropSettings(character = {}, prefix = "avatar") {
  const legacy = character[`${prefix}Position`] || "center";
  const x = Number.isFinite(Number(character[`${prefix}FocusX`])) ? Number(character[`${prefix}FocusX`]) : legacyCropCoordinate(legacy, "x");
  const y = Number.isFinite(Number(character[`${prefix}FocusY`])) ? Number(character[`${prefix}FocusY`]) : legacyCropCoordinate(legacy, "y");
  const zoom = Number.isFinite(Number(character[`${prefix}Zoom`])) ? Number(character[`${prefix}Zoom`]) : 1;
  return {
    x: Math.max(0, Math.min(100, x)),
    y: Math.max(0, Math.min(100, y)),
    zoom: Math.max(1, Math.min(2.4, zoom)),
  };
}

function cropImageStyle(character = {}, prefix = "avatar") {
  const crop = cropSettings(character, prefix);
  return `object-position:${crop.x}% ${crop.y}%;transform:scale(${crop.zoom})`;
}

function renderProfileBanner(character = {}, options = {}) {
  const source = character.bannerUrl || SEASON_ART.login;
  return `<div class="profile-banner-shell ${character.bannerUrl ? "" : "fallback"}"><img class="profile-banner" style="${esc(cropImageStyle(character, "banner"))}" src="${esc(source)}" alt="${esc(options.alt || "Banner do personagem")}" ${mediaAttrs("banner")} /></div>`;
}

function renderProfileAvatar(character = {}, options = {}) {
  const rarity = options.rarity || "Comum";
  const online = options.online === true;
  return `<div class="avatar-frame ${rarityClass(rarity)}" title="${esc(options.title || "Presença do personagem")}"><div class="avatar-viewport"><img class="avatar" style="${esc(cropImageStyle(character, "avatar"))}" src="${esc(character.avatarUrl || placeholderAvatar())}" alt="${esc(options.alt || "Avatar do personagem")}" ${mediaAttrs("avatar")} /></div>${options.showStatus === false ? "" : `<span class="profile-online-dot ${online ? "online" : ""}" aria-label="${online ? "Online" : "Offline"}"></span>`}</div>`;
}

function cropEditor(prefix, label, imageUrl, character = {}, draft = null) {
  const saved = cropSettings(character, prefix);
  const x = Number(draftValue(draft, `${prefix}FocusX`, saved.x));
  const y = Number(draftValue(draft, `${prefix}FocusY`, saved.y));
  const zoom = Number(draftValue(draft, `${prefix}Zoom`, saved.zoom));
  const source = imageUrl || (prefix === "avatar" ? placeholderAvatar() : SEASON_ART.login);
  return `
    <section class="crop-editor wide" data-crop-editor="${esc(prefix)}">
      <div class="crop-editor-preview ${esc(prefix)}"><img data-crop-preview-image="${esc(prefix)}" src="${esc(source)}" style="object-position:${x}% ${y}%;transform:scale(${zoom})" alt="Prévia de ${esc(label)}" ${mediaAttrs(prefix === "banner" ? "banner" : "portrait")} /></div>
      <div class="crop-editor-controls">
        <div><span>${esc(label)}</span><small>Arraste os controles e veja exatamente como ficará.</small></div>
        <label><span>Horizontal</span><input type="range" min="0" max="100" step="1" name="${esc(prefix)}FocusX" data-crop-control="${esc(prefix)}" value="${x}" /></label>
        <label><span>Vertical</span><input type="range" min="0" max="100" step="1" name="${esc(prefix)}FocusY" data-crop-control="${esc(prefix)}" value="${y}" /></label>
        <label><span>Zoom</span><input type="range" min="1" max="2.4" step="0.05" name="${esc(prefix)}Zoom" data-crop-control="${esc(prefix)}" value="${zoom}" /></label>
      </div>
    </section>
  `;
}

function updateCropPreview(form, prefix) {
  const image = form?.querySelector(`[data-crop-preview-image="${CSS.escape(prefix)}"]`);
  if (!image) return;
  const x = Number(form.querySelector(`[name="${CSS.escape(`${prefix}FocusX`)}"]`)?.value || 50);
  const y = Number(form.querySelector(`[name="${CSS.escape(`${prefix}FocusY`)}"]`)?.value || 50);
  const zoom = Number(form.querySelector(`[name="${CSS.escape(`${prefix}Zoom`)}"]`)?.value || 1);
  const url = form.querySelector(`[name="${CSS.escape(`${prefix}Url`)}"]`)?.value;
  if (url) image.src = url;
  image.style.objectPosition = `${x}% ${y}%`;
  image.style.transform = `scale(${zoom})`;
}

async function uploadMediaFile(file, folder = "general") {
  if (!file) return "";
  if (!file.type.startsWith("image/")) throw new Error("Envie apenas imagem ou GIF.");
  if (file.size > 6 * 1024 * 1024) throw new Error("Imagem muito pesada. Use até 6 MB.");
  if (state.demo) return fileToDataUrl(file);
  if (!CLOUDINARY_CONFIG.cloudName || !CLOUDINARY_CONFIG.uploadPreset) {
    throw new Error("Cloudinary não configurado.");
  }
  const formData = new FormData();
  formData.append("file", file);
  formData.append("upload_preset", CLOUDINARY_CONFIG.uploadPreset);
  formData.append("folder", `millennium/${folder}/${state.user?.uid || "anon"}`);
  formData.append("tags", "millennium,rpg");
  const response = await fetch(`https://api.cloudinary.com/v1_1/${CLOUDINARY_CONFIG.cloudName}/auto/upload`, {
    method: "POST",
    body: formData,
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || !data.secure_url) {
    throw new Error(data.error?.message || "Cloudinary recusou o upload. Confira o upload preset unsigned.");
  }
  return data.secure_url;
}

function mediaFolderForForm(type) {
  if (type === "character") return "characters";
  if (type?.startsWith("content-")) return `forja/${type.replace(/^content-/, "")}`;
  if (type === "create-guild" || type === "guild-settings") return "guilds";
  return "general";
}

async function resolveFormMedia(form, folder = "general") {
  const fileInputs = Array.from(form.querySelectorAll("input[type='file'][data-media-field]"));
  for (const input of fileInputs) {
    const file = input.files?.[0];
    if (!file) continue;
    const field = input.dataset.mediaField;
    const urlInput = form.querySelector(`[name="${CSS.escape(field)}"]`);
    toast("Enviando imagem...");
    const url = await uploadMediaFile(file, folder);
    if (urlInput) urlInput.value = url;
  }
}

async function previewMediaInput(input) {
  const file = input.files?.[0];
  if (!file) return;
  const field = input.dataset.mediaField;
  const preview = input.closest("form")?.querySelector(`[data-media-preview="${CSS.escape(field)}"]`);
  if (!preview) return;
  const url = await fileToDataUrl(file);
  preview.innerHTML = `<img src="${esc(url)}" alt="Prévia de imagem" ${mediaAttrs("generic")} />`;
  const cropImage = input.closest("form")?.querySelector(`[data-crop-preview-image="${CSS.escape(field.replace(/Url$/, ""))}"]`);
  if (cropImage) cropImage.src = url;
}

function nowValue() {
  if (state.firebaseReady && state.db) return firebase.firestore.FieldValue.serverTimestamp();
  return new Date().toISOString();
}

async function callTrustedOperation(type, payload = {}) {
  if (state.demo) return null;
  if (MILLENNIUM_SPARK_MODE) throw new Error(`A operação ${type} tentou usar Cloud Functions na edição Spark.`);
  if (!state.functions || !state.user) throw new Error("O serviço seguro do Firebase ainda não está disponível.");
  const callable = state.functions.httpsCallable("executeTrustedOperation");
  const response = await callable({ type, payload });
  return response?.data || null;
}

async function beginTrustedMinigame(session, mode) {
  if (state.demo || !session) return null;
  if (MILLENNIUM_SPARK_MODE) {
    session.serverRunPromise = Promise.resolve({ data: { runId: session.id, mode, spark: true } });
    return session.serverRunPromise;
  }
  if (!state.functions) throw new Error("O serviço seguro de minigames não foi carregado.");
  const callable = state.functions.httpsCallable("beginTrustedMinigame");
  const request = callable({
    runId: session.id,
    mode,
    difficultyId: session.difficulty.id,
    level: session.level,
    petId: session.petId || "",
    activity: session.activity || null,
  });
  session.serverRunPromise = request;
  return request;
}

function tsText(value) {
  if (!value) return "";
  if (typeof value === "string") return new Date(value).toLocaleString("pt-BR");
  if (typeof value.toDate === "function") return value.toDate().toLocaleString("pt-BR");
  return "";
}

function timeValue(value) {
  if (!value) return 0;
  if (typeof value === "string") return new Date(value).getTime() || 0;
  if (typeof value.toMillis === "function") return value.toMillis();
  if (typeof value.toDate === "function") return value.toDate().getTime();
  return 0;
}

function sortByName(items) {
  return [...items].sort((a, b) => String(a.name || a.title || a.displayName || "").localeCompare(String(b.name || b.title || b.displayName || ""), "pt-BR"));
}

function sortByOrder(items) {
  return [...items].sort((a, b) => Number(a.order || a.tier || 0) - Number(b.order || b.tier || 0) || String(a.name || a.title || "").localeCompare(String(b.name || b.title || ""), "pt-BR"));
}

function sortByTier(items) {
  return [...items].sort((a, b) => Number(a.tier || 0) - Number(b.tier || 0) || String(a.name || a.title || "").localeCompare(String(b.name || b.title || ""), "pt-BR"));
}

function normalize(value) {
  return String(value || "").normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
}

function bonusToText(bonus = {}) {
  const labels = { for: "FOR", vel: "VEL", hab: "HAB", res: "RES", pod: "POD", def: "DEF", hp: "PV", pp: "PP" };
  const parts = Object.entries(bonus)
    .filter(([, value]) => Number(value) !== 0)
    .map(([key, value]) => `+${value} ${labels[key] || key.toUpperCase()}`);
  return parts.length ? parts.join(", ") : "Sem bônus";
}

function penaltyToText(penalty = {}) {
  const labels = { for: "FOR", vel: "VEL", hab: "HAB", res: "RES", pod: "POD" };
  const parts = Object.entries(penalty)
    .filter(([key, value]) => labels[key] && Number(value) > 0)
    .map(([key, value]) => `−${Number(value)} ${labels[key]}`);
  return parts.join(", ");
}

function parseBonus(raw) {
  try {
    const parsed = JSON.parse(raw || "{}");
    return Object.fromEntries(Object.entries(parsed).map(([key, value]) => [key, Number(value) || 0]));
  } catch {
    throw new Error("Bônus inválido. Use JSON, exemplo: {\"pod\":2}");
  }
}

function optionList(items, selected = "", label = "name") {
  return sortByName(items)
    .map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(item[label] || item.name)}</option>`)
    .join("");
}

function draftValue(draft, name, fallback = "") {
  return draft && Object.prototype.hasOwnProperty.call(draft, name) ? draft[name] : fallback;
}

