function currentCharacter() {
  if (state.character) return state.character;
  const fallback = defaultCharacter(state.user?.uid || "demo", state.profile?.displayName || "");
  state.character = fallback;
  return fallback;
}

function normalizedAccountStatus(profile = state.profile, now = Date.now()) {
  const merged = state.accountDeletionQueue
    ? { ...(profile || {}), accountStatus: "deletion_pending", deletionQueue: state.accountDeletionQueue }
    : (profile || {});
  return ACCOUNT_MGMT.normalizeStatus(merged, now);
}

function accountIsRestricted(profile = state.profile, now = Date.now()) {
  if (state.role === "admin") return false;
  if (state.accountDeletionQueue) return true;
  return ACCOUNT_MGMT.isRestricted(profile || {}, now);
}

function presenceTabId() {
  if (state.presenceTabId) return state.presenceTabId;
  state.presenceTabId = `tab-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  try { sessionStorage.setItem("millennium:presence-tab", state.presenceTabId); } catch { /* storage unavailable */ }
  return state.presenceTabId;
}

function presenceStorageKey(kind) {
  return `millennium:presence:${state.user?.uid || "anonymous"}:${kind}`;
}

function readPresenceLease() {
  try { return JSON.parse(localStorage.getItem(presenceStorageKey("lease")) || "null"); } catch { return null; }
}

function claimPresenceLease() {
  if (!state.user) return false;
  const now = Date.now();
  const current = readPresenceLease();
  const tabId = presenceTabId();
  if (current?.tabId && current.tabId !== tabId && Number(current.expiresAt || 0) > now) return false;
  try {
    localStorage.setItem(presenceStorageKey("lease"), JSON.stringify({ tabId, expiresAt: now + PRESENCE_LEASE_TTL_MS }));
    return true;
  } catch {
    return true;
  }
}

function releasePresenceLease() {
  if (!state.user) return;
  try {
    const current = readPresenceLease();
    if (current?.tabId === presenceTabId()) localStorage.removeItem(presenceStorageKey("lease"));
  } catch { /* no-op */ }
}

function stopPresenceTracking() {
  if (state.presenceTimer) window.clearInterval(state.presenceTimer);
  state.presenceTimer = null;
  if (state.presenceVisibilityHandler) document.removeEventListener("visibilitychange", state.presenceVisibilityHandler);
  state.presenceVisibilityHandler = null;
  if (state.idleTimer) window.clearInterval(state.idleTimer);
  state.idleTimer = null;
  releasePresenceLease();
  clearRestrictionTimer();
}

function clearRestrictionTimer() {
  if (state.restrictionTimer) window.clearInterval(state.restrictionTimer);
  state.restrictionTimer = 0;
}

function updateRestrictionCountdown() {
  const element = document.querySelector("[data-restriction-countdown]");
  const status = normalizedAccountStatus();
  if (status !== "suspended") {
    clearRestrictionTimer();
    if (!accountIsRestricted()) {
      document.body.classList.remove("account-restricted");
      activateRouteSubscriptions(state.view);
      startPresence();
      scheduleRender({ critical: true, reason: "restriction-expired" });
    }
    return;
  }
  const countdown = ACCOUNT_MGMT.restrictionCountdown(state.profile || {}, Date.now());
  if (element) element.textContent = countdown.label || "Encerrando...";
}

function startRestrictionCountdown() {
  clearRestrictionTimer();
  updateRestrictionCountdown();
  if (normalizedAccountStatus() === "suspended") {
    state.restrictionTimer = window.setInterval(updateRestrictionCountdown, 1000);
  }
}

function getUserName(uid) {
  if (uid === state.user?.uid) return state.profile?.displayName || state.user?.email || "Você";
  const publicProfile = state.publicProfiles.find((profile) => profile.id === uid || profile.ownerId === uid);
  const rankingProfile = state.rankingProfiles.find((profile) => profile.id === uid || profile.ownerId === uid);
  return state.users.find((user) => user.id === uid)?.displayName
    || publicProfile?.player || publicProfile?.name
    || rankingProfile?.displayName || rankingProfile?.characterName
    || state.characters.find((char) => char.ownerId === uid)?.displayName || "Player";
}

function getCharacterFor(uid) {
  if (uid === state.user?.uid && state.character) return state.character;
  return state.characters.find((char) => char.ownerId === uid || char.id === uid) || defaultCharacter(uid, getUserName(uid));
}

function findCharacter(uid) {
  if (uid === state.user?.uid && state.character) return state.character;
  const local = state.characters.find((char) => char.ownerId === uid || char.id === uid);
  if (local) return local;
  const profile = state.publicProfiles.find((entry) => entry.id === uid || entry.ownerId === uid);
  const ranking = state.rankingProfiles.find((entry) => entry.id === uid || entry.ownerId === uid);
  if (!profile && !ranking) return null;
  return {
    ...(ranking || {}),
    id: uid,
    ownerId: uid,
    characterName: profile?.name || ranking?.characterName || "Player",
    playerName: profile?.player || ranking?.displayName || "Player",
    displayName: profile?.player || ranking?.displayName || "Player",
    avatarUrl: profile?.avatar || "",
    bannerUrl: profile?.banner || "",
    currentLocation: profile?.location || "",
    profilePublic: Boolean(profile && profile.privacy !== "private"),
    __publicProjection: true,
  };
}

function equippedItems(character = currentCharacter()) {
  return (character.inventory || []).filter((item) => item.equipped);
}

function addBonuses(...bonuses) {
  const total = { for: 0, vel: 0, hab: 0, res: 0, pod: 0, def: 0, hp: 0, pp: 0 };
  bonuses.forEach((bonus = {}) => {
    Object.keys(total).forEach((key) => {
      total[key] += Number(bonus[key] || 0);
    });
  });
  return total;
}

function getTotals(character = currentCharacter()) {
  const result = window.MILLENNIUM_CORE_31.calculateCharacterStats(character, state.content);
  return { ...result.total, ...result.derived, composition: result };
}

function isRareReward(rarity) {
  return RARE_RARITIES.includes(rarity);
}

function rarityKey(rarity) {
  const key = String(rarity || "Comum")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
  if (key.includes("secret")) return "secret";
  if (key.includes("celestial")) return "celestial";
  if (key.includes("cosm")) return "cosmic";
  if (key.includes("mitic") || key.includes("mythic")) return "mythic";
  if (key.includes("lend")) return "legendary";
  if (key.includes("pico")) return "epic";
  if (key.includes("raro")) return "rare";
  if (key.includes("incomum")) return "uncommon";
  if (key.includes("quebrado")) return "broken";
  return "common";
}

function rarityClass(rarity) {
  return `rarity-${rarityKey(rarity)}`;
}

function rarityScore(rarity) {
  return { broken: 0.5, common: 1, uncommon: 2, rare: 3, epic: 4, legendary: 5, mythic: 6, cosmic: 7, celestial: 8, secret: 9 }[rarityKey(rarity)] || 1;
}

function activeTitle(character = currentCharacter()) {
  const titles = character.titles || [];
  return titles.find((title) => title.id && title.id === character.activeTitleId) || titles.find((title) => title.equipped) || titles[0] || null;
}

function titleTextFor(uid) {
  const title = activeTitle(findCharacter(uid) || getCharacterFor(uid));
  return title?.name || "";
}

function displayNameWithTitle(uid, fallback = "") {
  const name = uid ? getUserName(uid) : fallback || "Sistema";
  const title = uid ? titleTextFor(uid) : "";
  return title ? `${name} · ${title}` : name;
}

function dateFromValue(value) {
  if (!value) return null;
  if (typeof value === "string") return new Date(value);
  if (typeof value.toDate === "function") return value.toDate();
  return null;
}

function dateTimeLocalValue(value) {
  const date = dateFromValue(value);
  if (!date || Number.isNaN(date.getTime())) return "";
  const offset = date.getTimezoneOffset() * 60000;
  return new Date(date.getTime() - offset).toISOString().slice(0, 16);
}

function isUserOnline(user) {
  if (!user?.online) return false;
  const lastSeen = dateFromValue(user.lastSeen);
  if (!lastSeen) return true;
  return Date.now() - lastSeen.getTime() < PRESENCE_ONLINE_WINDOW_MS;
}

function socialRequestsFor(uid = state.user?.uid) {
  return state.socialRequests.filter((request) => (request.participants || []).includes(uid));
}

function pendingIncomingRequests(uid = state.user?.uid) {
  return socialRequestsFor(uid).filter((request) => request.toId === uid && request.status === "pendente");
}

function friendIds(uid = state.user?.uid) {
  return socialRequestsFor(uid)
    .filter((request) => request.type === "friend" && request.status === "aceito")
    .map((request) => request.fromId === uid ? request.toId : request.fromId)
    .filter(Boolean);
}

function areFriends(uid, otherId) {
  return friendIds(uid).includes(otherId);
}

function pendingFriendRequestWith(otherId) {
  return state.socialRequests.find((request) => (
    request.type === "friend"
    && request.status === "pendente"
    && (request.participants || []).includes(state.user?.uid)
    && (request.participants || []).includes(otherId)
  ));
}

function myGuilds(uid = state.user?.uid) {
  if (state.role === "admin") return state.guilds;
  return state.guilds.filter((guild) => (guild.memberIds || []).includes(uid));
}

function currentGuild() {
  const mine = guildForUser();
  if (!state.selectedGuildId && mine) state.selectedGuildId = mine.id;
  if (!state.selectedGuildId && state.guilds.length) state.selectedGuildId = state.guilds[0].id;
  return state.guilds.find((guild) => guild.id === state.selectedGuildId) || mine || state.guilds[0] || null;
}

function isGuildLeader(guild, uid = state.user?.uid) {
  return state.role === "admin" || guild?.leaderId === uid;
}

function guildMembers(guild) {
  return (guild?.memberIds || []).map((uid) => ({ uid, user: state.users.find((user) => user.id === uid), character: findCharacter(uid) })).filter((item) => item.user || item.character);
}

function guildForUser(uid = state.user?.uid) {
  return state.guilds.find((guild) => (guild.memberIds || []).includes(uid)) || null;
}

function isGuildMember(guild, uid = state.user?.uid) {
  return Boolean(guild && (guild.memberIds || []).includes(uid));
}

function pendingGuildRequest(guildId, uid = state.user?.uid) {
  return state.socialRequests.find((request) => (
    request.status === "pendente"
    && request.guildId === guildId
    && (request.type === "guildInvite" || request.type === "guildJoinRequest")
    && (request.participants || []).includes(uid)
  ));
}

function isCharacterBanned(character = currentCharacter()) {
  return Number(character.bannedUntil || 0) > Date.now();
}

function playSound(kind) {
  if (state.settings.soundEnabled === false || document.hidden) return;
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    const ctx = playSound.ctx || new AudioCtx();
    playSound.ctx = ctx;
    ctx.resume?.().catch(() => {});
    const output = ctx.createGain();
    const filter = ctx.createBiquadFilter();
    output.gain.value = 0.72;
    filter.type = "lowpass";
    filter.frequency.value = kind === "secret" ? 5200 : 3400;
    filter.Q.value = 0.8;
    filter.connect(output);
    output.connect(ctx.destination);
    const tone = (note, start, duration, volume, type = "triangle", endRatio = 0.82) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      const at = ctx.currentTime + start;
      osc.type = type;
      osc.frequency.setValueAtTime(note, at);
      osc.frequency.exponentialRampToValueAtTime(Math.max(36, note * endRatio), at + duration);
      gain.gain.setValueAtTime(0.0001, at);
      gain.gain.exponentialRampToValueAtTime(volume, at + Math.min(0.025, duration * 0.18));
      gain.gain.exponentialRampToValueAtTime(0.0001, at + duration);
      osc.connect(gain);
      gain.connect(filter);
      osc.start(at);
      osc.stop(at + duration + 0.04);
    };
    const noise = (start, duration, volume, frequency = 1400) => {
      const frames = Math.max(1, Math.floor(ctx.sampleRate * duration));
      const buffer = ctx.createBuffer(1, frames, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let index = 0; index < frames; index += 1) data[index] = (Math.random() * 2 - 1) * (1 - index / frames);
      const source = ctx.createBufferSource();
      const band = ctx.createBiquadFilter();
      const gain = ctx.createGain();
      const at = ctx.currentTime + start;
      source.buffer = buffer;
      band.type = "bandpass";
      band.frequency.value = frequency;
      band.Q.value = 1.3;
      gain.gain.setValueAtTime(volume, at);
      gain.gain.exponentialRampToValueAtTime(0.0001, at + duration);
      source.connect(band);
      band.connect(gain);
      gain.connect(filter);
      source.start(at);
    };
    if (kind === "click") {
      tone(1280, 0, 0.045, 0.012, "triangle", 0.7);
      tone(210, 0, 0.065, 0.009, "sine", 0.55);
    } else if (kind === "rolling") {
      noise(0, 0.7, 0.026, 720);
      tone(55, 0, 0.86, 0.038, "sine", 2.8);
      tone(110, 0.08, 0.72, 0.024, "triangle", 2.1);
      tone(220, 0.28, 0.52, 0.014, "sine", 1.7);
    } else if (kind === "rare") {
      tone(196, 0, 0.58, 0.026, "triangle", 0.95);
      tone(293.66, 0.055, 0.72, 0.023, "sine", 1.01);
      tone(440, 0.13, 0.84, 0.018, "sine", 0.99);
      noise(0, 0.18, 0.008, 2500);
    } else if (kind === "legendary") {
      tone(55, 0, 0.72, 0.045, "sine", 0.58);
      [146.83, 220, 293.66, 440].forEach((note, index) => tone(note, 0.08 + index * 0.09, 0.9, 0.025 - index * 0.002, index % 2 ? "sine" : "triangle", 1.02));
      noise(0.02, 0.5, 0.018, 900);
    } else if (kind === "secret") {
      noise(0, 0.86, 0.022, 520);
      tone(41.2, 0, 1.25, 0.05, "sine", 0.72);
      [130.81, 196, 261.63, 392, 523.25].forEach((note, index) => tone(note, 0.18 + index * 0.14, 1.05, 0.024, "sine", 1.01));
    } else if (kind === "fail") {
      tone(146.83, 0, 0.28, 0.018, "triangle", 0.72);
      tone(73.42, 0.04, 0.4, 0.018, "sine", 0.8);
    } else {
      tone(220, 0, 0.18, 0.018, "triangle", 0.9);
      tone(329.63, 0.035, 0.28, 0.012, "sine", 0.94);
    }
    window.setTimeout(() => {
      try { filter.disconnect(); output.disconnect(); } catch {}
    }, 1800);
  } catch {
    // Audio can be blocked until the first gesture.
  }
}

function updateMusicButton() {
  const button = $("#musicToggle");
  if (!button) return;
  button.classList.toggle("active", state.musicOn);
  button.textContent = state.musicOn ? "♪" : "♫";
  button.title = state.musicOn ? "Desligar música ambiente" : "Ligar música ambiente";
  button.setAttribute("aria-label", button.title);
  button.dataset.state = state.musicOn ? "ligada" : "desligada";
  const volume = $("#musicVolume");
  if (volume) volume.value = String(Math.round(state.musicVolume * 100));
}

function setAmbientVolume(value) {
  const volume = Math.max(0, Math.min(1, Number(value) / 100));
  state.musicVolume = volume;
  if (state.musicNodes?.master && state.musicNodes?.ctx) {
    state.musicNodes.master.gain.setTargetAtTime(Math.max(0.0001, volume), state.musicNodes.ctx.currentTime, 0.06);
  }
  localStorage.setItem("millenniumMusicVolume", String(volume));
  updateMusicButton();
}

function ambientContext() {
  const AudioCtx = window.AudioContext || window.webkitAudioContext;
  if (!AudioCtx) return null;
  const ctx = playSound.ctx || new AudioCtx();
  playSound.ctx = ctx;
  return ctx;
}

async function startAmbientMusic() {
  if (state.musicNodes) return;
  const ctx = ambientContext();
  if (!ctx) {
    toast("Este navegador bloqueou o áudio ambiente.");
    return;
  }
  await ctx.resume?.().catch(() => {});
  const master = ctx.createGain();
  const filter = ctx.createBiquadFilter();
  const lfo = ctx.createOscillator();
  const lfoGain = ctx.createGain();
  const motifs = {
    awakening: { drone: [73.42, 110, 146.83], melody: [220, 261.63, 293.66, 329.63, 293.66, 246.94, 220, 196], interval: 3200, filter: 840 },
    void: { drone: [55, 82.41, 123.47], melody: [164.81, 196, 233.08, 174.61, 146.83, 130.81], interval: 3900, filter: 620 },
    blood: { drone: [65.41, 98, 130.81], melody: [196, 207.65, 261.63, 233.08, 174.61, 155.56], interval: 3000, filter: 760 },
    frost: { drone: [82.41, 123.47, 164.81], melody: [246.94, 329.63, 369.99, 293.66, 246.94, 220], interval: 3600, filter: 1040 },
    ember: { drone: [73.42, 110, 146.83], melody: [220, 293.66, 349.23, 329.63, 261.63, 220], interval: 2850, filter: 900 },
    forest: { drone: [65.41, 98, 146.83], melody: [196, 246.94, 293.66, 261.63, 220, 174.61], interval: 3450, filter: 920 },
  };
  const requestedTrack = state.musicTrack || state.settings.seasonThemeMainMusic || state.settings.seasonTheme || "awakening";
  const motif = FOUNDATIONS.musicTrack(requestedTrack) || motifs[requestedTrack] || motifs[state.settings.seasonTheme] || motifs.awakening;
  const notes = motif.drone;
  const oscillators = notes.map((freq, index) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = index % 2 ? "sine" : "triangle";
    osc.frequency.value = freq;
    gain.gain.value = 0.018 / (index + 1);
    osc.connect(gain);
    gain.connect(filter);
    osc.start();
    return { osc, gain };
  });
  filter.type = "lowpass";
  filter.frequency.value = motif.filter;
  filter.Q.value = 0.7;
  lfo.type = "sine";
  lfo.frequency.value = 0.035;
  lfoGain.gain.value = 220;
  lfo.connect(lfoGain);
  lfoGain.connect(filter.frequency);
  filter.connect(master);
  master.gain.value = Math.max(0.0001, state.musicVolume);
  master.connect(ctx.destination);
  lfo.start();
  const melody = motif.melody;
  let melodyIndex = 0;
  const melodyTimer = window.setInterval(() => {
    if (!state.musicOn) return;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    const note = melody[melodyIndex % melody.length] * (melodyIndex % 5 === 0 ? 0.5 : 1);
    melodyIndex += 1;
    osc.type = "triangle";
    osc.frequency.value = note;
    gain.gain.setValueAtTime(0.0001, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.026, ctx.currentTime + 0.018);
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 1.45);
    osc.connect(gain);
    gain.connect(master);
    osc.start();
    osc.stop(ctx.currentTime + 1.5);
  }, motif.interval);
  state.musicNodes = { ctx, master, filter, lfo, lfoGain, oscillators, timers: [melodyTimer], trackId: requestedTrack };
  state.musicOn = true;
  localStorage.setItem("millenniumMusic", "on");
  updateMusicButton();
}

function stopAmbientMusic() {
  const nodes = state.musicNodes;
  if (!nodes) {
    state.musicOn = false;
    updateMusicButton();
    return;
  }
  nodes.master.gain.setTargetAtTime(0.0001, nodes.ctx.currentTime, 0.08);
  window.setTimeout(() => {
    nodes.oscillators.forEach(({ osc }) => {
      try { osc.stop(); } catch {}
    });
    (nodes.timers || []).forEach((timer) => window.clearInterval(timer));
    try { nodes.lfo.stop(); } catch {}
    try { nodes.master.disconnect(); } catch {}
  }, 260);
  state.musicNodes = null;
  state.musicOn = false;
  localStorage.setItem("millenniumMusic", "off");
  updateMusicButton();
}

async function toggleAmbientMusic() {
  if (state.musicOn) {
    stopAmbientMusic();
    return;
  }
  await startAmbientMusic();
}

async function selectMusicTrack(trackId) {
  const track = FOUNDATIONS.musicTrack(trackId);
  if (!track) return;
  state.musicTrack = track.id;
  try { localStorage.setItem("millenniumMusicTrack", track.id); } catch { /* no-op */ }
  if (state.musicOn) {
    stopAmbientMusic();
    await startAmbientMusic();
  }
  toast(`Jukebox: ${track.name}.`);
  scheduleRender({ preserveScroll: true, reason: "jukebox-track" });
}

function nextMusicTrack() {
  const tracks = FOUNDATIONS.musicTracks || [];
  if (!tracks.length) return;
  const currentId = state.musicTrack || state.settings.seasonThemeMainMusic || state.settings.seasonTheme;
  const index = tracks.findIndex((track) => track.id === currentId);
  return selectMusicTrack(tracks[(index + 1 + tracks.length) % tracks.length].id);
}

function delay(ms) {
  return new Promise((resolve) => window.setTimeout(resolve, ms));
}

function localDayKey(date = new Date()) {
  return date.toLocaleDateString("en-CA", { timeZone: "America/Sao_Paulo" });
}

function weightedPick(items, weightKey = "weight") {
  const pool = items.filter((item) => Number(item[weightKey] || 0) > 0);
  const total = pool.reduce((sum, item) => sum + Number(item[weightKey] || 0), 0);
  if (!pool.length || total <= 0) return items[0] || null;
  let cursor = Math.random() * total;
  for (const item of pool) {
    cursor -= Number(item[weightKey] || 0);
    if (cursor <= 0) return item;
  }
  return pool[pool.length - 1];
}

function pickRollCategory(forceRare = false) {
  const categories = state.content.affinityCategories.filter((cat) => Number(cat.weight || 0) > 0);
  const banner = categories.find((cat) => cat.id === state.settings.bannerRateUp);
  if (state.settings.eventActive && banner && Math.random() < Number(state.settings.rareRateUpChance ?? 0.3)) return banner;

  if (forceRare) {
    const rareCategories = categories.filter((cat) => isRareReward(cat.rarity) || Number(cat.weight || 0) <= 10);
    return weightedPick(rareCategories.length ? rareCategories : categories);
  }

  return weightedPick(categories);
}

function pickAffinityForCategory(category) {
  const categoryPool = state.content.affinities.filter((affinity) => affinity.categoryId === category?.id);
  const pool = categoryPool.length ? categoryPool : state.content.affinities;
  return pool[Math.floor(Math.random() * pool.length)] || null;
}

function buildRollResult(pityCounter = 0) {
  const pityMax = Math.max(1, Number(state.settings.pityMax || 30));
  const forceRare = pityCounter + 1 >= pityMax;
  const category = pickRollCategory(forceRare);
  const affinity = pickAffinityForCategory(category);
  if (!affinity) return null;
  const finalCategory = category || getCategory(affinity.categoryId);
  const rare = isRareReward(finalCategory?.rarity) || Number(finalCategory?.weight || 0) <= 10;
  return {
    id: cryptoRandom(),
    affinity,
    category: finalCategory,
    rare,
    forced: forceRare && rare,
    pityAfter: rare ? 0 : pityCounter + 1,
    createdAt: new Date().toISOString(),
  };
}

function gachaRarityMeta(rarity) {
  return GACHA_RARITIES.find((item) => item.name === rarity || item.id === rarityKey(rarity)) || GACHA_RARITIES[1];
}

function gachaPool(type = "pets") {
  return type === "items" ? (state.content.gachaItems || []) : (state.content.gachaPets || []);
}

function petImageFor(item = {}, options = {}) {
  const monsterArt = migratedMonsterArtFor(item, options);
  if (monsterArt) return monsterArt;
  const asset = WORLD.petAssetFor(item);
  if (options.thumbnail && (item.imageThumbnail || asset?.thumbnail)) return item.imageThumbnail || asset.thumbnail;
  if (item.imageHero || item.imageUrl) return item.imageHero || item.imageUrl;
  if (asset?.hero) return asset.hero;
  if (SEASON_ART.pets[item.id]) return SEASON_ART.pets[item.id];
  if (item.sourceId && SEASON_ART.pets[item.sourceId]) return SEASON_ART.pets[item.sourceId];
  return generatedPetPortrait(item);
}

function migratedMonsterArtFor(item = {}, options = {}) {
  const api = window.MILLENNIUM_MONSTERS_364;
  if (!api?.assetBundleForSpecies) return "";
  const legacyId = String(item.sourceId || item.id || "");
  const speciesId = String(item.speciesId || api.migrationForLegacy?.(legacyId)?.targetSpeciesId || "");
  if (!speciesId) return "";
  const assets = api.assetBundleForSpecies(speciesId);
  return options.thumbnail ? assets.thumbnail : assets.portrait;
}

function generatedPetPortrait(item = {}) {
  const identity = item.sourceId || item.id || item.name || "eco-sem-nome";
  const seed = stableNumber(identity);
  const hues = [18, 38, 52, 132, 172, 208, 262, 318, 346];
  const hue = hues[seed % hues.length];
  const secondary = hues[(seed * 3 + 2) % hues.length];
  const initials = String(item.name || "Eco").split(/\s+/).filter(Boolean).slice(0, 2).map((part) => part[0]).join("").toUpperCase();
  const marks = ["◇", "✦", "△", "✥", "◈", "†"];
  const mark = marks[seed % marks.length];
  const name = normalize(item.name || identity);
  const kind = /corvo|coruja|falcao|ibis|abutre|galo|mariposa/.test(name) ? "wing"
    : /lobo|cao|raposa|fenrir|hiena/.test(name) ? "canine"
      : /serpente|escorpiao|aranha|hidra/.test(name) ? "serpent"
        : /peixe|lontra|tartaruga|leviata/.test(name) ? "aquatic"
          : /cervo|carneiro|javali|urso/.test(name) ? "horned"
            : /gato|pantera|lince|leao|grifo/.test(name) ? "feline"
              : /mimico|lesma|besouro|sapo/.test(name) ? "oddity"
                : "wraith";
  const silhouettes = {
    wing: `<path d="M55 246 Q94 112 184 156 Q246 85 329 128 Q287 183 232 198 Q278 224 306 282 Q238 266 192 225 Q140 278 70 292 Q102 231 150 204 Q94 198 55 246Z"/><path d="M177 151 194 78 212 151Z"/>`,
    canine: `<path d="M70 286 Q82 211 134 190 L117 111 165 145 Q195 126 225 145 L274 109 254 193 Q309 220 319 286 L249 260 222 282 161 282 132 258Z"/><path d="M143 194 Q192 157 244 194 L226 242 192 264 156 242Z"/>`,
    serpent: `<path d="M74 286 Q132 256 109 207 Q91 158 141 126 Q198 91 250 124 Q300 156 269 200 Q245 235 286 285 Q234 260 203 281 Q157 304 119 279Z"/><path d="M153 139 Q192 93 233 139 L218 197 192 218 165 197Z"/>`,
    aquatic: `<path d="M48 224 Q112 133 221 158 L311 112 294 198 336 249 245 235 Q135 294 48 224Z"/><path d="M124 162 170 91 205 163Z"/>`,
    horned: `<path d="M82 286 Q95 211 145 178 L112 112 151 133 136 74 184 145 232 73 219 137 273 108 239 181 Q292 214 302 286Z"/><path d="M145 178 Q192 140 239 178 L226 241 192 267 158 241Z"/>`,
    feline: `<path d="M70 286 Q86 211 142 183 L124 113 176 145 192 132 208 145 260 113 242 183 Q298 211 314 286Z"/><path d="M145 177 Q192 142 239 177 L226 235 192 260 158 235Z"/>`,
    oddity: `<path d="M65 286 Q67 196 139 169 Q112 126 144 94 Q177 61 203 114 Q236 66 270 105 Q301 141 258 177 Q319 209 319 286Z"/><circle cx="155" cy="173" r="24"/><circle cx="229" cy="173" r="24"/>`,
    wraith: `<path d="M62 286 Q86 213 133 184 L124 111 160 143 192 72 225 143 262 111 251 184 Q302 214 322 286 L250 259 220 288 192 257 160 288 130 259Z"/><path d="M143 176 Q192 125 241 176 L224 234 192 254 160 234Z"/>`,
  };
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="384" height="512" viewBox="0 0 384 512"><defs><radialGradient id="a" cx="52%" cy="35%"><stop offset="0" stop-color="hsl(${hue} 58% 35%)"/><stop offset=".6" stop-color="hsl(${secondary} 34% 15%)"/><stop offset="1" stop-color="#06070a"/></radialGradient><linearGradient id="b" x1="0" y1="0" x2="1" y2="1"><stop stop-color="hsl(${secondary} 68% 61%)"/><stop offset="1" stop-color="hsl(${hue} 72% 28%)"/></linearGradient></defs><rect width="384" height="512" fill="url(#a)"/><circle cx="192" cy="224" r="142" fill="none" stroke="hsl(${hue} 62% 68%)" stroke-opacity=".18" stroke-width="2"/><g transform="translate(0 42)" fill="#090b0f" stroke="url(#b)" stroke-opacity=".72" stroke-width="3">${silhouettes[kind]}</g><g transform="translate(0 42)" fill="hsl(${secondary} 90% 75%)"><circle cx="171" cy="191" r="5"/><circle cx="214" cy="191" r="5"/></g><text x="316" y="72" text-anchor="middle" font-family="serif" font-size="38" fill="hsl(${hue} 70% 70%)" opacity=".72">${mark}</text><rect x="22" y="438" width="340" height="50" rx="4" fill="#06070a" fill-opacity=".82"/><text x="38" y="471" font-family="serif" font-weight="700" font-size="20" fill="#f1dfb6">${initials}</text><text x="346" y="471" text-anchor="end" font-family="serif" font-size="13" fill="hsl(${hue} 65% 72%)">${String(item.rarity || "ECO").toUpperCase()}</text></svg>`;
  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;
}

function towerMapImageFor(map = {}, options = {}) {
  const local = options.thumbnail ? SEASON_ART.mapThumbs[map.id] : SEASON_ART.maps[map.id];
  if (local) return local;
  const asset = WORLD.locationAssetFor(map);
  if (options.thumbnail) return map.imageThumbnail || asset?.thumbnail || map.imageUrl || "";
  return map.imageHero || map.imageUrl || asset?.hero || "";
}

function stableNumber(seed) {
  return String(seed).split("").reduce((sum, char) => ((sum * 31) + char.charCodeAt(0)) % 2147483647, 7);
}

function pickRotating(items, count, seed) {
  if (!items.length) return [];
  const picked = [];
  let cursor = stableNumber(seed) % items.length;
  while (picked.length < Math.min(count, items.length)) {
    const item = items[cursor % items.length];
    if (!picked.some((entry) => entry.id === item.id)) picked.push(item);
    cursor += 1 + (stableNumber(`${seed}-${picked.length}`) % Math.max(1, items.length - 1));
  }
  return picked;
}

function activeGachaBanner(type = "pets") {
  const pool = gachaPool(type);
  const now = gachaNow();
  const hour = WORLD.rotationId(now);
  const eligible = (state.content.gachaBanners || []).filter((banner) => {
    if (!banner.enabled || banner.type !== type) return false;
    const startsAt = dateFromValue(banner.startsAt)?.getTime() || 0;
    const endsAt = dateFromValue(banner.endsAt)?.getTime() || Number.MAX_SAFE_INTEGER;
    return now >= startsAt && now <= endsAt;
  });
  const configured = eligible.find((banner) => banner.rotationMode === "fixed" || banner.fixed === true);
  if (configured) {
    const featuredIds = Array.isArray(configured.featuredIds)
      ? configured.featuredIds
      : String(configured.featuredIds || "").split(",").map((id) => id.trim()).filter(Boolean);
    const featured = featuredIds.map((id) => pool.find((item) => item.id === id)).filter(Boolean);
    if (featured.length) {
      return {
        type,
        hour,
        rotationId: `fixed:${configured.id || hour}`,
        name: configured.name || "Destaque fixado pelo Oráculo",
        description: configured.description || "Rate-up temporário configurado pelo Oráculo.",
        featured: featured.filter((item, index, list) => list.findIndex((entry) => entry.id === item.id) === index),
        startsAt: dateFromValue(configured.startsAt) || new Date(hour * WORLD.HOUR_MS),
        endsAt: dateFromValue(configured.endsAt) || new Date((hour + 1) * WORLD.HOUR_MS),
        configured: true,
      };
    }
  }
  const automatic = eligible.find((banner) => (banner.rotationMode || "automatic") === "automatic");
  const rotation = WORLD.selectBalancedRotation(pool, type, now);
  return {
    ...rotation,
    name: automatic?.name || rotation.name,
    description: automatic?.description || rotation.description,
    configured: false,
  };
}

function gachaNow() {
  return Date.now() + Number(state.serverTimeOffsetMs || 0);
}

function refreshGachaCountdown() {
  if (document.hidden) return;
  const countdowns = document.querySelectorAll("[data-gacha-countdown]");
  const routeNeedsRotation = ["gacha", "admin-economy"].includes(state.view);
  if (!countdowns.length && !routeNeedsRotation) return;
  const now = gachaNow();
  const hour = WORLD.rotationId(now);
  countdowns.forEach((element) => {
    const end = Number(element.dataset.gachaEnds || 0);
    const parts = WORLD.countdownParts(end || activeGachaBanner(element.dataset.gachaType || "pets").endsAt, now);
    element.textContent = `Próxima rotação em ${parts.label}`;
  });
  if (hour !== state.gachaRotationHour) {
    state.gachaRotationHour = hour;
    try { localStorage.setItem("millennium:last-pet-rotation", String(hour)); } catch { /* storage unavailable */ }
    if (!state.rolling && routeNeedsRotation) {
      scheduleRender({ preserveFocus: true, preserveScroll: true, reason: "gacha-hourly-rotation" });
    }
  }
}

function startGachaRotationTicker() {
  const active = !document.hidden && (["gacha", "admin-economy"].includes(state.view) || Boolean(document.querySelector("[data-gacha-countdown]")));
  const nextInterval = active ? 1000 : 60000;
  if (state.gachaRotationTimer && state.gachaRotationIntervalMs === nextInterval) {
    refreshGachaCountdown();
    return;
  }
  if (state.gachaRotationTimer) window.clearInterval(state.gachaRotationTimer);
  state.gachaRotationHour = WORLD.rotationId(gachaNow());
  state.gachaRotationIntervalMs = nextInterval;
  refreshGachaCountdown();
  state.gachaRotationTimer = window.setInterval(refreshGachaCountdown, nextInterval);
}

function gachaRatesFor(type = "pets") {
  return WORLD.publicRates(gachaPool(type), GACHA_RARITIES);
}

function openGachaOdds(type = "pets") {
  const banner = activeGachaBanner(type);
  const rates = gachaRatesFor(type);
  const pity = Math.max(1, Number(state.settings.pityMax || 30));
  $("#modalContent").innerHTML = `
    <section class="gacha-info-modal">
      <p class="eyebrow">Probabilidades publicadas</p>
      <h2>${esc(type === "pets" ? "Companheiros" : "Relíquias")}</h2>
      <p>As porcentagens abaixo derivam dos pesos ativos do catálogo. O rate-up aumenta a chance dentro da raridade destacada, sem inventar uma taxa separada.</p>
      <div class="gacha-rate-list">${rates.map((entry) => `<div><span class="rarity-pill ${rarityClass(entry.name)}">${esc(entry.name)}</span><strong>${entry.percentage.toLocaleString("pt-BR", { minimumFractionDigits: entry.percentage < 1 ? 3 : 2, maximumFractionDigits: 4 })}%</strong></div>`).join("") || `<div class="empty-state">Nenhuma taxa disponível.</div>`}</div>
      <div class="review-warning"><strong>Pity ${Number(currentCharacter().gachaPity?.[type] || 0)}/${pity}</strong><span>Ao atingir o limite configurado, a próxima invocação força uma raridade rara disponível e reinicia o contador.</span></div>
      <div class="rotation-summary"><span>Banner atual</span><strong>${esc(banner.name)}</strong><small data-gacha-countdown data-gacha-type="${esc(type)}" data-gacha-ends="${banner.endsAt.getTime()}">Próxima rotação</small></div>
    </section>`;
  $("#modal").hidden = false;
  refreshGachaCountdown();
}

function openGachaPool(type = "pets") {
  const banner = activeGachaBanner(type);
  const featuredIds = new Set((banner.featured || []).map((item) => item.id));
  const pool = [...gachaPool(type)].sort((a, b) => rarityScore(b.rarity) - rarityScore(a.rarity) || String(a.name).localeCompare(String(b.name), "pt-BR"));
  $("#modalContent").innerHTML = `
    <section class="gacha-pool-modal">
      <p class="eyebrow">Pool completo · rotação ${banner.rotationId || banner.hour}</p>
      <h2>${esc(banner.name)}</h2>
      <div class="gacha-pool-grid">${pool.map((item) => `<article class="${rarityClass(item.rarity)} ${featuredIds.has(item.id) ? "featured" : ""}">${type === "pets" ? `<img src="${esc(petImageFor(item, { thumbnail: true }))}" alt="${esc(item.altText || item.name)}" ${mediaAttrs("pet-thumbnail")} />` : `<span class="relic-silhouette">${esc(item.name.slice(0, 1))}</span>`}<div><small>${esc(item.rarity || "Comum")}${featuredIds.has(item.id) ? " · rate-up" : ""}</small><strong>${esc(item.name)}</strong><p>${esc(item.trait || item.effect || item.description || "Registro do pool.")}</p></div></article>`).join("")}</div>
    </section>`;
  $("#modal").hidden = false;
}

function pickGachaRarity(type = "pets") {
  const pool = gachaPool(type);
  const available = new Set(pool.map((item) => rarityKey(item.rarity)));
  const banner = activeGachaBanner(type);
  const featuredRarities = new Set(banner.featured.map((item) => rarityKey(item.rarity)));
  const weights = GACHA_RARITIES
    .filter((rarity) => available.has(rarity.id))
    .map((rarity) => {
      const rateUp = featuredRarities.has(rarity.id);
        const multiplier = rarity.id === "secret" && rateUp ? 10 : rateUp ? 1.65 : 1;
      return { ...rarity, weight: rarity.weight * multiplier };
    });
  return weightedPick(weights) || GACHA_RARITIES[1];
}

function pickGachaReward(type = "pets", rarity = "Comum") {
  const pool = gachaPool(type);
  const rarityPool = pool.filter((item) => rarityKey(item.rarity) === rarityKey(rarity));
  const fallback = rarityPool.length ? rarityPool : pool;
  const bannerItems = activeGachaBanner(type).featured.filter((item) => rarityKey(item.rarity) === rarityKey(rarity));
  if (bannerItems.length && Math.random() < 0.52) return bannerItems[Math.floor(Math.random() * bannerItems.length)];
  return fallback[Math.floor(Math.random() * fallback.length)] || null;
}

function shinyChanceFor(rarity) {
  const key = rarityKey(rarity);
  return { broken: 0.025, common: 0.022, uncommon: 0.018, epic: 0.012, legendary: 0.008, mythic: 0.005, cosmic: 0.003, celestial: 0.002, secret: 0.001 }[key] || 0.015;
}

function buildGachaInstance(source, type = "pets") {
  const shiny = Math.random() < shinyChanceFor(source.rarity);
  return {
    instanceId: cryptoRandom(),
    sourceId: source.id,
    kind: type === "items" ? "item" : "pet",
    name: `${shiny ? "Radiante " : ""}${source.name}`,
    baseName: source.name,
    rarity: source.rarity || "Comum",
    stars: 1,
    shiny,
    locked: false,
    equipped: false,
    status: "Livre",
    activityId: "",
    imageUrl: type === "items" ? (source.imageUrl || "") : petImageFor(source),
    archetype: source.archetype || source.category || "",
    element: source.element || "",
    category: source.category || "",
    bonus: source.bonus || {},
    td: source.td || {},
    trait: source.trait || source.effect || "",
    description: source.description || "",
    obtainedAt: new Date().toISOString(),
  };
}

function instancePower(instance) {
  const rarity = rarityScore(instance.rarity);
  const stars = Math.max(1, Number(instance.stars || 1));
  const shiny = instance.shiny ? 1.18 : 1;
  return Math.round((rarity * 100 + stars * 42) * (1 + (stars - 1) * 0.22) * shiny);
}

function scaledBonus(instance) {
  const stars = Math.max(1, Number(instance.stars || 1));
  const scale = (1 + (stars - 1) * 0.28) * (instance.shiny ? 1.12 : 1);
  return Object.fromEntries(Object.entries(instance.bonus || {}).map(([key, value]) => [key, Math.max(0, Math.round(Number(value || 0) * scale))]));
}

function equippedGachaBonuses(character = currentCharacter()) {
  return (character.gachaVault || [])
    .filter((item) => item.equipped && (item.kind === "item" || item.kind === "pet"))
    .map((item) => scaledBonus(item));
}

function gachaFragmentName(instanceOrType = "pets") {
  const kind = typeof instanceOrType === "string" ? instanceOrType : instanceOrType.kind;
  return kind === "item" || kind === "items" ? "Ecos de Relíquia" : "Ecos de Companheiro";
}

function fragmentGainFor(instance) {
  const meta = gachaRarityMeta(instance.rarity);
  const stars = Math.max(1, Number(instance.stars || 1));
  return Math.max(1, Math.round(meta.fragment * stars * (instance.shiny ? 1.5 : 1)));
}

function withFragments(character, name, amount) {
  return {
    ...(character.gachaFragments || {}),
    [name]: Number(character.gachaFragments?.[name] || 0) + Number(amount || 0),
  };
}

function refreshGachaEnergy(character = currentCharacter()) {
  const last = dateFromValue(character.gachaEnergyUpdatedAt);
  const lastKey = last ? localDayKey(last) : "";
  const todayKey = localDayKey();
  if (lastKey !== todayKey) {
    return { gachaEnergy: GACHA_ENERGY_MAX, gachaEnergyUpdatedAt: new Date().toISOString() };
  }
  return {};
}

function currentGachaEnergy(character = currentCharacter()) {
  const refreshed = refreshGachaEnergy(character);
  return Object.prototype.hasOwnProperty.call(refreshed, "gachaEnergy") ? refreshed.gachaEnergy : Number(character.gachaEnergy ?? GACHA_ENERGY_MAX);
}

function petBusy(instance) {
  return instance.status && !["Livre", "Equipado"].includes(instance.status);
}

function petRecoveryCost(instance) {
  const status = instance?.status || "Livre";
  const power = Math.max(1, Math.round(instancePower(instance || {}) / 260));
  if (status === "Morto") return 60 + power * 20;
  if (status === "Ferido") return 18 + power * 8;
  if (status === "Descansando") return 8 + power * 4;
  return 0;
}

function petPowerForPrestige(character = {}) {
  if (character.__rankingProjection || Object.prototype.hasOwnProperty.call(character, "petPower")) {
    return Math.max(0, Number(character.petPower || 0));
  }
  const seen = new Set();
  return [...(character.gachaVault || []).filter((item) => item?.kind === "pet"), ...(character.pets || [])]
    .filter((pet) => {
      const key = pet.instanceId || pet.id || `${pet.name || "pet"}:${pet.rarity || "Comum"}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .reduce((sum, pet) => sum + instancePower(pet), 0);
}

function approvedMissionCountForPrestige(character = {}) {
  const projected = Number(character.missions?.all || 0);
  const stored = Number(character.approvedMissionCount || 0);
  const ownerId = character.ownerId || character.id || "";
  const loaded = (state.progressRequests || []).filter((request) => request.uid === ownerId
    && request.status === "aprovado"
    && ["mission", "guildMission", "training"].includes(request.type)).length;
  return Math.max(0, projected, stored, loaded);
}

function prestigeBreakdown(character = {}) {
  const level = Math.max(1, Number(character.level || 0), levelFromXp(character.xp || 0));
  const xp = Math.max(0, Number(character.xp || 0));
  const missionCount = approvedMissionCountForPrestige(character);
  const developmentPoints = character.__rankingProjection || Object.prototype.hasOwnProperty.call(character, "developmentPoints")
    ? Math.max(0, Number(character.developmentPoints || 0))
    : ATTRIBUTES.reduce((sum, attribute) => sum + Math.max(0, Number(character.development?.[attribute.key] || 0)), 0);
  const petPower = petPowerForPrestige(character);
  const powerCount = Math.max(0, Number(character.powerCount ?? approvedPowerCount(character)));
  const techniqueCount = Math.max(0, Number(character.techniqueCount ?? (character.techniques || []).filter((entry) => entry?.name && entry.status !== "reprovado").length));
  const achievementCount = Math.max(0, Number(character.achievementCount ?? derivedAchievementIds(character).size));
  const passXp = Math.max(0, Number(character.passXp ?? character.seasonPassXp ?? 0));
  const components = {
    level: level * 100,
    xp: Math.floor(xp / 10),
    missions: missionCount * 120,
    development: developmentPoints * 75,
    pets: Math.floor(petPower / 20),
    po: Math.floor(Math.max(0, Number(character.gold || 0)) / 20),
    powers: powerCount * 100,
    techniques: techniqueCount * 60,
    achievements: achievementCount * 80,
    pass: Math.floor(passXp / 20),
    rarities: Math.max(0, Number(character.totalRares || 0)) * 30,
  };
  return {
    ...components,
    missionCount,
    developmentPoints,
    petPower,
    total: Object.values(components).reduce((sum, value) => sum + Number(value || 0), 0),
  };
}

function prestigeFor(character = {}) {
  return Math.floor(prestigeBreakdown(character).total);
}

function rankingEligible(character = {}) {
  const ownerId = character.ownerId || character.id || "";
  const user = state.users.find((entry) => entry.id === ownerId);
  if (!ownerId || !character.characterName) return false;
  if (character.__rankingProjection && character.eligible !== true) return false;
  if (character.excludeFromRanking === true) return false;
  if (user?.role === "admin") return false;
  if (["deleted", "removed"].includes(String(user?.status || "").toLowerCase())) return false;
  return Boolean(character.creationLocked || character.technicalCreationComplete);
}

function rankingCharacters() {
  const projected = state.rankingProfiles.map((profile) => ({
    ...profile,
    id: profile.id || profile.ownerId,
    ownerId: profile.ownerId || profile.id,
    __rankingProjection: true,
    creationLocked: profile.eligible === true,
    technicalCreationComplete: profile.eligible === true,
    millenniumCoins: Number(profile.coins || 0),
    seasonPassXp: Number(profile.passXp || 0),
    premiumPassUnlocked: profile.premiumPassUnlocked === true,
  }));
  const byOwner = new Map(projected.map((character) => [character.ownerId, character]));
  state.characters.forEach((character) => {
    const ownerId = character.ownerId || character.id;
    if (!byOwner.has(ownerId)) byOwner.set(ownerId, character);
  });
  if (state.character && !byOwner.has(state.user?.uid)) byOwner.set(state.user.uid, state.character);
  return [...byOwner.values()];
}

function classOwnerCount(classId) {
  return state.characters.filter((character) => rankingEligible(character) && character.classId === classId).length;
}

function levelFromXp(xp = 0) {
  return Math.max(1, Math.min(Number(state.settings.levelMax || 99), 1 + Math.floor(Number(xp || 0) / 100)));
}

function progressionFor(character = currentCharacter()) {
  return FOUNDATIONS.progressionSnapshot(character, Number(state.settings.levelMax || 99));
}

function pendingProgressRequests(uid = state.user?.uid) {
  return state.progressRequests.filter((request) => request.uid === uid && request.status === "pendente");
}

function pendingAttributeAllocation(uid = state.user?.uid) {
  return state.progressRequests.find((request) => request.uid === uid
    && request.type === "attributeAllocation"
    && !["aprovado", "reprovado"].includes(creationRequestStatus(request))) || null;
}

function pendingAttributeRedistribution(uid = state.user?.uid) {
  return state.progressRequests.find((request) => request.uid === uid
    && request.type === "attributeRedistribution"
    && !["aprovado", "reprovado"].includes(creationRequestStatus(request))) || null;
}

function baseAllocationSummary(base = {}) {
  return ATTRIBUTES.map((attribute) => `${attribute.short} ${Number(base?.[attribute.key] || 0)}`).join(" · ");
}

function attributeAllocationSummary(allocation = {}) {
  return ATTRIBUTES
    .map((attribute) => ({ label: attribute.short, amount: Math.max(0, Number(allocation?.[attribute.key] || 0)) }))
    .filter((entry) => entry.amount > 0)
    .map((entry) => `+${entry.amount} ${entry.label}`)
    .join(" · ") || "Nenhum ponto distribuído";
}

function syncPrivateMessages() {
  if (!state.selectedPrivateUserId) {
    state.privateMessages = [];
    return;
  }
  const legacy = state.directMessages
    .filter((message) => (message.participants || []).includes(state.user.uid) && (message.participants || []).includes(state.selectedPrivateUserId));
  state.privateMessages = window.MILLENNIUM_BACKEND_31.mergeMessages(
    [...legacy, ...(state.conversationMessages || [])],
    state.optimisticMessages || [],
  );
}

function profileViewsFor(uid = state.user?.uid) {
  return state.profileViews?.filter((view) => view.targetId === uid).length || 0;
}

function recentNews() {
  return state.globalMessages
    .filter((message) => ["system", "rare", "admin-alert", "join"].includes(message.type))
    .slice(-8);
}

function approvedPowerCount(character = currentCharacter()) {
  const powers = character.powers || [];
  if (powers.length) return powers.filter((power) => power.status !== "reprovado").length;
  return character.power?.name ? 1 : 0;
}

function progressTypeLabel(type) {
  return {
    training: "Treino",
    mission: "Missão",
    guildMission: "Missão de guilda",
    session: "Sessão de campanha",
    event: "Evento",
    achievement: "Conquista",
    minigame: "Minigame",
    attributeAllocation: "Distribuição de atributos",
    attributeRedistribution: "Redistribuição extraordinária",
    power: "Poder",
    technique: "Técnica",
    premiumPass: "Passe premium",
  }[type] || "Solicitação";
}

function defaultXpForRequest(type, rarity = "Comum") {
  const byRarity = { Comum: 50, Incomum: 75, Raro: 100, "Épico": 150, Lendário: 225, Cósmica: 300 };
  if (type === "training") return 50;
  if (type === "session") return 100;
  if (type === "event") return 150;
  if (type === "achievement") return 100;
  if (type === "minigame") return 20;
  if (["power", "technique", "premiumPass", "attributeAllocation", "attributeRedistribution"].includes(type)) return 0;
  return byRarity[rarity] || 50;
}

function requestRewardHint(request) {
  const parts = [];
  if (request.xp) parts.push(`${request.xp} XP`);
  if (request.reward) parts.push(request.reward);
  return parts.join(" · ") || "Oráculo define na aprovação";
}

function leaderboard() {
  return rankingCharacters()
    .filter(rankingEligible)
    .sort((a, b) => prestigeFor(b) - prestigeFor(a)
      || Number(b.totalRares || 0) - Number(a.totalRares || 0)
      || Math.max(Number(b.level || 0), levelFromXp(b.xp || 0)) - Math.max(Number(a.level || 0), levelFromXp(a.xp || 0)));
}

function prestigeComparison(character = currentCharacter()) {
  const ownerId = character.ownerId || character.id || state.user?.uid || "";
  const roster = new Map(rankingCharacters().filter(rankingEligible).map((entry) => [entry.ownerId || entry.id, entry]));
  if (ownerId && rankingEligible({ ...character, ownerId })) roster.set(ownerId, { ...character, ownerId });
  const ranked = [...roster.values()]
    .map((entry) => ({ character: entry, score: prestigeFor(entry) }))
    .sort((a, b) => b.score - a.score || String(a.character.characterName || "").localeCompare(String(b.character.characterName || ""), "pt-BR"));
  const index = ranked.findIndex((entry) => (entry.character.ownerId || entry.character.id) === ownerId);
  const own = index >= 0 ? ranked[index] : { character, score: prestigeFor(character) };
  const leaderScore = Math.max(1, Number(ranked[0]?.score || own.score || 1));
  return {
    score: own.score,
    position: index >= 0 ? index + 1 : 0,
    totalPlayers: ranked.length,
    leaderScore,
    gap: Math.max(0, leaderScore - own.score),
    percent: Math.max(0, Math.min(100, Math.round((own.score / leaderScore) * 100))),
    breakdown: prestigeBreakdown(character),
  };
}

function renderPityBar(value, max) {
  const pct = Math.max(0, Math.min(100, (Number(value || 0) / Math.max(1, Number(max || 1))) * 100));
  return `<div class="pity-bar" aria-label="Pity ${Number(value || 0)} de ${Number(max || 1)}"><span style="width:${pct}%"></span></div>`;
}

function mondayResetKey(date = new Date()) {
  const copy = new Date(date);
  copy.setHours(0, 0, 0, 0);
  const dayFromMonday = (copy.getDay() + 6) % 7;
  copy.setDate(copy.getDate() - dayFromMonday);
  return copy.toISOString().slice(0, 10);
}

function setAuthNote(message, tone = "neutral") {
  const note = $("#authNote");
  if (!note) return;
  note.hidden = !message;
  note.textContent = message || "";
  note.dataset.tone = tone;
}

function showAuth() {
  document.body.classList.remove("account-restricted");
  document.body.dataset.interfaceScope = "auth";
  clearRestrictionTimer();
  closeAwakeningCeremony({ markSeen: false, restoreFocus: false, resumeOnboarding: false });
  if (!state.user) state.awakeningCeremonyScheduled = false;
  $("#authScreen").hidden = false;
  $("#appShell").hidden = true;
  const skipLink = $("#skipLink");
  if (skipLink) {
    skipLink.href = "#authMain";
    skipLink.textContent = "Pular para o formulário de acesso";
  }
  updateMusicButton();
  $("#demoActions").hidden = false;
  setAuthNote(
    state.firebaseReady
      ? "Modo demo local disponível para testar a interface sem alterar contas reais."
      : "Firebase não carregou nesta sessão. Use o modo demo local para testar a interface.",
    state.firebaseReady ? "neutral" : "danger",
  );
  updateBuildBadge();
  normalizeRenderedImages($("#authScreen"));
  normalizeRenderedAccessibility($("#authScreen"));
}

function awakeningCeremonyStorageKey(uid = state.user?.uid || "anonymous") {
  return `millennium:awakening-ceremony:${uid}:${AWAKENING_CEREMONY_VERSION}`;
}

function awakeningCeremonySeen() {
  try { return localStorage.getItem(awakeningCeremonyStorageKey()) === "seen"; } catch { return false; }
}

function markAwakeningCeremonySeen() {
  try { localStorage.setItem(awakeningCeremonyStorageKey(), "seen"); } catch { /* storage unavailable */ }
}

function awakeningCeremonyEligible(character = currentCharacter()) {
  if (!state.user || state.role === "admin" || state.accountDeletionQueue || accountIsRestricted()) return false;
  if (!hasAcceptedTerms()) return false;
  return Boolean(character.characterName || character.technicalCreationComplete || character.creationLocked);
}

function awakeningCeremonyMarkup(character = currentCharacter()) {
  const affinity = getAffinity(character.affinityId);
  const race = getRace(character.raceId);
  const roleClass = getClass(character.classId);
  const title = activeTitle(character);
  let totals = character.base || {};
  try { totals = getTotals(character); } catch { /* preserve presentation with base values */ }
  const values = ATTRIBUTES.map((attribute) => Number(totals[attribute.key] ?? character.base?.[attribute.key] ?? 0));
  const maxValue = Math.max(1, ...values);
  const heroName = character.characterName || state.profile?.displayName || "Escolhido";
  const titleName = title?.name || "Recém-Desperto";
  const avatar = character.avatarUrl || placeholderAvatar();
  const summary = character.characterDescription
    || character.story
    || "A Interface abriu uma janela para uma história que ainda não terminou.";
  return `
    <div class="awakening-record">
      <section class="awakening-portrait-stage" aria-label="Retrato do herói despertado">
        <img class="awakening-sigil-large" src="assets/awakening/sigilo-primeiro-despertar.svg" alt="" aria-hidden="true" ${mediaAttrs("sigil")} />
        <div class="awakening-avatar-shell"><img src="${esc(avatar)}" style="${esc(cropImageStyle(character, "avatar"))}" alt="Retrato de ${esc(heroName)}" ${mediaAttrs("portrait", "eager")} /></div>
        <div class="awakening-portrait-caption"><span>Registro reconhecido</span><strong>${esc(heroName)}</strong></div>
      </section>
      <section class="awakening-record-copy">
        <p class="eyebrow">Cerimônia do Primeiro Despertar</p>
        <h2 id="awakeningCeremonyTitle">A aurora encontrou ${esc(heroName)}.</h2>
        <p class="awakening-title-line">${esc(titleName)}</p>
        <p class="awakening-summary">${esc(summary)}</p>
        <div class="awakening-identity-grid" aria-label="Identidade do personagem">
          <div><span>Afinidade</span><strong>${esc(affinity?.name || "Ainda não revelada")}</strong></div>
          <div><span>Raça</span><strong>${esc(race?.name || "Não registrada")}</strong></div>
          <div><span>Classe</span><strong>${esc(roleClass?.name || "Não registrada")}</strong></div>
        </div>
        <div class="awakening-stats" aria-label="Atributos atuais">
          ${ATTRIBUTES.map((attribute, index) => {
            const value = values[index];
            const fill = Math.max(8, Math.round((value / maxValue) * 100));
            return `<div class="awakening-stat" style="--awakening-stat-fill:${fill}%"><span>${esc(attribute.short)}</span><strong>${value}</strong></div>`;
          }).join("")}
        </div>
        <div class="awakening-ceremony-actions">
          <button class="primary-button intense" type="button" data-action="close-awakening-ceremony">Entrar em Millennium</button>
          <button class="ghost-button" type="button" data-action="awakening-open-onboarding">Rever jornada inicial</button>
        </div>
      </section>
    </div>`;
}

function openAwakeningCeremony(options = {}) {
  const ceremony = $("#awakeningCeremony");
  const content = $("#awakeningCeremonyContent");
  if (!ceremony || !content || !state.user || state.role === "admin") return false;
  const character = currentCharacter();
  if (!options.force && (!awakeningCeremonyEligible(character) || awakeningCeremonySeen())) return false;
  state.awakeningCeremonyReturnFocus = document.activeElement;
  state.awakeningCeremonyOpen = true;
  state.awakeningCeremonyScheduled = true;
  content.innerHTML = awakeningCeremonyMarkup(character);
  normalizeRenderedImages(content);
  normalizeRenderedAccessibility(content);
  ceremony.hidden = false;
  ceremony.setAttribute("aria-hidden", "false");
  const appShell = $("#appShell");
  if (appShell) appShell.inert = true;
  window.requestAnimationFrame(() => ceremony.querySelector(".awakening-ceremony-card")?.focus());
  return true;
}

function closeAwakeningCeremony(options = {}) {
  const { markSeen = true, restoreFocus = true, resumeOnboarding = true } = options;
  const ceremony = $("#awakeningCeremony");
  if (!ceremony) return;
  const wasOpen = !ceremony.hidden || state.awakeningCeremonyOpen;
  ceremony.hidden = true;
  ceremony.setAttribute("aria-hidden", "true");
  state.awakeningCeremonyOpen = false;
  const appShell = $("#appShell");
  if (appShell && $("#modal")?.hidden) appShell.inert = false;
  if (wasOpen && markSeen) markAwakeningCeremonySeen();
  if (restoreFocus && state.awakeningCeremonyReturnFocus?.isConnected) state.awakeningCeremonyReturnFocus.focus();
  state.awakeningCeremonyReturnFocus = null;
  if (wasOpen && resumeOnboarding) window.setTimeout(() => maybeOpenOnboarding(), 180);
}

function maybeOpenAwakeningCeremony() {
  if (state.awakeningCeremonyScheduled || awakeningCeremonySeen()) return false;
  if (!awakeningCeremonyEligible()) return false;
  state.awakeningCeremonyScheduled = true;
  window.setTimeout(() => openAwakeningCeremony(), 180);
  return true;
}

function trapAwakeningCeremonyFocus(event) {
  if (!state.awakeningCeremonyOpen || event.key !== "Tab") return;
  const ceremony = $("#awakeningCeremony");
  const focusable = [...ceremony.querySelectorAll('button:not([disabled]), [href], input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])')]
    .filter((element) => !element.hidden && element.getClientRects().length);
  if (!focusable.length) return;
  const first = focusable[0];
  const last = focusable[focusable.length - 1];
  if (event.shiftKey && document.activeElement === first) { event.preventDefault(); last.focus(); }
  else if (!event.shiftKey && document.activeElement === last) { event.preventDefault(); first.focus(); }
}


function firebaseErrorCode(error = {}) {
  return String(error?.code || error?.name || "").replace(/^firestore\//, "").toLowerCase();
}

function isFirestoreQuotaError(error = {}) {
  const code = firebaseErrorCode(error);
  const message = String(error?.message || "").toLowerCase();
  return code === "resource-exhausted"
    || message.includes("quota exceeded")
    || message.includes("resource exhausted");
}

function pauseFirestoreForSession(error, source = "firebase") {
  if (!isFirestoreQuotaError(error)) return false;
  state.firestorePaused = true;
  state.firestorePausedAt = Date.now();
  state.firestorePauseReason = `${source}: ${String(error?.code || error?.message || "resource-exhausted")}`.slice(0, 300);
  state.diagnostics.lastSyncError = state.firestorePauseReason;

  if (!state.firestoreQuotaNoticeShown) {
    state.firestoreQuotaNoticeShown = true;
    toast("A cota diária gratuita do Firestore foi esgotada. O site pausou novas sincronizações nesta sessão para não repetir chamadas. Aguarde a renovação da cota e recarregue a página.");
  }

  window.setTimeout(() => {
    if (state.firestorePaused) cleanupListeners();
  }, 0);
  return true;
}

function assertFirestoreAvailable() {
  if (!state.firestorePaused) return;
  const error = new Error("A sincronização do Firestore está pausada nesta sessão porque a cota diária foi esgotada. Recarregue somente depois da renovação da cota.");
  error.code = "resource-exhausted";
  throw error;
}

function handleFirebaseOperationError(error, source = "firebase") {
  pauseFirestoreForSession(error, source);
  return error;
}

function firebaseErrorMessage(error) {
  const code = error?.code || "";
  const messages = {
    "auth/email-already-in-use": "Esse email já tem conta. Use Entrar em vez de Criar conta.",
    "auth/invalid-email": "Email inválido.",
    "auth/invalid-credential": "Email ou senha incorretos.",
    "auth/user-not-found": "Conta não encontrada. Crie a conta primeiro.",
    "auth/wrong-password": "Senha incorreta.",
    "auth/weak-password": "A senha precisa ter pelo menos 6 caracteres.",
    "auth/configuration-not-found": "Firebase Authentication ainda não está configurado nesse projeto. No Firebase Console, vá em Authentication, clique em Get started e ative Email/Password.",
    "auth/operation-not-allowed": "Ative Email/Senha em Firebase Authentication > Sign-in method.",
    "auth/unauthorized-domain": "Domínio não autorizado no Firebase. Adicione 127.0.0.1 e localhost em Authentication > Settings > Authorized domains.",
    "auth/network-request-failed": "Não consegui conectar ao Firebase agora. Verifique internet, bloqueios do navegador ou tente recarregar.",
    "permission-denied": "A operação foi bloqueada pelo Firestore. Confirme que o site e as regras estão na versão 3.6.4 Aurora.",
    "failed-precondition": "O Firestore precisa de um índice ou configuração adicional. Publique firestore.indexes.json e recarregue o site.",
    "unavailable": "O Firebase está temporariamente indisponível. Nenhuma alteração foi confirmada; tente novamente.",
    "deadline-exceeded": "A conexão demorou além do limite. Confira a internet e tente novamente sem repetir vários cliques.",
    "resource-exhausted": "A cota diária gratuita do Firestore foi esgotada. O site pausou novas chamadas nesta sessão; aguarde a renovação da cota e recarregue.",
  };
  return messages[code] || error?.message || "Não foi possível concluir a ação.";
}

function loadScript(src, timeoutMs = 10000) {
  return new Promise((resolve) => {
    if ([...document.scripts].some((script) => script.src === src)) {
      resolve(true);
      return;
    }

    const script = document.createElement("script");
    const timer = window.setTimeout(() => {
      script.remove();
      resolve(false);
    }, timeoutMs);
    script.src = src;
    script.onload = () => {
      window.clearTimeout(timer);
      resolve(true);
    };
    script.onerror = () => {
      window.clearTimeout(timer);
      resolve(false);
    };
    document.head.appendChild(script);
  });
}

async function loadFirebaseScripts() {
  if (window.firebase?.initializeApp && window.firebase?.auth && window.firebase?.firestore) return true;

  for (const src of FIREBASE_SCRIPTS) {
    const loaded = await loadScript(src);
    if (!loaded) return false;
  }

  return Boolean(window.firebase?.initializeApp && window.firebase?.auth && window.firebase?.firestore);
}

function cleanupListeners() {
  state.unsubs.forEach((unsub) => {
    try {
      unsub();
    } catch {
      // noop
    }
  });
  state.unsubs = [];
  clearRouteSubscriptions();
  state.routeOnceCache.clear();
  if (state.privateUnsub) state.privateUnsub();
  state.privateUnsub = null;
  state.characterUnsub = null;
  stopPresenceTracking();
  clearRestrictionTimer();
  if (state.renderFrame) window.cancelAnimationFrame(state.renderFrame);
  state.renderFrame = 0;
  if (state.renderTimer) window.clearTimeout(state.renderTimer);
  state.renderTimer = null;
  if (state.searchTimer) window.clearTimeout(state.searchTimer);
  state.searchTimer = null;
  if (state.searchUpdateTimer) window.clearTimeout(state.searchUpdateTimer);
  state.searchUpdateTimer = 0;
  state.searchTask?.cancel?.();
  state.searchTask = null;
  state.pendingRenderRequest = null;
  state.renderReason = "";
}

async function setPresence(online, options = {}) {
  if (!state.user) return false;
  const force = options.force === true;
  const now = Date.now();
  if (online) {
    if (!force && (document.hidden || now - state.lastActivityAt >= IDLE_LIMIT_MS)) return false;
    if (!claimPresenceLease()) return false;
    let lastSharedWrite = 0;
    try { lastSharedWrite = Number(localStorage.getItem(presenceStorageKey("last-write")) || 0); } catch { /* no-op */ }
    if (!force && state.lastPresenceOnline === true && now - Math.max(state.lastPresenceWriteAt, lastSharedWrite) < PRESENCE_HEARTBEAT_MS) return false;
  } else if (!force) {
    const lease = readPresenceLease();
    if (lease?.tabId && lease.tabId !== presenceTabId()) return false;
  }

  const payload = {
    online,
    lastSeen: state.demo ? new Date().toISOString() : nowValue(),
  };
  if (state.demo) {
    writeDemo("users", state.user.uid, payload);
    state.lastPresenceWriteAt = now;
    state.lastPresenceOnline = online;
    return true;
  }
  if (!state.db || state.firestorePaused) return false;
  try {
    await state.db.collection("users").doc(state.user.uid).set(payload, { merge: true });
    state.diagnostics.writes += 1;
    state.lastPresenceWriteAt = now;
    state.lastPresenceOnline = online;
    try { localStorage.setItem(presenceStorageKey("last-write"), String(now)); } catch { /* no-op */ }
    if (!online) releasePresenceLease();
    return true;
  } catch (error) {
    handleFirebaseOperationError(error, "presenca");
    return false;
  }
}

function runPresenceHeartbeat(force = false) {
  if (!state.user || accountIsRestricted(state.profile)) return;
  setPresence(true, { force }).catch(() => {});
}

function startPresence() {
  touchActivity();
  runPresenceHeartbeat(true);
  if (state.presenceTimer) window.clearInterval(state.presenceTimer);
  state.presenceTimer = window.setInterval(() => runPresenceHeartbeat(false), PRESENCE_CHECK_MS);
  if (state.presenceVisibilityHandler) document.removeEventListener("visibilitychange", state.presenceVisibilityHandler);
  state.presenceVisibilityHandler = () => {
    if (!document.hidden) {
      touchActivity();
      runPresenceHeartbeat(false);
    }
  };
  document.addEventListener("visibilitychange", state.presenceVisibilityHandler);
  if (state.idleTimer) window.clearInterval(state.idleTimer);
  state.idleTimer = window.setInterval(checkIdleTimeout, 30000);
}

function touchActivity() {
  state.lastActivityAt = Date.now();
}

async function checkIdleTimeout() {
  if (!state.user || state.role === "admin") return;
  if (Date.now() - state.lastActivityAt < IDLE_LIMIT_MS) return;
  toast("Sessão encerrada por inatividade.");
  await setPresence(false, { force: true });
  cleanupListeners();
  if (state.firebaseReady && state.auth?.currentUser) await state.auth.signOut().catch(() => {});
  state.user = null;
  state.demo = false;
  showAuth();
}

async function initFirebase() {
  state.firebaseReady = await loadFirebaseScripts();
  if (!state.firebaseReady) {
    showAuth();
    return;
  }

  state.app = firebase.apps?.length ? firebase.app() : firebase.initializeApp(firebaseConfig);
  state.auth = firebase.auth();
  state.db = firebase.firestore();
  try {
    state.db.settings({
      experimentalAutoDetectLongPolling: true,
      ignoreUndefinedProperties: true,
    }, { merge: true });
  } catch (error) {
    console.warn("Configuração de transporte do Firestore preservada:", error);
  }
  try {
    await state.db.enablePersistence({ synchronizeTabs: true });
    state.diagnostics.persistence = "multi-tab";
  } catch (error) {
    const code = String(error?.code || "");
    state.diagnostics.persistence = code || "unavailable";
    if (!code.includes("failed-precondition") && !code.includes("unimplemented")) {
      console.warn("Persistência local do Firestore não pôde ser ativada:", error);
    }
  }
  state.functions = null;
  await state.auth.setPersistence(firebase.auth.Auth.Persistence.LOCAL).catch(() => {});

  state.auth.onAuthStateChanged(async (user) => {
    cleanupListeners();
    if (!user) {
      state.user = null;
      state.profile = null;
      showAuth();
      return;
    }

    state.user = user;
    try {
      await ensureUserProfile(user);
      subscribeCore();
    } catch (error) {
      handleFirebaseOperationError(error, "carregamento-do-perfil");
      console.error(error);
      toast(firebaseErrorMessage(error));
      if (state.firestorePaused) {
        $("#authScreen").hidden = true;
        $("#appShell").hidden = false;
        render();
      } else {
        showAuth();
      }
    }
  });
}

async function ensureUserProfile(user) {
  const queueRef = state.db.collection("accountDeletionQueue").doc(user.uid);
  const queueSnap = await queueRef.get().catch(() => null);
  if (queueSnap?.exists && queueSnap.data()?.status === "awaiting-auth-delete") {
    state.accountDeletionQueue = { id: user.uid, ...queueSnap.data() };
    state.profile = {
      id: user.uid,
      email: user.email || queueSnap.data()?.email || "",
      displayName: queueSnap.data()?.displayName || "Usuário removido",
      role: "player",
      accountStatus: "deletion_pending",
      restrictionReason: "Os dados desta conta foram removidos. A exclusão da credencial está pendente no Firebase Authentication.",
    };
    return;
  }

  state.accountDeletionQueue = null;
  const ref = state.db.collection("users").doc(user.uid);
  const snap = await ref.get();

  if (snap.exists) {
    state.profile = { id: user.uid, accountStatus: "active", ...snap.data() };
    return;
  }

  const profile = {
    id: user.uid,
    email: user.email,
    displayName: user.email?.split("@")[0] || "Player",
    role: "player",
    accountStatus: "active",
    restrictionReason: "",
    suspendedUntil: null,
    createdAt: nowValue(),
  };
  await ref.set(profile, { merge: true });
  await state.db.collection("characters").doc(user.uid).set(defaultCharacter(user.uid, profile.displayName), { merge: true });
  state.profile = profile;
}

async function seedDefaultsIfNeeded() {
  if (!state.db) return;
  try {
    const settingsRef = state.db.collection("settings").doc("system");
    const snap = await settingsRef.get();
    if (snap.exists && Number(snap.data().seedVersion || 0) >= SEED_VERSION) return;

    const writes = [];
    for (const collection of CONTENT_COLLECTIONS) {
      DEFAULT_CONTENT[collection].forEach((item) => {
        writes.push({ ref: state.db.collection(collection).doc(item.id), data: item });
      });
    }
    writes.push({ ref: settingsRef, data: DEFAULT_CONTENT.settings });
    for (let offset = 0; offset < writes.length; offset += 400) {
      const batch = state.db.batch();
      writes.slice(offset, offset + 400).forEach(({ ref, data }) => {
        batch.set(ref, data, { merge: true });
      });
      await batch.commit();
    }
  } catch (error) {
    console.warn("Seed skipped:", error);
  }
}

function subscribeDoc(path, id, cb) {
  if (state.firestorePaused) return () => {};
  state.diagnostics.listenerStarts += 1;
  const unsub = state.db.collection(path).doc(id).onSnapshot((snap) => {
    state.diagnostics.documentsRead += snap.exists ? 1 : 0;
    cb(snap.exists ? { id: snap.id, ...snap.data() } : null);
  }, (error) => {
    handleFirebaseOperationError(error, `listener:${path}/${id}`);
    console.error(`Listener ${path}/${id}:`, error);
  });
  state.unsubs.push(unsub);
  state.diagnostics.listenerCount = state.unsubs.length + state.routeUnsubs.length + (state.privateUnsub ? 1 : 0);
  return unsub;
}

function subscribeCollection(path, cb, queryBuilder = null, bucket = state.unsubs) {
  const base = state.db.collection(path);
  const query = queryBuilder ? queryBuilder(base) : base;
  let initialized = false;
  state.diagnostics.listenerStarts += 1;
  const unsub = query.onSnapshot(
    (snap) => {
      state.diagnostics.documentsRead += initialized ? snap.docChanges().length : snap.size;
      initialized = true;
      state.syncErrorNotices.delete(path);
      cb(snap.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    },
    (error) => {
      handleFirebaseOperationError(error, `listener:${path}`);
      console.error(error);
      state.diagnostics.lastSyncError = `${path}: ${String(error?.code || error?.message || "erro")}`.slice(0, 300);
      if (path === "directMessages") {
        state.privateChatError = "O Firestore bloqueou o chat direto. Publique as regras novas e recarregue o site.";
        render();
      }
      if (["progressRequests", "reports"].includes(path) && !state.syncErrorNotices.has(path)) {
        state.syncErrorNotices.add(path);
        toast(path === "progressRequests"
          ? "Não foi possível sincronizar as validações. Confira regras, índices e conexão antes de analisar a fila."
          : "Não foi possível sincronizar os reports. Confira regras, índices e conexão antes de salvar uma análise.");
      }
    },
  );
  bucket.push(unsub);
  state.diagnostics.listenerCount = state.unsubs.length + state.routeUnsubs.length;
}

function clearRouteSubscriptions() {
  state.routeUnsubs.forEach((unsubscribe) => {
    try { unsubscribe(); } catch { /* no-op */ }
  });
  state.routeUnsubs = [];
  state.routeSubscriptionNames = [];
  state.routeSubscriptionKey = "";
  state.diagnostics.listenerCount = state.unsubs.length;
}

function routeCollection(path, cb, queryBuilder = null, name = path) {
  const useEconomySnapshot = state.role !== "admin"
    && Boolean(state.profile?.dataEconomy)
    && !["globalMessages", "conversations", "directMessages", "guildMessages"].includes(path);
  if (useEconomySnapshot) {
    const routeKey = state.routeSubscriptionKey;
    const cacheKey = `${state.user?.uid || "anonymous"}:${name}`;
    state.routeSubscriptionNames.push(`${name}:once`);
    if (state.routeOnceCache.has(cacheKey)) {
      cb(state.routeOnceCache.get(cacheKey));
      return;
    }
    const base = state.db.collection(path);
    const query = queryBuilder ? queryBuilder(base) : base;
    query.get().then((snapshot) => {
      state.diagnostics.documentsRead += snapshot.size;
      const entries = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
      state.routeOnceCache.set(cacheKey, entries);
      if (state.routeSubscriptionKey === routeKey) cb(entries);
    }).catch((error) => {
      handleFirebaseOperationError(error, `economy-snapshot:${path}`);
      console.error(`Snapshot econÃ´mico ${path}:`, error);
    });
    return;
  }
  subscribeCollection(path, cb, queryBuilder, state.routeUnsubs);
  state.routeSubscriptionNames.push(name);
}

function routeDocument(path, id, cb, name = `${path}/${id}`) {
  if (state.firestorePaused) return;
  if (state.role !== "admin" && state.profile?.dataEconomy) {
    const routeKey = state.routeSubscriptionKey;
    const cacheKey = `${state.user?.uid || "anonymous"}:${name}`;
    state.routeSubscriptionNames.push(`${name}:once`);
    if (state.routeOnceCache.has(cacheKey)) {
      cb(state.routeOnceCache.get(cacheKey));
      return;
    }
    state.db.collection(path).doc(id).get().then((snapshot) => {
      state.diagnostics.documentsRead += snapshot.exists ? 1 : 0;
      const entry = snapshot.exists ? { id: snapshot.id, ...snapshot.data() } : null;
      state.routeOnceCache.set(cacheKey, entry);
      if (state.routeSubscriptionKey === routeKey) cb(entry);
    }).catch((error) => {
      handleFirebaseOperationError(error, `economy-snapshot:${path}/${id}`);
      console.error(`Snapshot econÃ´mico ${path}/${id}:`, error);
    });
    return;
  }
  state.diagnostics.listenerStarts += 1;
  const unsub = state.db.collection(path).doc(id).onSnapshot((snapshot) => {
    state.diagnostics.documentsRead += snapshot.exists ? 1 : 0;
    cb(snapshot.exists ? { id: snapshot.id, ...snapshot.data() } : null);
  }, (error) => {
    handleFirebaseOperationError(error, `listener:${path}/${id}`);
    console.error(`Listener ${path}/${id}:`, error);
  });
  state.routeUnsubs.push(unsub);
  state.routeSubscriptionNames.push(name);
  state.diagnostics.listenerCount = state.unsubs.length + state.routeUnsubs.length;
}

function subscribeUserDirectory() {
  if (state.role === "admin") {
    routeCollection("users", (users) => {
      state.users = users;
      scheduleRender({ route: state.view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.limit(500));
  } else {
    state.users = state.profile ? [{ id: state.user.uid, ...state.profile }] : [];
  }
  routeCollection("publicProfiles", (profiles) => {
    state.publicProfiles = profiles;
    if (state.role !== "admin") {
      state.users = profiles.map((profile) => ({ id: profile.ownerId || profile.id, displayName: profile.player || profile.name || "Player", publicOnly: true }));
    }
    scheduleRender({ route: state.view, preserveFocus: true, preserveScroll: true });
  }, (query) => state.role === "admin" ? query.limit(500) : query.where("privacy", "==", "public").limit(500));
}

function subscribeOwnRequests() {
  routeCollection("progressRequests", (requests) => {
    state.progressRequests = requests;
    scheduleRender({ route: state.view, preserveFocus: true, preserveScroll: true });
  }, (query) => state.role === "admin"
    ? query.orderBy("createdAt", "desc").limit(30)
    : query.where("uid", "==", state.user.uid).orderBy("createdAt", "desc").limit(20));
}

function decorateCatalog(collection, items) {
  const decorated = WORLD.decorateCollection(collection, items.length ? items : DEFAULT_CONTENT[collection]);
  state.content[collection] = decorated;
  if (collection === "affinities") state.content.affinities = FOUNDATIONS.enrichAffinities(state.content.affinities, state.content.affinityCategories);
  return decorated;
}

async function loadCatalogOnce(collection, options = {}) {
  if (state.demo || !state.db || state.firestorePaused) return state.content[collection] || [];
  if (!options.force && state.catalogLoaded.has(collection)) return state.content[collection] || [];
  if (!options.force && state.catalogPromises.has(collection)) return state.catalogPromises.get(collection);
  const promise = state.db.collection(collection).limit(Number(options.limit || 120)).get()
    .then((snapshot) => {
      state.diagnostics.documentsRead += snapshot.size;
      state.diagnostics.catalogReads += snapshot.size;
      const items = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
      state.catalogLoaded.add(collection);
      return decorateCatalog(collection, items);
    })
    .catch((error) => {
      handleFirebaseOperationError(error, `catalog:${collection}`);
      console.error(`Catálogo ${collection}:`, error);
      return state.content[collection] || [];
    })
    .finally(() => state.catalogPromises.delete(collection));
  state.catalogPromises.set(collection, promise);
  return promise;
}

function requestRouteCatalog(collection, view) {
  loadCatalogOnce(collection).then(() => {
    if (state.view === view && !state.firestorePaused) scheduleRender({ route: view, preserveFocus: true, preserveScroll: true, reason: `catalog-cache-${collection}` });
  });
}

function selectedAdminContentCollection(tab = state.contentTab) {
  const groups = {
    world: ["worldLore", "reputationFactions", "worldEvents", "bestiary", "campaignPosts"],
    gacha: ["gachaPets", "gachaItems", "gachaShardShops", "towerMaps", "gachaBanners", "marketListings", "auctionListings", "craftingRecipes"],
    epic: ["wantedBoard", "bestiary", "marketListings", "auctionListings", "craftingRecipes", "techniqueLibrary", "achievements", "seasonPass", "passMissions", "gachaPets", "gachaItems", "gachaShardShops", "towerMaps", "reputationFactions", "worldEvents", "campaignPosts"],
  };
  const fallback = tab === "world" ? "worldLore" : tab === "gacha" ? "gachaPets" : "wantedBoard";
  const allowed = groups[tab] || [];
  return allowed.includes(state.epicCollection) ? state.epicCollection : fallback;
}

function adminContentCollections(tab = state.contentTab) {
  const map = {
    race: ["races"],
    class: ["classes"],
    category: ["affinityCategories", "affinities"],
    affinity: ["affinityCategories", "affinities"],
    itemCategory: ["itemCategories", "items"],
    item: ["itemCategories", "items"],
    biome: ["biomes"],
    kingdom: ["kingdoms"],
    region: ["kingdoms", "regions"],
    npc: ["npcs"],
    rules: ["rulesChapters"],
    faq: ["faqEntries"],
    tutorial: ["tutorialSteps"],
  };
  if (map[tab]) return map[tab];
  const selected = selectedAdminContentCollection(tab);
  if (selected === "gachaBanners") return ["gachaPets", "gachaItems", selected];
  return [selected];
}

function activateRouteSubscriptions(view = state.view) {
  if (state.demo || !state.db || !state.user || state.firestorePaused) return;
  const key = `${state.role}:${state.user.uid}:${view}:${state.profile?.dataEconomy ? "economy" : "live"}`;
  if (state.routeSubscriptionKey === key) return;
  clearRouteSubscriptions();
  state.routeSubscriptionKey = key;

  const needsDirectory = ["player-home", "profile", "chat", "guild", "ranking", "hall", "reports", "admin-home", "admin-users", "admin-chat", "admin-mail", "admin-ops", "admin-reports", "admin-settings"].includes(view);
  if (needsDirectory) subscribeUserDirectory();

  if (["admin-home", "admin-users", "admin-requests", "admin-ops", "admin-settings", "ranking"].includes(view) && state.role === "admin") {
    routeCollection("characters", (characters) => {
      state.characters = characters;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.limit(250));
    routeCollection("accountDeletionQueue", (entries) => {
      state.accountDeletionQueueEntries = entries;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.orderBy("createdAt", "desc").limit(30), "account-deletion-queue");
  }

  if (["player-home", "profile", "ranking", "hall"].includes(view)) {
    routeCollection("rankings", (profiles) => {
      state.rankingProfiles = profiles;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true, reason: "ranking-live" });
    }, (query) => query.orderBy("eligible", "desc"), "ranking-projections");
  }

  if (["player-home", "missions", "guild", "admin-home", "admin-missions"].includes(view)) {
    routeCollection("weeklyMissions", (missions) => {
      state.weeklyMissions = missions;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.orderBy("createdAt", "desc").limit(20));
  }

  if (["player-home", "chat", "admin-home", "admin-chat"].includes(view)) {
    routeCollection("globalMessages", (messages) => {
      state.globalMessages = messages.reverse();
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.orderBy("createdAt", "desc").limit(view === "player-home" ? 10 : 30));
  }

  if (["chat", "admin-chat"].includes(view)) {
    routeCollection("conversations", (conversations) => {
      state.conversations = conversations;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.where("participantIds", "array-contains", state.user.uid).orderBy("lastMessageAt", "desc").limit(30), "conversation-summaries");
    routeCollection("directMessages", (messages) => {
      state.directMessages = messages.reverse();
      syncPrivateMessages();
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.where("participants", "array-contains", state.user.uid).orderBy("createdAt", "desc").limit(30), "legacy-direct-messages");
  }

  if (["player-home", "missions", "guild", "creations", "pass", "admin-home", "admin-requests", "admin-ops"].includes(view)) subscribeOwnRequests();

  if (view === "character-life") {
    routeDocument(`characters/${state.user.uid}/lore`, "main", (lore) => {
      state.characterLore = lore || {};
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    });
  }

  if (["profile", "chat", "guild", "admin-mail"].includes(view)) {
    routeCollection("socialRequests", (requests) => {
      state.socialRequests = requests;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.where("participants", "array-contains", state.user.uid).orderBy("createdAt", "desc").limit(30));
  }

  if (["player-home", "guild", "market", "ranking", "hall", "admin-home", "admin-ops"].includes(view)) {
    routeCollection("guilds", (guilds) => {
      state.guilds = guilds;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query);
  }

  if (["guild", "admin-chat"].includes(view)) {
    routeCollection("guildMessages", (messages) => {
      state.guildMessages = messages.reverse();
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => state.role === "admin"
      ? query.orderBy("createdAt", "desc").limit(30)
      : query.where("memberIds", "array-contains", state.user.uid).orderBy("createdAt", "desc").limit(30));
    routeCollection("guildMissions", (missions) => {
      state.guildMissions = missions.length ? missions : [...DEFAULT_GUILD_MISSIONS];
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.limit(20));
  }

  if (view === "diary") {
    routeCollection("campaignDiary", (entries) => {
      state.diaryEntries = entries;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => query.orderBy("createdAt", "desc").limit(20));
  }

  if (["reports", "admin-home", "admin-reports"].includes(view)) {
    routeCollection("reports", (reports) => {
      state.reports = reports;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => state.role === "admin"
      ? query.orderBy("createdAt", "desc").limit(20)
      : query.where("reporterId", "==", state.user.uid).orderBy("createdAt", "desc").limit(20));
  }

  if (["market", "admin-ops"].includes(view)) {
    routeCollection("marketTrades", (trades) => {
      state.marketTrades = trades;
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true });
    }, (query) => state.role === "admin"
      ? query.orderBy("createdAt", "desc").limit(30)
      : query.where("participants", "array-contains", state.user.uid).orderBy("createdAt", "desc").limit(30));
    for (const collection of ["playerListings", "auctionBids"]) {
      routeCollection(collection, (items) => {
        state.content[collection] = items;
        scheduleRender({ route: view, preserveFocus: true, preserveScroll: true, reason: `market-${collection}` });
      }, (query) => query.orderBy("createdAt", "desc").limit(100), `market-${collection}`);
    }
  }

  if (view === "admin-content" && state.role === "admin") {
    adminContentCollections().forEach((collection) => routeCollection(collection, (items) => {
      state.catalogLoaded.add(collection);
      decorateCatalog(collection, items);
      scheduleRender({ route: view, preserveFocus: true, preserveScroll: true, reason: `admin-content-${collection}` });
    }, (query) => query.limit(100), `admin-content-${collection}`));
  } else {
    const routeCatalogs = new Set();
    if (["character", "profile", "player-home", "ranking", "admin-users"].includes(view)) ["classes", "races", "affinities", "items"].forEach((entry) => routeCatalogs.add(entry));
    if (["character", "character-life", "cultures", "professions", "codex"].includes(view)) ["classes", "races", "kingdoms", "regions", "biomes"].forEach((entry) => routeCatalogs.add(entry));
    if (["gacha", "minigames", "inventory", "admin-economy"].includes(view)) ["gachaPets", "gachaItems", "gachaBanners", "biomes", "towerMaps", "items"].forEach((entry) => routeCatalogs.add(entry));
    if (view === "market") ["marketListings", "auctionListings", "craftingRecipes", "items"].forEach((entry) => routeCatalogs.add(entry));
    if (view === "pass") ["seasonPass", "passMissions"].forEach((entry) => routeCatalogs.add(entry));
    if (view === "help") ["rulesChapters", "faqEntries", "tutorialSteps"].forEach((entry) => routeCatalogs.add(entry));
    if (view === "creations") ["techniqueLibrary", "affinities"].forEach((entry) => routeCatalogs.add(entry));
    if (view === "codex") ["affinityCategories", "affinities", "npcs", "worldLore", "worldEvents", "bestiary", "wantedBoard", "reputationFactions"].forEach((entry) => routeCatalogs.add(entry));
    routeCatalogs.forEach((collection) => requestRouteCatalog(collection, view));
  }

  state.diagnostics.listenerCount = state.unsubs.length + state.routeUnsubs.length;
}

function hasActiveTextEntry() {
  const active = document.activeElement;
  if (!(active instanceof HTMLElement) || !active.closest("#viewHost, #modalContent")) return false;
  if (active.isContentEditable || active.matches("textarea")) return true;
  if (!active.matches("input")) return false;
  return !["button", "checkbox", "color", "file", "hidden", "image", "radio", "range", "reset", "submit"].includes(active.type);
}

function captureRenderContext(options = {}) {
  const active = document.activeElement;
  const form = active?.closest?.("form[data-form]");
  const fields = form ? [...form.elements] : [];
  return {
    preserveFocus: options.preserveFocus !== false,
    preserveScroll: options.preserveScroll !== false,
    scrollX: window.scrollX,
    scrollY: window.scrollY,
    formType: form?.dataset.form || "",
    formScope: form?.dataset.draftKey || "",
    fieldName: active?.name || "",
    fieldId: active?.id || "",
    fieldAction: active?.dataset?.action || "",
    focusKey: active?.dataset?.focusKey || "",
    fieldIndex: form && active ? fields.indexOf(active) : -1,
    selectionStart: typeof active?.selectionStart === "number" ? active.selectionStart : null,
    selectionEnd: typeof active?.selectionEnd === "number" ? active.selectionEnd : null,
  };
}

function restoreRenderContext(context) {
  if (!context) return;
  if (context.preserveScroll) window.scrollTo({ left: context.scrollX, top: context.scrollY, behavior: "auto" });
  if (!context.preserveFocus) return;
  const formSelector = context.formType
    ? `form[data-form="${CSS.escape(context.formType)}"]${context.formScope ? `[data-draft-key="${CSS.escape(context.formScope)}"]` : ""}`
    : "";
  const root = formSelector ? document.querySelector(formSelector) : document;
  const selectors = [
    context.fieldId ? `#${CSS.escape(context.fieldId)}` : "",
    context.focusKey ? `[data-focus-key="${CSS.escape(context.focusKey)}"]` : "",
    context.fieldName ? `[name="${CSS.escape(context.fieldName)}"]` : "",
    context.fieldAction ? `[data-action="${CSS.escape(context.fieldAction)}"]` : "",
  ].filter(Boolean);
  let field = selectors.map((selector) => root?.querySelector?.(selector) || document.querySelector(selector)).find(Boolean);
  if (!field && context.fieldIndex >= 0 && root?.elements) field = root.elements[context.fieldIndex];
  if (!field || field.disabled || !field.isConnected) return;
  field.focus({ preventScroll: true });
  if (context.selectionStart !== null && field.setSelectionRange) {
    const maximum = typeof field.value === "string" ? field.value.length : context.selectionEnd ?? context.selectionStart;
    field.setSelectionRange(Math.min(context.selectionStart, maximum), Math.min(context.selectionEnd ?? context.selectionStart, maximum));
  }
}

function updateLiveShell() {
  if (!state.user || $("#appShell")?.hidden) return;
  const character = currentCharacter();
  const money = $("#moneyPill strong");
  if (money) money.textContent = Number(character.gold || 0);
  const quickStatus = $("#quickStatus");
  if (quickStatus) STABILITY.replaceHtmlIfChanged(quickStatus, renderQuickStatus(character));
  const notifications = notificationCount();
  const notifyCount = $("#notifyCount");
  if (notifyCount) {
    notifyCount.hidden = notifications < 1;
    notifyCount.textContent = notifications;
  }
  const notice = $("#globalNotice");
  if (notice) {
    notice.classList.toggle("show", Boolean(state.settings.globalNotice));
    notice.textContent = state.settings.globalNotice || "";
  }
}

function normalizeRenderRequest(views, options = {}) {
  if (views && !Array.isArray(views) && typeof views === "object") {
    options = views;
    views = options.views || null;
  }
  return {
    critical: Boolean(options.critical),
    preserveFocus: options.preserveFocus !== false,
    preserveScroll: options.preserveScroll !== false,
    route: options.route || "",
    reason: options.reason || "state-update",
    views: Array.isArray(views) ? views : null,
  };
}

function renderRequestMatches(request) {
  if (request.route && request.route !== state.view) return false;
  if (Array.isArray(request.views) && !request.views.includes(state.view)) return false;
  return true;
}

function scheduleRender(views = null, options = {}) {
  const request = normalizeRenderRequest(views, options);
  if (!renderRequestMatches(request)) return;

  const decision = STABILITY.shouldDeferRender({
    critical: request.critical,
    activeText: hasActiveTextEntry() || state.textComposing || state.searchComposing,
    dirtyForm: hasDirtyForm(),
    liveSession: Boolean(state.activeTowerSession || state.activeAimSession || state.activeSealSession || state.activeCartographySession || state.activeAlchemySession),
  });

  if (decision.defer) {
    state.pendingRenderRequest = STABILITY.mergeRenderRequests(state.pendingRenderRequest, request);
    state.pendingInputRender = true;
    if (decision.reason === "live-session") state.pendingLiveRender = true;
    updateLiveShell();
    return;
  }

  state.pendingRenderRequest = STABILITY.mergeRenderRequests(state.pendingRenderRequest, request);
  if (request.critical && state.renderFrame) {
    window.cancelAnimationFrame(state.renderFrame);
    state.renderFrame = 0;
  }
  if (state.renderFrame) return;

  state.renderFrame = window.requestAnimationFrame(() => {
    state.renderFrame = 0;
    const pending = state.pendingRenderRequest || request;
    state.pendingRenderRequest = null;
    if (!renderRequestMatches(pending)) return;

    const recheck = STABILITY.shouldDeferRender({
      critical: pending.critical,
      activeText: hasActiveTextEntry() || state.textComposing || state.searchComposing,
      dirtyForm: hasDirtyForm(),
      liveSession: Boolean(state.activeTowerSession || state.activeAimSession || state.activeSealSession || state.activeCartographySession || state.activeAlchemySession),
    });
    if (recheck.defer) {
      state.pendingRenderRequest = STABILITY.mergeRenderRequests(state.pendingRenderRequest, pending);
      state.pendingInputRender = true;
      updateLiveShell();
      return;
    }

    if (pending.critical && (hasActiveTextEntry() || hasDirtyForm())) {
      persistDirtyForms();
      saveUpdateDrafts();
      state.updateDraftRestored = false;
    }
    state.pendingInputRender = false;
    state.renderContext = captureRenderContext(pending);
    state.renderReason = pending.reason || "state-update";
    render();
  });
}

function flushDeferredRender(options = {}) {
  if (!state.pendingRenderRequest) return false;
  const pending = state.pendingRenderRequest;
  state.pendingRenderRequest = null;
  state.pendingInputRender = false;
  scheduleRender({
    ...pending,
    critical: Boolean(options.force || pending.critical),
    reason: options.reason || pending.reason || "deferred-flush",
  });
  return true;
}

function profileRenderKey(profile = {}) {
  return JSON.stringify({
    displayName: profile.displayName || "",
    role: profile.role || "player",
    accountStatus: profile.accountStatus || profile.status || "active",
    suspendedUntil: timeValue(profile.suspendedUntil || profile.bannedUntil),
    restrictionReason: profile.restrictionReason || profile.moderationReason || "",
    restrictedAt: timeValue(profile.restrictedAt),
    restrictedBy: profile.restrictedBy || "",
    acceptedTermsVersion: profile.acceptedTermsVersion || "",
    panicOfflineAt: timeValue(profile.panicOfflineAt),
    deletionQueue: Boolean(state.accountDeletionQueue),
  });
}

function stopCharacterSubscription() {
  if (!state.characterUnsub) return;
  try { state.characterUnsub(); } catch { /* no-op */ }
  state.unsubs = state.unsubs.filter((unsub) => unsub !== state.characterUnsub);
  state.characterUnsub = null;
  state.diagnostics.listenerCount = state.unsubs.length + state.routeUnsubs.length + (state.privateUnsub ? 1 : 0);
}

function startCharacterSubscription() {
  if (state.demo || !state.db || !state.user || state.characterUnsub || accountIsRestricted(state.profile)) return;
  state.characterUnsub = subscribeDoc("characters", state.user.uid, async (character) => {
    if (!character) {
      state.character = null;
      if (state.accountDeletionQueue || accountIsRestricted(state.profile)) {
        scheduleRender({ critical: true, preserveFocus: true, preserveScroll: true, reason: "character-removed-restricted" });
        return;
      }
      await state.db.collection("characters").doc(state.user.uid).set(defaultCharacter(state.user.uid, state.profile?.displayName), { merge: true });
      return;
    }
    state.character = character;
    window.dispatchEvent(new CustomEvent("millennium:character", { detail: { uid: state.user.uid, character } }));
    if (state.role !== "admin") state.characters = [character];
    if (state.role !== "admin" && character.characterName) {
      const projectionHash = stableSerialize(rankingProjection({ ...character, ownerId: character.ownerId || state.user.uid }));
      if (!state.rankingProjectionHash) state.rankingProjectionHash = projectionHash;
      else if (state.rankingProjectionHash !== projectionHash) syncRankingProjection(character).catch((error) => console.warn("Ranking projection deferred:", error));
    }
    scheduleRender({ preserveFocus: true, preserveScroll: true });
  });
}

function subscribeCore() {
  subscribeDoc("accountDeletionQueue", state.user.uid, (queue) => {
    state.accountDeletionQueue = queue?.status === "awaiting-auth-delete" ? queue : null;
    if (state.accountDeletionQueue) {
      state.profile = {
        ...(state.profile || {}),
        id: state.user.uid,
        accountStatus: "deletion_pending",
        restrictionReason: "Os dados desta conta foram removidos. A exclusão da credencial está pendente no Firebase Authentication.",
      };
      clearRouteSubscriptions();
      stopCharacterSubscription();
      stopPresenceTracking();
    }
    scheduleRender({ critical: true, preserveFocus: true, preserveScroll: true, reason: "account-deletion-queue" });
  });

  subscribeDoc("users", state.user.uid, (profile) => {
    const previousRole = state.role;
    const previousBlocked = accountIsRestricted(state.profile);
    const previousKey = profileRenderKey(state.profile || {});
    if (profile) {
      state.profile = { accountStatus: "active", ...profile };
    } else if (state.accountDeletionQueue) {
      state.profile = {
        ...(state.profile || {}),
        id: state.user.uid,
        accountStatus: "deletion_pending",
        restrictionReason: "Os dados desta conta foram removidos. A exclusão da credencial está pendente no Firebase Authentication.",
      };
    }
    state.role = state.profile?.role === "admin" ? "admin" : "player";
    window.dispatchEvent(new CustomEvent("millennium:profile", { detail: { uid: state.user.uid, profile: state.profile, role: state.role } }));
    const blocked = accountIsRestricted(state.profile);
    if (!NAVS[state.role].some((item) => item.id === state.view)) state.view = NAVS[state.role][0].id;
    if (previousRole !== state.role) {
      clearRouteSubscriptions();
      if (!blocked) activateRouteSubscriptions(state.view);
    }
    if (blocked) {
      clearRouteSubscriptions();
      stopCharacterSubscription();
      stopPresenceTracking();
      setPresence(false, { force: true }).catch(() => {});
    } else if (previousBlocked && !blocked) {
      startCharacterSubscription();
      activateRouteSubscriptions(state.view);
      startPresence();
    }
    if (previousKey !== profileRenderKey(state.profile || {})) {
      scheduleRender({
        critical: previousRole !== state.role || blocked || previousBlocked !== blocked,
        preserveFocus: true,
        preserveScroll: true,
        reason: "profile-access-change",
      });
    }
  });

  subscribeDoc("settings", "system", (settings) => {
    const previousPanic = state.lastPanicVersion;
    const previousTheme = state.settings.seasonTheme;
    const previousMaintenance = Boolean(state.settings.maintenanceMode);
    state.settings = { ...DEFAULT_CONTENT.settings, ...(settings || {}) };
    if (state.musicOn && previousTheme && previousTheme !== state.settings.seasonTheme) {
      stopAmbientMusic();
      window.setTimeout(() => startAmbientMusic().catch(() => {}), 320);
    }
    if (!state.lastPanicVersion) state.lastPanicVersion = state.settings.panicVersion || "";
    if (previousPanic && state.settings.panicVersion && state.settings.panicVersion !== previousPanic && state.role !== "admin") {
      handleEmergencyUpdate(state.settings);
      return;
    }
    state.lastPanicVersion = state.settings.panicVersion || "";
    applyThemeClasses();
    maybeResetWeeklyMissions();
    scheduleRender({
      critical: previousMaintenance !== Boolean(state.settings.maintenanceMode),
      preserveFocus: true,
      preserveScroll: true,
    });
  });

  startCharacterSubscription();

  $("#authScreen").hidden = true;
  $("#appShell").hidden = false;
  const skipLink = $("#skipLink");
  if (skipLink) {
    skipLink.href = "#mainContent";
    skipLink.textContent = "Pular para o conteúdo principal";
  }
  if (accountIsRestricted(state.profile)) {
    clearRouteSubscriptions();
    stopCharacterSubscription();
    stopPresenceTracking();
  } else {
    startCharacterSubscription();
    activateRouteSubscriptions(state.view);
    startPresence();
    announceSessionEntry();
  }
  render();
}

function enterDemo(role) {
  state.demo = true;
  state.user = { uid: `demo-${role}`, email: `${role}@demo.local` };
  state.profile = {
    id: state.user.uid,
    email: state.user.email,
    displayName: role === "admin" ? "Oráculo Demo" : "Player Demo",
    role,
    acceptedTermsVersion: state.settings.rulesVersion || "1.0",
    online: true,
    lastSeen: new Date().toISOString(),
  };
  state.role = role;
  state.view = NAVS[role][0].id;
  state.characterStep = 0;
  state.characterDraft = null;
  state.characterLore = null;
  state.characterIntroSeen = false;
  state.settings = { ...DEFAULT_CONTENT.settings };
  state.content = defaultContentState();
  const playerChar = seedDemoMonsters(defaultCharacter("demo-player", "Player Demo"));
  const existingChar = {
    ...defaultCharacter("demo-existing", "Viajante Demo"),
    characterName: "Ariadne Vesper",
    creationLocked: true,
    technicalCreationComplete: true,
    creationStatus: "registered",
    kingdomId: state.content.kingdoms?.[0]?.id || "",
    regionId: state.content.regions?.[0]?.id || "",
    cultureId: state.content.cultures?.[0]?.id || "",
    professionId: state.content.professions?.[0]?.id || "",
    base: { for: 3, vel: 4, hab: 5, res: 4, pod: 4 },
    attributeRulesVersion: 0,
    attributeRedistributionStatus: "",
    attributeRedistributionUsed: false,
    gold: 180,
    titles: [{ id: "arquivo-vivo", name: "Arquivo Vivo", rarity: "Raro" }],
    pets: [{ id: "luma", name: "Luma", imageUrl: "" }],
  };
  state.users = [
    { id: "demo-player", displayName: "Player Demo", email: "player@demo.local", role: "player" },
    { id: "demo-existing", displayName: "Viajante Demo", email: "existing@demo.local", role: "player" },
    { id: "demo-admin", displayName: "Oráculo Demo", email: "admin@demo.local", role: "admin" },
  ];
  state.characters = [playerChar, existingChar, defaultCharacter("demo-admin", "Oráculo Demo")];
  state.character = role === "player" ? playerChar : defaultCharacter("demo-admin", "Oráculo Demo");
  state.weeklyMissions = DEFAULT_CONTENT.missionPool.slice(0, 3).map((mission) => ({ ...mission, createdAt: new Date().toISOString() }));
  state.globalMessages = [{ id: "welcome", senderName: "Sistema", text: "Chat global iniciado.", type: "system", createdAt: new Date().toISOString() }];
  $("#authScreen").hidden = true;
  $("#appShell").hidden = false;
  startPresence();
  render();
}

function adminAuditReason(collection, data = {}, customReason = "") {
  if (customReason) return String(customReason).slice(0, 500);
  const fields = Object.keys(data).filter((key) => !["updatedAt", "lastAuditId"].includes(key)).slice(0, 8).join(", ");
  return `Alteração administrativa em ${collection}${fields ? `: ${fields}` : ""}.`;
}

async function writeDoc(collection, id, data, options = {}) {
  if (!state.demo) assertFirestoreAvailable();
  if (state.demo) {
    writeDemo(collection, id, data);
    state.diagnostics.writes += 1;
    render();
    return;
  }
  const auditedCollections = new Set(["characters", "users", "reports", "progressRequests"]);
  const needsAudit = state.role === "admin" && auditedCollections.has(collection) && options.audit !== false;
  if (needsAudit) {
    const auditId = `audit-${cryptoRandom()}`;
    const targetRef = state.db.collection(collection).doc(id);
    const auditRef = state.db.collection("auditLogs").doc(auditId);
    const batch = state.db.batch();
    batch.set(auditRef, {
      adminId: state.user.uid,
      targetId: id,
      field: Object.keys(data).filter((key) => !["updatedAt", "lastAuditId"].includes(key)).join(",").slice(0, 300) || "registro",
      previousValue: options.previousValue ?? null,
      nextValue: options.nextValue ?? data,
      reason: adminAuditReason(collection, data, options.reason),
      createdAt: nowValue(),
    });
    batch.set(targetRef, { ...data, lastAuditId: auditId, updatedAt: nowValue() }, { merge: true });
    await batch.commit();
    state.diagnostics.writes += 2;
    state.routeOnceCache.clear();
    return;
  }
  await state.db.collection(collection).doc(id).set({ ...data, updatedAt: nowValue() }, { merge: true });
  state.diagnostics.writes += 1;
  state.routeOnceCache.clear();
}

async function addDoc(collection, data) {
  if (!state.demo) assertFirestoreAvailable();
  if (state.demo) {
    const id = cryptoRandom();
    writeDemo(collection, id, { id, ...data });
    state.diagnostics.writes += 1;
    render();
    return id;
  }
  const ref = await state.db.collection(collection).add({ ...data, createdAt: nowValue() });
  state.diagnostics.writes += 1;
  state.routeOnceCache.clear();
  return ref.id;
}

async function deleteDoc(collection, id) {
  if (!state.demo) assertFirestoreAvailable();
  if (!id) return;
  if (state.demo) {
    if (collection === "globalMessages") state.globalMessages = state.globalMessages.filter((item) => item.id !== id);
    if (collection === "directMessages") state.directMessages = state.directMessages.filter((item) => item.id !== id);
    if (collection === "guildMessages") state.guildMessages = state.guildMessages.filter((item) => item.id !== id);
    if (state.content?.[collection]) state.content[collection] = state.content[collection].filter((item) => item.id !== id);
    syncPrivateMessages();
    render();
    return;
  }
  await state.db.collection(collection).doc(id).delete();
  state.diagnostics.writes += 1;
  state.routeOnceCache.clear();
}

function writeDemo(collection, id, data) {
  if (collection === "settings") state.settings = { ...state.settings, ...data };
  if (collection === "characters") {
    const next = { ...getCharacterFor(id), ...data, id, ownerId: id };
    state.characters = state.characters.filter((item) => item.ownerId !== id && item.id !== id).concat(next);
    if (id === state.user.uid) state.character = next;
  }
  if (collection === "users") {
    const current = state.users.find((item) => item.id === id) || {};
    state.users = state.users.filter((item) => item.id !== id).concat({ ...current, ...data, id });
    if (id === state.user.uid) state.profile = { ...state.profile, ...data };
  }
  if (Object.keys(state.content).includes(collection)) {
    state.content[collection] = state.content[collection].filter((item) => item.id !== id).concat({ ...data, id });
  }
  if (collection === "weeklyMissions") state.weeklyMissions = state.weeklyMissions.filter((item) => item.id !== id).concat({ ...data, id });
  if (collection === "campaignDiary") state.diaryEntries = state.diaryEntries.filter((item) => item.id !== id).concat({ ...data, id });
  if (collection === "globalMessages") state.globalMessages.push({ ...data, id });
  if (collection === "directMessages") {
    state.directMessages = state.directMessages.filter((item) => item.id !== id).concat({ ...data, id });
    syncPrivateMessages();
  }
  if (collection === "socialRequests") {
    const current = state.socialRequests.find((item) => item.id === id) || {};
    state.socialRequests = state.socialRequests.filter((item) => item.id !== id).concat({ ...current, ...data, id });
  }
  if (collection === "guilds") {
    const current = state.guilds.find((item) => item.id === id) || {};
    state.guilds = state.guilds.filter((item) => item.id !== id).concat({ ...current, ...data, id });
  }
  if (collection === "guildMessages") state.guildMessages.push({ ...data, id });
  if (collection === "guildMissions") state.guildMissions = state.guildMissions.filter((item) => item.id !== id).concat({ ...data, id });
  if (collection === "reports") {
    const current = state.reports.find((item) => item.id === id) || {};
    state.reports = state.reports.filter((item) => item.id !== id);
    state.reports.unshift({ ...current, ...data, id });
  }
  if (collection === "progressRequests") {
    const current = state.progressRequests.find((item) => item.id === id) || {};
    state.progressRequests = state.progressRequests.filter((item) => item.id !== id).concat({ ...current, ...data, id });
  }
  if (collection === "conversations") {
    const current = state.conversations.find((item) => item.id === id) || {};
    state.conversations = state.conversations.filter((item) => item.id !== id).concat({ ...current, ...data, id });
  }
}

async function pruneMessages(collection, messages, predicate = () => true) {
  const scoped = [...messages]
    .filter(predicate)
    .filter((message) => message.id && timeValue(message.createdAt) > 0)
    .sort((a, b) => timeValue(a.createdAt) - timeValue(b.createdAt));
  const overflow = scoped.slice(0, Math.max(0, scoped.length - CHAT_LIMIT));
  await Promise.all(overflow.map((message) => deleteDoc(collection, message.id).catch(() => {})));
}

async function updateCharacter(uid, patch, options = {}) {
  await writeDoc("characters", uid, { ...patch, ownerId: uid }, options);
  const merged = { ...getCharacterFor(uid), ...patch, ownerId: uid };
  if (uid === state.user?.uid) state.character = merged;
  await syncRankingProjection(merged).catch((error) => console.warn("Ranking projection deferred:", error));
}

async function addGlobalMessage(data) {
  const payload = {
    senderId: data.senderId || state.user.uid,
    senderName: data.senderName || state.profile?.displayName || "Player",
    text: data.text,
    type: data.type || "global",
    targetId: data.targetId || "",
    targetName: data.targetName || "",
    rarity: data.rarity || "",
    createdAt: state.demo ? new Date().toISOString() : nowValue(),
  };
  const id = await addDoc("globalMessages", payload);
  const pruneSource = state.globalMessages.some((message) => message.id === id)
    ? state.globalMessages
    : [...state.globalMessages, { ...payload, id, createdAt: new Date().toISOString() }];
  await pruneMessages("globalMessages", pruneSource);
}

async function announceSessionEntry() {
  if (state.sessionAnnounced || !state.user || state.demo) return;
  state.sessionAnnounced = true;
  let localLastAnnouncedAt = 0;
  try { localLastAnnouncedAt = Number(localStorage.getItem(`millennium:join-announced:${state.user.uid}`) || 0); } catch { /* no-op */ }
  const lastAnnouncedAt = Math.max(timeValue(state.profile?.lastAnnouncedAt), localLastAnnouncedAt);
  if (lastAnnouncedAt && Date.now() - lastAnnouncedAt < JOIN_ANNOUNCE_COOLDOWN_MS) return;
  const character = currentCharacter();
  const title = activeTitle(character);
  const name = displayNameWithTitle(state.user.uid, state.profile?.displayName || state.user.email);
  await addGlobalMessage({
    senderId: state.user.uid,
    senderName: state.profile?.displayName || "Player",
    type: "global",
    text: state.role === "admin"
      ? `ALERTA: ${ORACLE_LABEL} ${name} entrou na interface.`
      : `${name}${title ? ` (${title.name})` : ""} entrou no servidor.`,
  }).catch(() => {});
  try { localStorage.setItem(`millennium:join-announced:${state.user.uid}`, String(Date.now())); } catch { /* no-op */ }
}

async function announceRareReward(uid, rewardName, rarity, type = "prêmio") {
  if (!isRareReward(rarity)) return;
  const name = getUserName(uid);
  await addGlobalMessage({
    senderId: state.user.uid,
    senderName: state.profile?.displayName || "Player",
    type: "global",
    rarity,
    text: `${name} conquistou ${type} raro: ${rewardName} (${rarity}).`,
  });
}

function secondaryModuleStats(view, character = currentCharacter()) {
  const totalFragments = Object.values(character.gachaFragments || {}).reduce((sum, value) => sum + Number(value || 0), 0);
  const guild = currentGuild();
  const passLevel = seasonPassLevel(character);
  const maps = state.content.towerMaps || [];
  const common = {
    gacha: [["Millennium Coins", Number(character.millenniumCoins || 0).toLocaleString("pt-BR")], ["Pity raro", `${Number(character.monsterGachaPity?.rareMonster || 0)}/${Math.max(1, Number(character.monsterGachaPity?.max || monsterApi()?.monsterPityMax || 30))}`], ["Monstros", `${monsterInstancesForCharacter(character).length}/25`]],
    market: [["Peças de Ouro", Number(character.gold || 0).toLocaleString("pt-BR")], ["Millennium Coins", Number(character.millenniumCoins || 0).toLocaleString("pt-BR")], ["Fragmentos", totalFragments.toLocaleString("pt-BR")]],
    inventory: [["Itens", `${(character.inventory || []).length}`], ["Equipados", `${equippedItems(character).length}`], ["Pets", `${(character.gachaVault || []).filter((item) => item.kind === "pet").length}`]],
    guild: [["Aliança", guild?.name || "Sem guilda"], ["Membros", `${guild?.memberIds?.length || 0}/${GUILD_MEMBER_LIMIT}`], ["Mensagens", `${state.guildMessages.length}`]],
    missions: [["Ativas", `${(character.activeMissions || []).length}`], ["Semana", `${state.weeklyMissions.length}`], ["Em análise", `${pendingProgressRequests().length}`]],
    "admin-missions": [["Publicadas", `${state.weeklyMissions.length}`], ["Solicitações", `${state.progressRequests.length}`], ["Temporada", state.settings.gameStarted ? "Ativa" : "Pré-lançamento"]],
    pass: [["Nível do Passe", `${passLevel}`], ["XP sazonal", Number(character.seasonPassXp || 0).toLocaleString("pt-BR")], ["Trilha", character.premiumPassUnlocked ? "Premium" : "Gratuita"]],
    chat: [["Online", `${state.users.filter(isUserOnline).length}`], ["Global", `${state.globalMessages.length}`], ["Diretas", `${state.privateMessages.length}`]],
    "admin-chat": [["Online", `${state.users.filter(isUserOnline).length}`], ["Mensagens", `${state.globalMessages.length}`], ["Reports", `${state.reports.length}`]],
    minigames: [["Energia", `${currentGachaEnergy(character)}/${GACHA_ENERGY_MAX}`], ["Atividades", `${(character.activeActivities || []).length}`], ["Mapas", `${maps.length}`]],
    codex: [["Aba", VIEW_TITLES[state.view] ? String(state.codexTab || "world") : "world"], ["Mapas", `${maps.length}`], ["Eventos", `${(state.content.worldEvents || []).length}`]],
    "admin-settings": [["Temporada", `${Number(state.settings.seasonNumber || 1)}`], ["Tema", state.settings.seasonTheme || "padrão"], ["Estado", state.settings.seasonThemeState || "ativo"]],
  };
  return common[view] || [];
}

function renderSecondaryModuleFrame(view, content) {
  const module = SECONDARY_MODULES[view];
  if (!module) return content;
  const stats = secondaryModuleStats(view);
  const links = (module.links || []).filter(([nav]) => NAVS[state.role].some((item) => item.id === nav));
  const mapContext = view === "codex" ? `<span class="secondary-module-context"><i aria-hidden="true">⌖</i>${state.codexTab === "world" ? "Mapa mundial em foco" : `Arquivo: ${esc(state.codexTab || "world")}`}</span>` : "";
  return `
    <section class="secondary-module secondary-module--${esc(module.tone || "interface")}" data-secondary-module="${esc(view)}">
      <header class="secondary-module-hero">
        <div class="secondary-module-symbol" aria-hidden="true">${module.icon}</div>
        <div class="secondary-module-copy">
          <p class="eyebrow">${esc(module.eyebrow)}</p>
          <h2>${esc(module.title)}</h2>
          <p>${esc(module.description)}</p>
          <div class="secondary-module-context-row">${mapContext}<span class="secondary-module-context"><i aria-hidden="true">✦</i>Interface 3.6.4</span></div>
        </div>
        <div class="secondary-module-ledger" aria-label="Resumo do módulo">
          ${stats.map(([label, value]) => `<div><small>${esc(label)}</small><strong>${esc(value)}</strong></div>`).join("")}
        </div>
      </header>
      ${links.length ? `<nav class="secondary-module-links" aria-label="Atalhos relacionados">${links.map(([nav, label]) => `<button class="secondary-module-link" type="button" data-nav="${esc(nav)}">${esc(label)}</button>`).join("")}</nav>` : ""}
      <div class="secondary-module-content">${content}</div>
    </section>
  `;
}

function finishRender(startedAt) {
  $("#viewHost")?.setAttribute("aria-busy", "false");
  state.diagnostics.renders += 1;
  state.diagnostics.lastRenderMs = Math.round((performance.now() - startedAt) * 100) / 100;
  state.diagnostics.lastRoute = state.view;
  state.diagnostics.lastReason = state.renderReason || "direct-render";
  restoreRenderContext(state.renderContext);
  const focused = document.activeElement;
  state.diagnostics.lastFocusedElement = focused?.id || focused?.name || focused?.dataset?.action || focused?.tagName || "";
  state.diagnostics.renderHistory = STABILITY.boundedHistory(state.diagnostics.renderHistory, {
    at: new Date().toISOString(),
    route: state.view,
    reason: state.diagnostics.lastReason,
    durationMs: state.diagnostics.lastRenderMs,
    focused: state.diagnostics.lastFocusedElement,
    listeners: state.diagnostics.listenerCount,
  });
  state.renderContext = null;
  state.renderReason = "direct-render";
}

function render() {
  const startedAt = performance.now();
  $("#viewHost")?.setAttribute("aria-busy", "true");
  state.pendingInputRender = false;
  if (!state.user) {
    showAuth();
    finishRender(startedAt);
    return;
  }

  applyThemeClasses();
  updateBuildBadge();

  if (!state.updateDraftRouteApplied) {
    const payload = pendingUpdateDraft();
    const allowedViews = NAVS[state.role].map((item) => item.id);
    if (payload?.view && allowedViews.includes(payload.view)) state.view = payload.view;
    state.updateDraftRouteApplied = true;
  }

  $("#authScreen").hidden = true;
  $("#appShell").hidden = false;
  const skipLink = $("#skipLink");
  if (skipLink) {
    skipLink.href = "#mainContent";
    skipLink.textContent = "Pular para o conteúdo principal";
  }
  updateMusicButton();
  const nav = NAVS[state.role];
  if (!nav.some((item) => item.id === state.view)) state.view = nav[0].id;
  const accessRestricted = accountIsRestricted(state.profile);
  document.body.classList.toggle("account-restricted", accessRestricted);
  if (accessRestricted) clearRouteSubscriptions();
  else activateRouteSubscriptions(state.view);
  $("#roleLabel").textContent = state.role === "admin" ? ORACLE_LABEL : "Player";
  $("#seasonLabel").textContent = state.settings.seasonName || `Temporada ${state.settings.seasonNumber || 1}`;
  $("#contextLabel").textContent = state.role === "admin" ? "Oráculo da interface" : "Suporte do personagem";
  $("#viewTitle").textContent = VIEW_TITLES[state.view] || "Painel";
  STABILITY.replaceHtmlIfChanged($("#navList"), renderGroupedNavigation(nav));

  const character = currentCharacter();
  $("#moneyPill").hidden = state.role === "admin";
  $("#moneyPill strong").textContent = Number(character.gold || 0);
  updateLiveShell();
  STABILITY.replaceHtmlIfChanged($("#mobileBottomNav"), renderMobileBottomNav(nav));

  if (accessRestricted) {
    STABILITY.replaceHtmlIfChanged($("#viewHost"), renderAccountRestrictionGate());
    startRestrictionCountdown();
    finishRender(startedAt);
    return;
  }
  clearRestrictionTimer();
  if (state.role !== "admin" && state.settings.maintenanceMode) {
    STABILITY.replaceHtmlIfChanged($("#viewHost"), renderMaintenanceGate());
    finishRender(startedAt);
    return;
  }
  if (state.role !== "admin" && !hasAcceptedTerms()) {
    STABILITY.replaceHtmlIfChanged($("#viewHost"), renderTermsGate());
    finishRender(startedAt);
    return;
  }

  const chatScroll = captureChatScroll();
  const renderer = VIEW_RENDERERS[state.view] || renderPlayerHome;
  const rawViewContent = renderer();
  const viewContent = renderSecondaryModuleFrame(state.view, rawViewContent);
  const oracleFramed = state.role === "admin" && (state.view.startsWith("admin-") || state.view === "ranking")
    ? renderOracleFrame(state.view, viewContent)
    : viewContent;
  STABILITY.replaceHtmlIfChanged($("#viewHost"), oracleFramed);
  normalizeRenderedImages($("#viewHost"));
  normalizeRenderedAccessibility($("#viewHost"));
  announceCurrentRoute();
  startGachaRotationTicker();
  restoreChatScroll(chatScroll);
  restoreUpdateDrafts();
  restoreLocalFormDrafts();
  const awakeningScheduled = maybeOpenAwakeningCeremony();
  if (!awakeningScheduled && !state.awakeningCeremonyOpen) maybeOpenOnboarding();
  finishRender(startedAt);
}

function applyThemeClasses(settings = state.settings) {
  const now = Date.now();
  const startsAt = Date.parse(settings.seasonThemeStartsAt || "") || 0;
  const endsAt = Date.parse(settings.seasonThemeEndsAt || "") || 0;
  const scheduledNow = settings.seasonThemeState === "scheduled" && (!startsAt || startsAt <= now) && (!endsAt || endsAt > now);
  const canApplyToPlayer = settings.seasonThemeState === "active" || scheduledNow;
  const useStandard = state.role === "player" && state.profile?.themePreference === "standard";
  const effectiveSettings = useStandard || (state.role === "player" && !canApplyToPlayer) ? { ...settings, seasonTheme: "spirit-veil", seasonThemePrimary: "", seasonThemeSecondary: "", seasonThemeAccent: "", seasonThemeBackground: "" } : settings;
  const theme = ECHOES.resolvedTheme(effectiveSettings);
  document.body.className = [
    settings.theme && settings.theme !== "default" ? `theme-${settings.theme}` : "",
    settings.seasonTheme ? `season-theme-${settings.seasonTheme}` : "season-theme-eclipse",
    "echoes-theme",
    `season-${Number(settings.seasonNumber || 1)}`,
  ].filter(Boolean).join(" ");
  document.body.dataset.interfaceScope = state.role === "admin" ? "oracle" : "player";
  document.body.dataset.themeAnimation = state.profile?.interfaceAnimations || settings.seasonThemeAnimation || theme.animation || "normal";
  document.body.dataset.themeMenuEffect = settings.seasonThemeMenuEffect || theme.menuEffect || "mist";
  document.body.dataset.interfaceContrast = state.profile?.interfaceContrast || "normal";
  document.body.dataset.dataEconomy = state.profile?.dataEconomy ? "on" : "off";
  document.documentElement.style.setProperty("--season-primary", theme.palette.primary);
  document.documentElement.style.setProperty("--season-secondary", theme.palette.secondary);
  document.documentElement.style.setProperty("--season-accent", theme.palette.accent);
  document.documentElement.style.setProperty("--season-danger", theme.palette.danger);
  document.documentElement.style.setProperty("--season-success", theme.palette.success);
  document.documentElement.style.setProperty("--season-background", theme.background ? `url("${theme.background.replace(/["'()]/g, "")}")` : "none");
  const authHero = document.querySelector("#authHeroImage");
  const authHeroMobile = document.querySelector("#authHeroMobileSource");
  const safeLoginArt = String(theme.loginArt || "").replace(/["'()]/g, "");
  if (authHero) authHero.src = safeLoginArt || "assets/awakening/aurora-despertos-hero-16x9.webp";
  if (authHeroMobile) authHeroMobile.srcset = safeLoginArt || "assets/awakening/aurora-despertos-hero-mobile.webp";
}

function onboardingSteps() {
  const progress = currentJourney();
  return progress.steps.map((entry) => ({
    ...entry,
    name: entry.label,
    label: entry.done ? `${entry.label} · concluído` : entry.label,
  }));
}

function maybeOpenOnboarding() {
  const version = state.settings.onboardingVersion || state.settings.rulesVersion || "3.0";
  if (state.role === "admin" || state.onboardingShown || state.awakeningCeremonyOpen || state.profile?.tutorialSeenVersion === version || !hasAcceptedTerms()) return;
  state.onboardingShown = true;
  window.setTimeout(() => openOnboarding(0), 160);
}

function openOnboarding(index = 0) {
  const steps = onboardingSteps();
  if (!steps.length) return;
  const safeIndex = Math.max(0, Math.min(steps.length - 1, Number(index || 0)));
  state.onboardingStep = safeIndex;
  const step = steps[safeIndex];
  const journey = currentJourney();
  const progress = journey.percentage;
  $("#modalContent").innerHTML = `
    <section class="onboarding-ritual">
      <div class="onboarding-visual"><span>${String(safeIndex + 1).padStart(2, "0")}</span><div><small>Primeiro Despertar</small><strong>${esc(step.label)}</strong></div></div>
      <div class="onboarding-copy">
        <div class="onboarding-progress"><i style="width:${progress}%"></i></div>
        <p class="eyebrow">${journey.completed} de ${journey.total} etapas essenciais concluídas · visão ${safeIndex + 1}</p>
        <h2>${esc(step.name)}</h2>
        <p>${esc(step.description || "A Interface aguarda sua próxima escolha.")}</p>
        <div class="onboarding-rule"><span>${step.done ? "Etapa reconhecida" : "Próxima orientação"}</span><strong>${step.done ? "A Interface já encontrou este registro." : step.description}</strong></div>
        <div class="onboarding-actions">
          <button class="ghost-button" type="button" data-action="onboarding-prev" ${safeIndex === 0 ? "disabled" : ""}>Voltar</button>
          <button class="ghost-button" type="button" data-action="onboarding-visit" data-nav-target="${esc(step.nav)}">Ver esta área</button>
          ${safeIndex < steps.length - 1 ? `<button class="primary-button" type="button" data-action="onboarding-next">Próximo</button>` : `<button class="primary-button intense" type="button" data-action="onboarding-complete">Entrar em Millennium</button>`}
        </div>
      </div>
    </section>
  `;
  $("#modal").hidden = false;
}

async function completeOnboarding() {
  const version = state.settings.onboardingVersion || state.settings.rulesVersion || "3.0";
  await writeDoc("users", state.user.uid, { tutorialSeenVersion: version });
  state.profile = { ...state.profile, tutorialSeenVersion: version };
  closeModal();
  toast("Primeiro Despertar concluído. A Interface agora acompanha sua jornada.");
}

function captureChatScroll() {
  return [...document.querySelectorAll("[data-chat-scroll]")].map((element) => ({
    key: element.dataset.chatScroll,
    top: element.scrollTop,
    atBottom: element.scrollHeight - element.scrollTop - element.clientHeight < 48,
  }));
}

function restoreChatScroll(records = []) {
  window.requestAnimationFrame(() => records.forEach((record) => {
    const element = document.querySelector(`[data-chat-scroll="${record.key}"]`);
    if (!element) return;
    const forceBottom = state.forceChatBottom === record.key;
    element.scrollTop = forceBottom || record.atBottom ? element.scrollHeight : Math.min(record.top, element.scrollHeight);
    if (forceBottom) state.forceChatBottom = "";
  }));
}

function renderStat(label, value) {
  return `<div class="stat"><span>${esc(label)}</span><strong>${esc(value)}</strong></div>`;
}

function notificationCount() {
  const character = currentCharacter();
  return pendingIncomingRequests().length
    + (character.pendingGift ? 1 : 0)
    + pendingProgressRequests().length;
}

function hasAcceptedTerms() {
  return state.profile?.acceptedTermsVersion === (state.settings.rulesVersion || "1.0");
}

function renderQuickStatus(character) {
  if (state.role === "admin") {
    const online = state.users.filter((user) => user.role !== "admin" && isUserOnline(user)).length;
    return `
      <span>Online ${online}</span>
      <span>Validações ${state.progressRequests.filter((request) => request.status === "pendente").length}</span>
      <span>Reports ${state.reports.filter((report) => report.status !== "resolvido").length}</span>
    `;
  }
  return `
    <span>Nv ${Number(character.level || levelFromXp(character.xp || 0))}</span>
    <span>Ess ${Number(character.affinityAttempts ?? state.settings.defaultAffinityAttempts ?? 0)}</span>
    <span>MC ${Number(character.millenniumCoins || 0)}</span>
    <span>Energia ${currentGachaEnergy(character)}/${GACHA_ENERGY_MAX}</span>
    <span>Online ${state.users.filter((user) => user.role !== "admin" && isUserOnline(user)).length}</span>
  `;
}

function renderGroupedNavigation(nav, compact = false) {
  const groups = NAV_GROUPS[state.role] || NAV_GROUPS.player;
  const byId = new Map(nav.map((item) => [item.id, item]));
  return groups.map((group) => {
    const items = group.ids.map((id) => byId.get(id)).filter(Boolean);
    if (!items.length) return "";
    return `
      <section class="nav-group ${compact ? "compact" : ""}" aria-label="${esc(group.label)}">
        <span class="nav-group-label">${esc(group.label)}</span>
        <div class="nav-group-items">
          ${items.map((item) => `<button class="nav-item ${state.view === item.id ? "active" : ""}" type="button" data-nav="${item.id}" ${state.view === item.id ? 'aria-current="page"' : ""}><span class="nav-icon" aria-hidden="true">${item.icon}</span><span>${item.label}</span></button>`).join("")}
        </div>
      </section>
    `;
  }).join("");
}

function renderMobileBottomNav(nav) {
  const preferred = state.role === "admin"
    ? ["admin-home", "admin-users", "ranking", "admin-requests", "admin-settings"]
    : ["player-home", "profile", "roulette", "chat", "missions"];
  const quick = preferred.map((id) => nav.find((item) => item.id === id)).filter(Boolean);
  return [
    ...quick.map((item) => `<button class="${state.view === item.id ? "active" : ""}" type="button" data-nav="${item.id}" title="${esc(item.label)}" ${state.view === item.id ? 'aria-current="page"' : ""}><span aria-hidden="true">${item.icon}</span><small>${item.label}</small></button>`),
    `<button class="${quick.some((item) => item.id === state.view) ? "" : "active"}" type="button" data-action="open-more-nav" title="Abrir todas as áreas" ${quick.some((item) => item.id === state.view) ? "" : 'aria-current="page"'}><span aria-hidden="true">☰</span><small>Mais</small></button>`,
  ].join("");
}

function openMoreNav() {
  const nav = NAVS[state.role] || NAVS.player;
  $("#modalContent").innerHTML = `
    <div class="app-drawer-head">
      <div><p class="eyebrow">Navegação rápida</p><h2>Seu grimório</h2></div>
      <span class="tag">${state.role === "admin" ? ORACLE_LABEL : "Escolhido"}</span>
    </div>
    <div class="more-nav-grid app-drawer-grid">${renderGroupedNavigation(nav, true)}</div>
    <button class="drawer-logout" type="button" data-action="logout"><span>↪</span> Sair da interface</button>
  `;
  const modal = $("#modal");
  modal.hidden = false;
  modal.scrollTop = 0;
  const modalCard = modal.querySelector(".modal-card");
  if (modalCard) modalCard.scrollTop = 0;
}

function renderMaintenanceGate() {
  return `
    <div class="grid">
      <article class="panel span-12 center-panel">
        <p class="eyebrow">Modo manutenção</p>
        <h2>O Oráculo está ajustando a interface</h2>
        <p>Players ficam temporariamente bloqueados para evitar perda de dados durante correções e atualizações.</p>
      </article>
    </div>
  `;
}

function renderAccountRestrictionGate() {
  const status = normalizedAccountStatus();
  const profile = state.profile || {};
  const suspended = status === "suspended";
  const banned = status === "banned";
  const deletionPending = status === "deletion_pending" || Boolean(state.accountDeletionQueue);
  const until = dateFromValue(profile.suspendedUntil || profile.bannedUntil);
  const reason = profile.restrictionReason || profile.moderationReason || state.accountDeletionQueue?.reason || "Entre em contato com o Oráculo para obter mais informações.";
  const heading = deletionPending ? "Exclusão pendente" : banned ? "Conta banida" : "Conta suspensa";
  const title = deletionPending
    ? "Os dados desta conta foram removidos"
    : banned
      ? "A Interface recusou este registro"
      : "Seu acesso foi pausado pelo Oráculo";
  return `
    <section class="restriction-shell" aria-labelledby="restriction-title">
      <article class="restriction-card">
        <p class="eyebrow">${esc(heading)}</p>
        <h1 id="restriction-title">${esc(title)}</h1>
        <p>${esc(reason)}</p>
        ${suspended && until ? `<p>Suspensão válida até <strong>${esc(until.toLocaleString("pt-BR"))}</strong>.</p><span class="restriction-countdown" data-restriction-countdown>${esc(ACCOUNT_MGMT.restrictionCountdown(profile).label)}</span>` : ""}
        ${banned ? `<p>Entre em contato com o Oráculo caso deseje solicitar revisão.</p>` : ""}
        ${deletionPending ? `<div class="deletion-checklist"><p>A credencial ainda precisa ser removida no Firebase Authentication pelo administrador.</p><code>UID: ${esc(state.user?.uid || "")}</code><code>Email: ${esc(state.user?.email || state.accountDeletionQueue?.email || "")}</code></div>` : ""}
        <button class="ghost-button" type="button" data-action="logout">Sair</button>
      </article>
    </section>
  `;
}

function renderTermsGate() {
  return `
    <div class="grid">
      <article class="panel span-12 terms-gate">
        <p class="eyebrow">Termo de acordo</p>
        <h2>Antes de despertar em Millennium</h2>
        <p>${esc(state.settings.termsText || DEFAULT_CONTENT.settings.termsText)}</p>
        <div class="content-grid">${renderRulesCards(state.content.rulesChapters.slice(0, 4))}</div>
        <form class="form-stack" data-form="terms-accept">
          <label class="checkbox-line"><input name="accepted" type="checkbox" value="true" required /> <span>Li e aceito as regras de convivência, integridade, punições e uso da Interface.</span></label>
          <button class="primary-button" type="submit">Aceitar e entrar</button>
        </form>
      </article>
    </div>
  `;
}

function homeSeasonSnapshot(character = currentCharacter()) {
  const level = seasonPassLevel(character);
  const xp = Math.max(0, Number(character.seasonPassXp || 0));
  const percent = Math.max(2, Math.min(100, Math.round((level / 50) * 100)));
  return {
    level,
    xp,
    percent,
    premium: character.premiumPassUnlocked === true,
  };
}

function homeMissionSpotlight(character = currentCharacter()) {
  const missions = Array.isArray(state.weeklyMissions) ? state.weeklyMissions : [];
  const activeIds = new Set(character.activeMissions || []);
  const pending = pendingProgressRequests().filter((request) => request.type === "mission");
  const active = missions.find((mission) => activeIds.has(mission.id));
  const awaiting = missions.find((mission) => pending.some((request) => request.missionId === mission.id));
  const mission = active || awaiting || missions[0] || null;
  if (!mission) {
    return {
      title: "Nenhuma missão publicada",
      description: "O Oráculo ainda não abriu uma missão para esta semana.",
      reward: "Aguardando registro",
      rarity: "Comum",
      status: "Indisponível",
      tone: "idle",
    };
  }
  const isActive = activeIds.has(mission.id);
  const isPending = pending.some((request) => request.missionId === mission.id);
  return {
    ...mission,
    title: mission.title || mission.name || "Missão sem nome",
    status: isPending ? "Aguardando Oráculo" : isActive ? "Em andamento" : "Disponível agora",
    tone: isPending ? "pending" : isActive ? "active" : "available",
  };
}

function homeActivityEntries(character = currentCharacter()) {
  const entries = [];
  recentNews().slice(-6).reverse().forEach((message) => {
    entries.push({
      icon: message.type === "rare" ? "✦" : message.type === "admin-alert" ? "!" : message.type === "join" ? "+" : "◇",
      title: message.type === "rare" ? "Raridade registrada" : message.type === "join" ? "Novo despertar" : "Pulso do mundo",
      text: message.text || message.senderName || "A Interface registrou um movimento.",
      when: message.createdAt,
      tone: message.type === "rare" ? "rare" : message.type === "admin-alert" ? "danger" : "interface",
    });
  });
  pendingProgressRequests().slice(-3).reverse().forEach((request) => {
    entries.push({
      icon: "⌛",
      title: `${progressTypeLabel(request.type)} em análise`,
      text: request.title || request.description || "O Oráculo está examinando este registro.",
      when: request.createdAt,
      tone: "pending",
    });
  });
  if (character.pendingGift) {
    entries.push({
      icon: "✧",
      title: "Correio místico",
      text: character.pendingGift.message || "Uma recompensa aguarda confirmação.",
      when: character.pendingGift.createdAt,
      tone: "hero",
    });
  }
  if (state.privateMessages.some((message) => message.senderId !== state.user?.uid && !message.readAt)) {
    entries.push({
      icon: "✉",
      title: "Mensagem não lida",
      text: "Há um chamado direto aguardando sua atenção.",
      when: new Date().toISOString(),
      tone: "interface",
    });
  }
  return entries
    .sort((left, right) => timeValue(right.when) - timeValue(left.when))
    .slice(0, 6);
}

function renderHomeActivity(entries) {
  if (!entries.length) {
    return `<div class="empty-state home-activity-empty"><strong>Nenhuma atividade recente.</strong><span>Quando o mundo se mover, a Interface registrará os sinais aqui.</span></div>`;
  }
  return entries.map((entry) => `
    <article class="home-activity-entry" data-tone="${esc(entry.tone || "interface")}">
      <span class="home-activity-icon" aria-hidden="true">${esc(entry.icon || "◇")}</span>
      <div>
        <strong>${esc(entry.title)}</strong>
        <p>${esc(entry.text)}</p>
        ${entry.when ? `<time>${esc(tsText(entry.when))}</time>` : ""}
      </div>
    </article>
  `).join("");
}

