function renderHallOfFame() {
  const byPrestige = leaderboard().slice(0, 5);
  const eligible = rankingCharacters().filter(rankingEligible);
  const byLevel = [...eligible].sort((a, b) => Number(b.level || levelFromXp(b.xp || 0)) - Number(a.level || levelFromXp(a.xp || 0))).slice(0, 5);
  const byRares = [...eligible].sort((a, b) => Number(b.totalRares || 0) - Number(a.totalRares || 0)).slice(0, 5);
  const guilds = [...state.guilds].sort((a, b) => guildScore(b) - guildScore(a)).slice(0, 5);
  return `
    <div class="grid">
      <article class="panel span-12"><div class="panel-heading"><div><p class="eyebrow">Legado</p><h2>Hall da Fama</h2></div><span class="tag">Temporada ${Number(state.settings.seasonNumber || 1)}</span></div></article>
      ${hallPanel("Prestígio", byPrestige, (char) => `${prestigeFor(char)} pontos · ${activeTitle(char)?.name || "sem título"}`)}
      ${hallPanel("Maiores níveis", byLevel, (char) => `Nível ${Number(char.level || levelFromXp(char.xp || 0))} · ${Number(char.xp || 0)} XP`)}
      ${hallPanel("Mais raros", byRares, (char) => `${Number(char.totalRares || 0)} raros · ${Number(char.totalRolls || 0)} giros`)}
      <article class="panel span-6"><p class="eyebrow">Guildas lendárias</p><div class="ranking-list">${guilds.map((guild, index) => `<div class="ranking-row compact"><strong>#${index + 1}</strong><span>${esc(guild.name)} · ${guildScore(guild)} pts</span><b>${(guild.memberIds || []).length}/${GUILD_MEMBER_LIMIT}</b></div>`).join("") || `<div class="empty-state">Sem guildas ainda.</div>`}</div></article>
    </div>
  `;
}

function hallPanel(title, characters, detail) {
  return `
    <article class="panel span-6">
      <p class="eyebrow">${esc(title)}</p>
      <div class="ranking-list">
        ${characters.map((char, index) => `<button class="ranking-row compact" type="button" data-action="open-user-profile" data-user-id="${esc(char.ownerId)}"><strong>#${index + 1}</strong><span>${esc(char.characterName || getUserName(char.ownerId))}</span><b>${esc(detail(char))}</b></button>`).join("") || `<div class="empty-state">Sem dados.</div>`}
      </div>
    </article>
  `;
}

function guildScore(guild) {
  const missionScore = state.progressRequests.filter((request) => request.guildId === guild.id && request.status === "aprovado").length * 100;
  return missionScore + (guild.memberIds || []).length * 10;
}

function renderAdminOps() {
  const diagnostics = currentDiagnosticSnapshot();
  const totalGold = state.characters.reduce((sum, char) => sum + Number(char.gold || 0), 0);
  const totalItems = state.characters.reduce((sum, char) => sum + (char.inventory || []).length, 0);
  const totalEssences = state.characters.reduce((sum, char) => sum + Number(char.affinityAttempts || 0), 0);
  const accepted = state.users.filter((user) => user.acceptedTermsVersion === (state.settings.rulesVersion || "1.0")).length;
  const affinityRows = sortByName(state.content.affinities).map((affinity) => ({ name: affinity.name, count: affinityOwnerCount(affinity.id) })).sort((a, b) => b.count - a.count).slice(0, 8);
  return `
    <div class="grid">
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Operações</p><h2>Auditoria, economia e manutenção</h2></div><span class="tag">${accepted}/${state.users.length} aceitaram termos</span></div>
        <div class="stat-grid">
          ${renderStat("PO total", totalGold)}
          ${renderStat("Itens", totalItems)}
          ${renderStat("Essências", totalEssences)}
          ${renderStat("Guildas", state.guilds.length)}
          ${renderStat("Online", state.users.filter(isUserOnline).length)}
        </div>
      </article>
      <article class="panel span-6">
        <p class="eyebrow">Balanceamento</p>
        <div class="ranking-list">${affinityRows.map((row, index) => `<div class="ranking-row compact"><strong>#${index + 1}</strong><span>${esc(row.name)}</span><b>${row.count} player(s)</b></div>`).join("") || `<div class="empty-state">Sem afinidades distribuídas.</div>`}</div>
      </article>
      <article class="panel span-6">
        <p class="eyebrow">Auditoria recente</p>
        <div class="scroll-list">${renderAuditRows()}</div>
      </article>
      <article class="panel span-12">
        <p class="eyebrow">Modo manutenção e termo</p>
        <form class="form-grid" data-form="admin-ops">
          <label><span>Modo manutenção</span><select name="maintenanceMode"><option value="false" ${!state.settings.maintenanceMode ? "selected" : ""}>Desligado</option><option value="true" ${state.settings.maintenanceMode ? "selected" : ""}>Ligado</option></select></label>
          <label><span>Versão do termo</span><input name="rulesVersion" value="${esc(state.settings.rulesVersion || "1.0")}" /></label>
          <label class="wide"><span>Texto do termo</span><textarea name="termsText" rows="5">${esc(state.settings.termsText || "")}</textarea></label>
          <button class="primary-button wide" type="submit">Salvar operações</button>
        </form>
      </article>
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Migração 3.1</p><h3>Diagnóstico sem escrita</h3></div><span class="tag">Dry-run obrigatório</span></div>
        <p>Gera um plano idempotente para separar arrays antigos em subcoleções. Nenhum documento real é alterado e os arrays antigos permanecem preservados.</p>
        <div class="form-grid"><label><span>Ficha</span><select id="migrationCharacterSelect">${state.characters.map((character) => `<option value="${esc(character.ownerId || character.id)}">${esc(character.characterName || getUserName(character.ownerId || character.id))}</option>`).join("")}</select></label><div class="action-row wide"><button class="primary-button" type="button" data-action="preview-migration">Gerar plano</button>${state.migrationPreview ? `<button class="ghost-button" type="button" data-action="download-migration-preview">Baixar JSON</button>` : ""}</div></div>
        ${state.migrationPreview ? `<div class="diagnostic-chip-row"><span class="tag">${state.migrationPreview.operations.length} operação(ões)</span><span class="tag">origem v${state.migrationPreview.fromVersion}</span><span class="tag">destino v${state.migrationPreview.targetVersion}</span><span class="tag">arrays preservados</span></div><pre class="migration-plan">${esc(JSON.stringify({ plan: state.migrationPreview, rollback: window.MILLENNIUM_BACKEND_31.migrationRollbackPlan(state.migrationPreview) }, null, 2))}</pre>` : ""}
      </article>
      <article class="panel span-12"><div class="panel-heading"><div><p class="eyebrow">Listeners por rota</p><h3>Assinaturas ativas</h3></div><span class="tag">${totalActiveListeners()} total</span></div><div class="diagnostic-chip-row">${(state.routeSubscriptionNames || []).map((name) => `<span class="tag">${esc(name)}</span>`).join("") || `<span class="muted-text">Nenhuma assinatura de rota ativa.</span>`}${state.privateUnsub ? `<span class="tag">conversa-aberta</span>` : ""}</div></article>
      <article class="panel span-12 diagnostic-console" aria-labelledby="diagnostic-console-title">
        <div class="panel-heading"><div><p class="eyebrow">Diagnóstico local</p><h3 id="diagnostic-console-title">Estado da Interface</h3></div><div class="action-row"><span class="tag ${diagnostics.online ? "success" : "danger"}">${diagnostics.online ? "Online" : "Offline"}</span><button class="ghost-button" type="button" data-action="download-diagnostics">Baixar diagnóstico</button></div></div>
        <div class="diagnostic-metrics">
          ${renderStat("Build", diagnostics.build)}${renderStat("Commit", diagnostics.commit)}${renderStat("Rota", diagnostics.route)}${renderStat("Service Worker", diagnostics.serviceWorker)}
          ${renderStat("Renders", diagnostics.renders)}${renderStat("Último render", `${diagnostics.lastRenderMs} ms`)}${renderStat("Listeners", diagnostics.listeners)}${renderStat("Foco", diagnostics.focused || "nenhum")}
          ${renderStat("Leituras observadas", diagnostics.reads)}${renderStat("Escritas observadas", diagnostics.writes)}${renderStat("Listeners iniciados", diagnostics.listenerStarts)}${renderStat("Catálogos em cache", diagnostics.catalogsCached)}
          ${renderStat("Leituras de catálogo", diagnostics.catalogReads)}${renderStat("Persistência", diagnostics.persistence)}${renderStat("Verificações de segurança", diagnostics.securityVerifications)}${renderStat("Falhas de imagem", diagnostics.images.failed)}
        </div>
        <div class="diagnostic-chip-row">${diagnostics.minigames.map((game) => `<span class="tag">${esc(game.mode)} · ${esc(game.state)} · ${game.timers} timer(s)</span>`).join("") || `<span class="muted-text">Nenhuma sessão de minigame ativa.</span>`}</div>
        <details><summary>Histórico recente de renderização</summary><div class="diagnostic-history">${(state.diagnostics.renderHistory || []).slice(-12).reverse().map((entry) => `<div><span>${esc(entry.route || "rota")}</span><strong>${Number(entry.durationMs || 0)} ms</strong><small>${esc(entry.reason || "render")} · ${esc(entry.focused || "sem foco")} · ${Number(entry.listeners || 0)} listener(s)</small></div>`).join("") || `<p class="muted-text">Nenhum render registrado.</p>`}</div></details>
      </article>
    </div>
  `;
}

function previewMigrationPlan() {
  const select = document.querySelector("#migrationCharacterSelect");
  const uid = select?.value || state.characters[0]?.ownerId || state.characters[0]?.id;
  const character = state.characters.find((entry) => (entry.ownerId || entry.id) === uid) || currentCharacter();
  state.migrationPreview = window.MILLENNIUM_BACKEND_31.arrayDocumentPlan(character, 3);
  scheduleRender({ critical: true, preserveScroll: true, reason: "migration-preview" });
}

function downloadMigrationPreview() {
  if (!state.migrationPreview) return;
  const payload = JSON.stringify({ generatedAt: new Date().toISOString(), dryRun: true, plan: state.migrationPreview, rollback: window.MILLENNIUM_BACKEND_31.migrationRollbackPlan(state.migrationPreview) }, null, 2);
  const url = URL.createObjectURL(new Blob([payload], { type: "application/json" }));
  const link = document.createElement("a");
  link.href = url;
  link.download = `millennium-migration-${state.migrationPreview.uid || "character"}.json`;
  link.click();
  URL.revokeObjectURL(url);
}

function downloadDiagnostics() {
  const payload = JSON.stringify({ generatedAt: new Date().toISOString(), diagnostics: currentDiagnosticSnapshot(), renderHistory: state.diagnostics.renderHistory || [], routeSubscriptions: state.routeSubscriptionNames || [] }, null, 2);
  const url = URL.createObjectURL(new Blob([payload], { type: "application/json" }));
  const link = document.createElement("a");
  link.href = url;
  link.download = `millennium-diagnostics-${Date.now()}.json`;
  link.click();
  URL.revokeObjectURL(url);
}

function renderAuditRows() {
  const rows = [
    ...state.progressRequests.map((item) => ({ at: item.reviewedAt || item.createdAt, label: `Validação ${item.status || "pendente"}`, text: `${item.title || "Solicitação"} · ${getUserName(item.uid)}` })),
    ...state.reports.map((item) => ({ at: item.createdAt, label: `Report ${item.status || "aberto"}`, text: item.title || item.description || "Report" })),
    ...state.globalMessages.filter((item) => ["rare", "admin-alert", "system"].includes(item.type)).map((item) => ({ at: item.createdAt, label: item.type, text: item.text })),
  ].sort((a, b) => timeValue(b.at) - timeValue(a.at)).slice(0, 20);
  return rows.map((row) => `<div class="item-row"><span>${esc(row.label)} · ${esc(tsText(row.at))}</span><strong>${esc(row.text)}</strong></div>`).join("") || `<div class="empty-state">Nada auditado ainda.</div>`;
}

