function renderGuild() {
  const character = currentCharacter();
  const guild = currentGuild();
  const ownGuild = guildForUser();
  const canCreate = state.role !== "admin" && !ownGuild;
  const createDisabled = !canCreate || Number(character.gold || 0) < GUILD_CREATE_COST;
  const guildBrowser = `
    <article class="panel span-4 guild-browser">
      <div class="panel-heading"><div><p class="eyebrow">Guildas</p><h2>Salões da temporada</h2></div></div>
      ${state.role !== "admin" ? `
        <form class="form-stack compact-form" data-form="create-guild">
          <label><span>Nome da guilda</span><input name="name" required ${canCreate ? "" : "disabled"} /></label>
          <label><span>Imagem / brasão por URL</span><input name="imageUrl" ${canCreate ? "" : "disabled"} /></label>
          <label><span>Descrição</span><textarea name="description" rows="3" ${canCreate ? "" : "disabled"}></textarea></label>
          <button class="primary-button" type="submit" ${createDisabled ? "disabled" : ""}>Criar por ${GUILD_CREATE_COST.toLocaleString("pt-BR")} PO</button>
          ${ownGuild ? `<p class="hint">Você já pertence a uma guilda. Para fundar outra, fale com o Oráculo.</p>` : Number(character.gold || 0) < GUILD_CREATE_COST ? `<p class="hint">Você precisa de ${GUILD_CREATE_COST.toLocaleString("pt-BR")} PO para fundar uma guilda.</p>` : ""}
        </form>
      ` : ""}
      <div class="guild-list scroll-list">
        ${state.guilds.map((item) => {
          const count = (item.memberIds || []).length;
          const pending = pendingGuildRequest(item.id);
          const joined = isGuildMember(item);
          return `
            <div class="guild-card ${guild?.id === item.id ? "active" : ""}">
              <button class="guild-card-main" type="button" data-action="select-guild" data-guild-id="${esc(item.id)}">
                ${item.imageUrl ? `<img src="${esc(item.imageUrl)}" alt="${esc(item.name)}" />` : `<span class="guild-emblem">G</span>`}
                <span>
                  <strong>${esc(item.name)}</strong>
                  <small>${count}/${GUILD_MEMBER_LIMIT} membros · Líder ${esc(getUserName(item.leaderId))}</small>
                </span>
              </button>
              ${state.role !== "admin" && !joined && !ownGuild ? `<button class="ghost-button" type="button" data-action="request-guild-join" data-guild-id="${esc(item.id)}" ${(pending || count >= GUILD_MEMBER_LIMIT) ? "disabled" : ""}>${pending ? "Pedido enviado" : count >= GUILD_MEMBER_LIMIT ? "Lotada" : "Pedir entrada"}</button>` : joined ? `<span class="tag">Sua guilda</span>` : ""}
            </div>
          `;
        }).join("") || `<div class="empty-state">Nenhuma guilda fundada ainda.</div>`}
      </div>
    </article>
  `;

  if (!guild) {
    return `<div class="grid">${guildBrowser}<article class="panel span-8"><div class="empty-state">Crie a primeira guilda ou aguarde novas fundações.</div></article></div>`;
  }

  const leader = isGuildLeader(guild);
  const members = guildMembers(guild);
  const memberCount = (guild.memberIds || []).length;
  const selectedMember = isGuildMember(guild) || state.role === "admin";
  const availableUsers = state.users.filter((user) => user.id !== state.user.uid && !(guild.memberIds || []).includes(user.id) && !guildForUser(user.id));
  const messages = state.guildMessages.filter((message) => message.guildId === guild.id);
  const activeMission = guild.activeMission || null;
  const selectedPending = pendingGuildRequest(guild.id);
  const selectedFull = memberCount >= GUILD_MEMBER_LIMIT;
  const score = guildScore(guild);
  const guildLevel = Math.max(1, Math.floor(score / 100) + 1);
  return `
    <div class="grid">
      ${guildBrowser}
      <article class="panel span-8 guild-hero">
        ${guild.imageUrl ? `<img src="${esc(guild.imageUrl)}" alt="${esc(guild.name)}" />` : `<div class="guild-emblem big">G</div>`}
        <div>
          <p class="eyebrow">Guilda</p>
          <h2>${esc(guild.name)}</h2>
          <p>${esc(guild.description || "Sem descrição.")}</p>
          <div class="tag-row">
            <span class="tag">${memberCount}/${GUILD_MEMBER_LIMIT} membro(s)</span>
            <span class="tag">Nível ${guildLevel}</span>
            <span class="tag">${score} reputação</span>
            <span class="tag">Líder: ${esc(getUserName(guild.leaderId))}</span>
            ${selectedMember ? `<span class="tag">Acesso liberado</span>` : `<span class="tag">Prévia pública</span>`}
          </div>
          ${!selectedMember && state.role !== "admin" ? `
            <div class="action-row" style="margin-top:14px">
              <button class="primary-button" type="button" data-action="request-guild-join" data-guild-id="${esc(guild.id)}" ${(ownGuild || selectedPending || selectedFull) ? "disabled" : ""}>${ownGuild ? "Você já tem guilda" : selectedPending ? "Pedido enviado" : selectedFull ? "Guilda lotada" : "Pedir entrada"}</button>
            </div>
          ` : ""}
        </div>
      </article>
      ${!selectedMember ? `
        <article class="panel span-8">
          <div class="empty-state">Entre na guilda para liberar chat interno, missões de party e painel de membros.</div>
        </article>
      ` : ""}
      ${selectedMember && leader ? `
        <article class="panel span-5">
          <p class="eyebrow">Liderança</p>
          <h3>Editar guilda</h3>
          <form class="form-stack" data-form="guild-settings">
            <input type="hidden" name="guildId" value="${esc(guild.id)}" />
            <label><span>Nome</span><input name="name" value="${esc(guild.name)}" required /></label>
            <label><span>Imagem / brasão</span><input name="imageUrl" value="${esc(guild.imageUrl || "")}" /></label>
            <label><span>Descrição</span><textarea name="description" rows="4">${esc(guild.description || "")}</textarea></label>
            <label><span>Mural</span><textarea name="mural" rows="4">${esc(guild.mural || "")}</textarea></label>
            <button class="primary-button" type="submit">Salvar guilda</button>
          </form>
          <form class="form-stack" data-form="guild-invite">
            <input type="hidden" name="guildId" value="${esc(guild.id)}" />
            <label><span>Convidar player</span><select name="uid">${availableUsers.map((user) => `<option value="${esc(user.id)}">${esc(displayNameWithTitle(user.id, user.displayName || user.email))}</option>`).join("")}</select></label>
            <button class="ghost-button" type="submit" ${(availableUsers.length && memberCount < GUILD_MEMBER_LIMIT) ? "" : "disabled"}>${memberCount >= GUILD_MEMBER_LIMIT ? "Guilda lotada" : "Enviar convite"}</button>
          </form>
        </article>
      ` : ""}
      ${selectedMember ? `<article class="panel ${leader ? "span-7" : "span-8"}">
        <div class="panel-heading"><div><p class="eyebrow">Membros</p><h3>Salão da guilda</h3></div></div>
        <div class="guild-members">
          ${members.map((member) => `
            <div class="guild-member">
              <button class="link-button" type="button" data-action="open-user-profile" data-user-id="${esc(member.uid)}">${esc(displayNameWithTitle(member.uid, member.user?.displayName || member.character?.displayName || "Player"))}</button>
              <span>${member.uid === guild.leaderId ? "Líder" : isUserOnline(member.user) ? "Online" : "Offline"}</span>
              ${leader && member.uid !== guild.leaderId ? `<button class="danger-button" type="button" data-action="guild-remove-member" data-guild-id="${esc(guild.id)}" data-user-id="${esc(member.uid)}">Remover</button>` : ""}
            </div>
          `).join("")}
        </div>
      </article>` : ""}
      ${selectedMember ? `<article class="panel span-12 guild-mural">
        <div class="panel-heading"><div><p class="eyebrow">Mural da guilda</p><h3>Recados, reputação e objetivos</h3></div><span class="tag">Nível ${guildLevel}</span></div>
        <p>${esc(guild.mural || "Use este espaço como mural narrativo da guilda. O líder pode editar no painel de liderança.")}</p>
      </article>` : ""}
      ${selectedMember ? `<article class="panel span-6">
        <div class="panel-heading"><div><p class="eyebrow">Chat da guilda</p><h3>Canal interno</h3></div></div>
        <div class="scroll-list">${renderMessages(messages, { source: "guild", reportable: true })}</div>
        <form class="form-stack" data-form="guild-chat">
          <input type="hidden" name="guildId" value="${esc(guild.id)}" />
          <textarea name="text" rows="3" required placeholder="Mensagem da guilda..."></textarea>
          ${renderEmojiBar()}
          <button class="primary-button" type="submit">Enviar para guilda</button>
        </form>
      </article>
      <article class="panel span-6">
        <div class="panel-heading"><div><p class="eyebrow">Missões de guilda</p><h3>Partys até 4 membros</h3></div></div>
        ${activeMission ? `
          <div class="mission weekly">
            <span>Em andamento</span>
            <h3>${esc(activeMission.title)}</h3>
            <p>Party: ${(activeMission.partyIds || []).map((uid) => esc(getUserName(uid))).join(" · ")}</p>
            ${leader ? `<button class="primary-button" type="button" data-action="finish-guild-mission" data-guild-id="${esc(guild.id)}">Enviar conclusão ao Oráculo</button>` : ""}
          </div>
        ` : leader ? `
          <form class="form-stack" data-form="start-guild-mission">
            <input type="hidden" name="guildId" value="${esc(guild.id)}" />
            <label><span>Missão</span><select name="missionId">${state.guildMissions.map((mission) => `<option value="${esc(mission.id)}">${esc(mission.title)} · ${esc(mission.rarity)}</option>`).join("")}</select></label>
            <div class="checkbox-grid">
              ${members.map((member) => `<label><input type="checkbox" name="party_${esc(member.uid)}" ${member.uid === state.user.uid ? "checked" : ""} /> <span>${esc(getUserName(member.uid))}</span></label>`).join("")}
            </div>
            <button class="primary-button" type="submit">Formar party</button>
          </form>
        ` : `<div class="empty-state">Aguardando o líder formar a próxima party.</div>`}
        <div class="content-grid" style="margin-top:14px">
          ${state.guildMissions.map((mission) => `
            <div class="mission weekly">
              <span>${esc(mission.rarity || "Raro")}</span>
              <h3>${esc(mission.title)}</h3>
              <p>${esc(mission.description)}</p>
              <strong>${esc(mission.reward)}</strong>
            </div>
          `).join("")}
        </div>
      </article>` : ""}
    </div>
  `;
}

function conversationOtherId(conversation = {}) {
  return (conversation.participantIds || conversation.participants || []).find((uid) => uid !== state.user?.uid) || "";
}

function conversationSummaryFor(uid) {
  const id = window.MILLENNIUM_BACKEND_31.conversationIdFor(state.user.uid, uid);
  return state.conversations.find((entry) => entry.id === id) || null;
}

function renderConversationContact(user) {
  const conversation = conversationSummaryFor(user.id);
  const active = state.selectedPrivateUserId === user.id;
  return `<button class="conversation-card ${active ? "active" : ""}" type="button" data-action="select-direct-user" data-user-id="${esc(user.id)}"><span class="${isUserOnline(user) ? "online-dot" : "offline-dot"}"></span><span><strong>${esc(displayNameWithTitle(user.id, user.displayName || user.email))}</strong><small>${esc(conversation?.lastMessage || (conversation ? "Conversa iniciada" : "Iniciar conversa"))}</small></span>${conversation?.lastMessageAt ? `<time>${esc(tsText(conversation.lastMessageAt))}</time>` : ""}</button>`;
}

function renderChatView() {
  const recipients = state.users.filter((user) => user.id !== state.user.uid);
  const globalMessages = state.globalMessages.filter((message) => message.type !== "whisper");
  const friends = friendIds().map((uid) => state.users.find((user) => user.id === uid)).filter(Boolean);
  const conversationUsers = state.conversations.map((conversation) => state.users.find((user) => user.id === conversationOtherId(conversation))).filter(Boolean);
  const directList = [...new Map([...(friends.length ? friends : recipients), ...conversationUsers].map((user) => [user.id, user])).values()]
    .sort((a, b) => timeValue(conversationSummaryFor(b.id)?.lastMessageAt) - timeValue(conversationSummaryFor(a.id)?.lastMessageAt));
  return `
    <div class="grid">
      <div class="span-12 chat-mode-switch" role="tablist" aria-label="Tipo de conversa">
        <button class="${state.chatTab === "global" ? "active" : ""}" type="button" role="tab" aria-selected="${state.chatTab === "global"}" data-action="chat-mode" data-tab="global"><span>Global</span><small>${globalMessages.length} mensagens</small></button>
        <button class="${state.chatTab === "direct" ? "active" : ""}" type="button" role="tab" aria-selected="${state.chatTab === "direct"}" data-action="chat-mode" data-tab="direct"><span>Direto</span><small>${state.privateMessages.length} carregadas</small></button>
      </div>
      <article class="panel span-12 chat-panel ${state.chatTab === "global" ? "active" : ""}" data-chat-panel="global"><div class="panel-heading"><div><p class="eyebrow">Global</p><h3>Chat e anúncios raros</h3></div></div><div class="scroll-list" data-chat-scroll="global">${renderMessages(globalMessages, { source: "global", reportable: true })}</div><form class="form-stack" data-form="global-chat"><textarea name="text" rows="3" placeholder="Escreva no chat global..." required></textarea>${renderEmojiBar()}<button class="primary-button" type="submit">Enviar global</button></form></article>
      <article class="panel span-12 chat-panel ${state.chatTab === "direct" ? "active" : ""}" data-chat-panel="direct"><div class="panel-heading"><div><p class="eyebrow">Direto</p><h3>Conversas privadas</h3></div><span class="tag">30 mensagens por página</span></div><div class="direct-layout"><div class="conversation-list">${directList.map(renderConversationContact).join("") || `<div class="empty-state compact">Nenhum contato disponível.</div>`}</div><div class="direct-chat">${state.selectedPrivateUserId ? `<div class="direct-chat-head"><button class="link-button" type="button" data-action="direct-back">← Conversas</button><strong>${esc(displayNameWithTitle(state.selectedPrivateUserId, getUserName(state.selectedPrivateUserId)))}</strong><button class="link-button" type="button" data-action="open-user-profile" data-user-id="${esc(state.selectedPrivateUserId)}">Perfil</button></div>${state.conversationHasMore ? `<div class="load-older-wrap"><button class="ghost-button" type="button" data-action="load-older-direct" ${state.conversationLoading ? "disabled" : ""}>${state.conversationLoading ? "Carregando..." : "Carregar anteriores"}</button></div>` : ""}<div class="scroll-list direct-messages" data-chat-scroll="private-${esc(state.selectedPrivateUserId)}">${state.privateChatError ? `<div class="empty-state">${esc(state.privateChatError)}</div>` : renderMessages(state.privateMessages, { source: "private", reportable: true })}</div><form class="form-stack" data-form="private-chat"><textarea name="text" rows="3" maxlength="2000" placeholder="Mensagem direta..." required></textarea>${renderEmojiBar()}<button class="primary-button" type="submit" ${state.messageSending ? "disabled" : ""}>${state.messageSending ? "Enviando..." : "Enviar direto"}</button></form>` : `<div class="direct-chat-empty"><div><p class="eyebrow">Mensagem direta</p><h3>Selecione um jogador</h3><p>Somente os dois participantes podem ler a conversa. Mensagens enviadas não podem ser reescritas.</p></div></div>`}</div></div></article>
    </div>`;
}

function renderEmojiBar() {
  return `<div class="emoji-bar">${CHAT_EMOJIS.map((emoji) => `<button type="button" data-action="add-emoji" data-emoji="${esc(emoji)}" aria-label="Emoji ${esc(emoji)}">${esc(emoji)}</button>`).join("")}</div>`;
}

function renderMessageIdentity(message = {}) {
  if (!message.senderId || message.senderId === "system") {
    return `<div class="message-avatar system" aria-hidden="true">M</div><div class="message-identity"><span>Sistema de Millennium</span><small>${message.type === "admin-alert" ? "Presença do Oráculo" : "Registro da Interface"}</small></div>`;
  }
  const character = findCharacter(message.senderId) || getCharacterFor(message.senderId);
  const title = activeTitle(character);
  const playerName = getUserName(message.senderId) || message.senderName || "Player";
  const characterName = character.characterName || playerName;
  return `
    <button class="message-avatar" type="button" data-action="open-user-profile" data-user-id="${esc(message.senderId)}" aria-label="Abrir perfil de ${esc(characterName)}"><img src="${esc(character.avatarUrl || placeholderAvatar())}" style="${esc(cropImageStyle(character, "avatar"))}" alt="" ${mediaAttrs("avatar")} /></button>
    <div class="message-identity">
      <button class="link-button message-author" type="button" data-action="open-user-profile" data-user-id="${esc(message.senderId)}">${esc(characterName)}</button>
      <small>${esc(playerName)}${title ? ` · ${esc(title.name)}` : " · Sem título equipado"}</small>
    </div>
  `;
}

function renderMessages(messages, options = {}) {
  if (!messages.length) return `<div class="empty-state">Nada por aqui ainda.</div>`;
  return messages.map((message) => `
    <div class="message ${esc(message.type || "")} ${message.type === "rare" ? "rare" : ""} ${message.pending ? "pending" : ""} ${message.failed ? "failed" : ""}">
      <div class="message-head">
        ${renderMessageIdentity(message)}
        ${message.rarity ? `<span class="message-rarity ${rarityClass(message.rarity)}">${esc(message.rarity)}</span>` : ""}
      </div>
      <p>${esc(message.text)}</p>
      <div class="message-actions">
        <small>${esc(tsText(message.createdAt))}${message.pending ? " · enviando" : message.failed ? " · falhou" : ""}</small>
        ${message.failed ? `<button class="link-button" type="button" data-action="retry-private-message" data-client-id="${esc(message.clientId || message.id)}">Tentar novamente</button>` : ""}
        ${options.reportable && message.senderId && message.senderId !== "system" && message.senderId !== state.user?.uid ? `
          <button class="link-button danger-link" type="button" data-action="report-message" data-message-id="${esc(message.id)}" data-message-source="${esc(options.source || "global")}">Denunciar mensagem</button>
        ` : ""}
      </div>
    </div>
  `).join("");
}

function renderMissions() {
  const character = currentCharacter();
  if (!state.settings.gameStarted && state.role !== "admin") {
    return `
      <div class="grid">
        <article class="panel span-12 center-panel">
          <p class="eyebrow">Pré-lançamento</p>
          <h2>O chamado ainda não começou</h2>
          <p>Por enquanto, você pode criar ficha, falar nos chats, ver perfis e girar sua afinidade. Missões, treinos e criações serão liberados quando o ${ORACLE_LABEL} iniciar a Temporada do Despertar.</p>
        </article>
      </div>
    `;
  }
  const activeIds = new Set(character.activeMissions || []);
  const pending = pendingProgressRequests();
  const powerSlots = 1;
  const techniqueSlots = FOUNDATIONS.techniqueSlotsForLevel(Math.max(1, Number(character.level || levelFromXp(character.xp || 0))));
  const usedPowers = approvedPowerCount(character);
  return `
    <div class="grid">
      <article class="panel span-12">
        <div class="panel-heading">
          <div>
            <p class="eyebrow">Reset semanal</p>
            <h2>Missões da semana</h2>
          </div>
          <span class="tag">Reseta segunda 00:00</span>
        </div>
        <div class="content-grid">${renderPlayerMissionList(state.weeklyMissions, activeIds, pending)}</div>
      </article>
      <article class="panel span-6">
        <p class="eyebrow">Progresso narrativo</p>
        <h3>Solicitar XP ao Oráculo</h3>
        <form class="form-stack" data-form="progression-request">
          <label><span>Origem do progresso</span><select name="type"><option value="training">Treino</option><option value="session">Sessão de campanha</option><option value="event">Evento</option><option value="achievement">Conquista importante</option><option value="minigame">Desempenho em minigame</option></select></label>
          <label><span>Título</span><input name="title" required placeholder="Ex.: Controle de mana sob pressão" /></label>
          <label><span>O que foi feito?</span><textarea name="description" rows="5" required></textarea></label>
          <button class="primary-button" type="submit">Enviar progresso ao Oráculo</button>
        </form>
      </article>
      <article class="panel span-6">
        <p class="eyebrow">Nerf e aprovação</p>
        <h3>Poderes e técnicas novas</h3>
        <p class="muted-text">Poder central: ${usedPowers}/${powerSlots}. Técnicas: ${(character.techniques || []).length}/${techniqueSlots}, com um novo espaço a cada 5 níveis. Custo, limites e contramedidas são definidos pelo Oráculo.</p>
        <button class="primary-button" type="button" data-nav="creations">Abrir oficina de Criações</button>
      </article>
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Fila pessoal</p><h3>Solicitações enviadas</h3></div></div>
        <div class="content-grid">${renderProgressRequests(state.progressRequests.filter((request) => request.uid === state.user.uid).slice(0, 12), false)}</div>
      </article>
    </div>
  `;
}

function renderPlayerMissionList(missions, activeIds, pending) {
  if (!missions.length) return `<div class="empty-state">Nenhuma missão semanal publicada.</div>`;
  return missions.map((mission) => {
    const pendingMission = pending.find((request) => request.type === "mission" && request.missionId === mission.id);
    const active = activeIds.has(mission.id);
    return `
      <div class="mission weekly">
        <span class="mission-rarity">${missionIcon(mission.rarity)} ${esc(mission.rarity || "Comum")}</span>
        <h3>${esc(mission.title)}</h3>
        <p>${esc(mission.description)}</p>
        <strong>${esc(mission.reward || "Recompensa a definir")}</strong>
        <div class="action-row">
          ${pendingMission ? `<span class="tag">Aguardando Oráculo</span>` : active
            ? `<button class="primary-button" type="button" data-action="finish-mission" data-mission-id="${esc(mission.id)}">Marcar concluída</button>`
            : `<button class="ghost-button" type="button" data-action="start-mission" data-mission-id="${esc(mission.id)}">Quero fazer</button>`}
        </div>
      </div>
    `;
  }).join("");
}

function renderMissionList(missions) {
  if (!missions.length) return `<div class="empty-state">Nenhuma missão semanal publicada.</div>`;
  return missions.map((mission) => `
    <div class="mission weekly">
      <span class="mission-rarity">${missionIcon(mission.rarity)} ${esc(mission.rarity || "Comum")}</span>
      <h3>${esc(mission.title)}</h3>
      <p>${esc(mission.description)}</p>
      <strong>${esc(mission.reward || "Recompensa a definir")}</strong>
    </div>
  `).join("");
}

function missionIcon(rarity = "Comum") {
  const icons = {
    Comum: "◇",
    Incomum: "◆",
    Raro: "✦",
    "Épico": "✧",
    "Lendário": "★",
    "Cósmica": "✹",
  };
  return icons[rarity] || "◇";
}

function renderProgressRequests(requests, adminMode = false) {
  if (!requests.length) return `<div class="empty-state">Nenhuma solicitação nessa fila.</div>`;
  return requests.map((request) => {
    const status = creationRequestStatus(request);
    const creation = ["power", "technique"].includes(request.type);
    const attributeAllocation = request.type === "attributeAllocation";
    const attributeRedistribution = request.type === "attributeRedistribution";
    const attributeRequest = attributeAllocation || attributeRedistribution;
    const canAdminAct = adminMode && (!creation || window.MILLENNIUM_BACKEND_31.creationNeedsAdminAction(request));
    const accepted = status === "aceito pelo player";
    const contested = status === "contestado pelo player";
    const proposalFields = creation ? `
      <label><span>Nome final proposto</span><input name="proposedTitle" value="${esc(request.proposedTitle || request.title || "")}" maxlength="120" /></label>
      <label class="wide"><span>Descrição final proposta</span><textarea name="proposedDescription" rows="4" maxlength="5000">${esc(request.proposedDescription || request.description || "")}</textarea></label>
      <label><span>Custo final</span><textarea name="proposedCost" rows="3" maxlength="1200">${esc(request.proposedCost || request.cost || "")}</textarea></label>
      <label><span>Limitações finais</span><textarea name="proposedLimitations" rows="3" maxlength="1200">${esc(request.proposedLimitations || request.limitations || "")}</textarea></label>
      <label><span>Contramedidas finais</span><textarea name="proposedCountermeasures" rows="3" maxlength="1200">${esc(request.proposedCountermeasures || request.countermeasures || "")}</textarea></label>
    ` : "";
    const decisionOptions = creation
      ? accepted
        ? `<option value="approved">Aprovar definitivamente</option><option value="proposal">Enviar nova revisão</option><option value="rejected">Reprovar</option>`
        : `<option value="proposal">Enviar análise para confirmação</option><option value="reviewing">Marcar em análise</option><option value="rejected">Reprovar</option>`
      : `<option value="approved">Aprovar</option><option value="rejected">Reprovar</option>`;

    return `
      <div class="request-card ${status === "pendente" ? "pending" : ""}" data-request-id="${esc(request.id)}">
        <span>${esc(progressTypeLabel(request.type))} · ${esc(status)}</span>
        <small>Player: ${esc(request.characterName || request.playerName || getUserName(request.uid))} · Protocolo: ${esc(request.id || "sem protocolo")}</small>
        <h3>${esc(request.title || "Solicitação")}</h3>
        <p>${esc(request.description || "")}</p>
        ${creation ? `<div class="creation-field-list">${creationRequestDetails(request)}</div>` : ""}
        ${attributeAllocation ? `<p><strong>Distribuição:</strong> ${esc(attributeAllocationSummary(request.allocation))}</p>` : ""}
        ${attributeRedistribution ? `<div class="review-warning"><strong>Comparação da base</strong><span>Antes: ${esc(baseAllocationSummary(request.currentBase))}<br />Depois: ${esc(baseAllocationSummary(request.proposedBase))}<br />Desenvolvimento e demais dados: preservados</span></div>${request.detectedIssue ? `<p><strong>Elegibilidade:</strong> ${esc(request.detectedIssue)}</p>` : ""}` : ""}
        <p>${esc(requestRewardHint(request))}</p>
        ${request.adminNote ? `<p><strong>Nota do Oráculo:</strong> ${esc(request.adminNote)}</p>` : ""}
        ${request.playerResponse ? `<p><strong>Resposta do player:</strong> ${esc(request.playerResponse)}</p>` : ""}
        ${contested ? `<div class="review-warning"><strong>O player apontou uma contradição.</strong><span>Revise a proposta antes de reenviar.</span></div>` : ""}
        ${canAdminAct ? `
          ${!creation && !attributeRequest && status === "pendente" ? `<div class="action-row"><button class="ghost-button" type="button" data-action="quick-approve" data-request-id="${esc(request.id)}">Aprovar rápido</button></div>` : ""}
          <form class="form-grid compact-form" data-form="review-request" data-draft-key="progress:${esc(request.id)}">
            <input type="hidden" name="requestId" value="${esc(request.id)}" data-draft-ignore="true" />
            ${proposalFields}
            ${creation || attributeRequest ? "" : `<label><span>XP aprovado</span><input name="xp" type="number" min="0" max="5000" value="${Number(request.xp || defaultXpForRequest(request.type, request.rarity))}" /></label><label><span>PO</span><input name="gold" type="number" min="0" value="0" /></label><label><span>Essências</span><input name="essences" type="number" min="0" value="0" /></label>`}
            <label><span>Decisão do Oráculo</span><select name="decision">${decisionOptions}</select></label>
            <label class="wide"><span>Análise e justificativa</span><textarea name="adminNote" rows="4" maxlength="2000" ${attributeRequest ? "required" : ""} placeholder="Explique a decisão e o efeito sobre a progressão.">${esc(request.adminNote || "")}</textarea></label>
            <button class="primary-button wide" type="submit">${creation && accepted ? "Registrar decisão final" : "Enviar análise"}</button>
          </form>
        ` : ""}
      </div>
    `;
  }).join("");
}

function reportStatusLabel(status = "recebido") {
  const normalized = String(status || "recebido").toLowerCase();
  return window.MILLENNIUM_BACKEND_31.REPORT_STATUSES.includes(normalized) ? normalized : normalized === "aberto" ? "recebido" : normalized;
}

function renderReports() {
  const tab = state.reportTab || "bug";
  const mine = [...state.reports].sort((a, b) => timeValue(b.updatedAt || b.createdAt) - timeValue(a.updatedAt || a.createdAt));
  return `
    <div class="grid support-workbench">
      <article class="catalog-hero span-12"><div><p class="eyebrow">Suporte e Segurança</p><h2>Ajuda, bugs e denúncias</h2><p>O formulário preserva seu texto localmente e envia somente os dados necessários para análise.</p></div><div class="support-tabs">${[["bug","Reportar bug"],["player","Denunciar player"],["message","Denunciar mensagem"],["mine","Meus reports"],["faq","FAQ"]].map(([id,label]) => `<button class="ghost-button ${tab === id ? "active" : ""}" type="button" data-action="report-tab" data-tab="${id}">${label}</button>`).join("")}</div></article>
      ${tab === "bug" ? `<article class="panel span-12"><p class="eyebrow">Reportar bug</p><h3>Descreva como reproduzir o problema</h3><form class="support-form-grid" data-form="bug-report"><label><span>Título</span><input name="title" maxlength="160" required /></label><label><span>Categoria</span><select name="category"><option>Interface</option><option>Conta</option><option>Personagem</option><option>Chat</option><option>Codex</option><option>Minigame</option><option>Outro</option></select></label><label class="wide"><span>Descrição</span><textarea name="description" rows="4" maxlength="5000" required></textarea></label><label class="wide"><span>Passos para reproduzir</span><textarea name="steps" rows="4" maxlength="3000"></textarea></label><label><span>Resultado esperado</span><textarea name="expected" rows="3" maxlength="2000"></textarea></label><label><span>Resultado atual</span><textarea name="actual" rows="3" maxlength="2000"></textarea></label><label><span>Dispositivo</span><input name="device" maxlength="160" placeholder="Ex.: Android, PC, iPhone" /></label><label><span>Navegador</span><input name="browser" maxlength="160" placeholder="Ex.: Chrome, Safari" /></label><button class="primary-button wide" type="submit">Enviar bug</button></form></article>` : ""}
      ${tab === "player" ? `<article class="panel span-12"><p class="eyebrow">Denunciar player</p><h3>Envio restrito ao Oráculo</h3><form class="support-form-grid" data-form="player-report"><label><span>Player denunciado</span><select name="targetId" required><option value="">Escolha</option>${state.users.filter((user) => user.id !== state.user.uid).map((user) => `<option value="${esc(user.id)}">${esc(user.displayName || user.email)}</option>`).join("")}</select></label><label><span>Categoria</span><select name="category"><option>Assédio</option><option>Trapaça</option><option>Conteúdo inadequado</option><option>Conflito narrativo</option><option>Outro</option></select></label><label class="wide"><span>Contexto e descrição</span><textarea name="description" rows="6" maxlength="5000" required></textarea></label><label class="wide"><span>Link de anexo opcional</span><input name="attachmentUrl" maxlength="1000" /></label><button class="danger-button wide" type="submit">Enviar denúncia</button></form></article>` : ""}
      ${tab === "message" ? `<article class="panel span-12"><div class="empty-state"><strong>Denuncie pela própria mensagem.</strong><p>Abra o chat, localize a mensagem e use “Denunciar mensagem”. O sistema inclui um pequeno contexto sem carregar toda a conversa.</p><button class="primary-button" type="button" data-nav="chat">Abrir Chat</button></div></article>` : ""}
      ${tab === "mine" ? `<article class="panel span-12"><div class="panel-heading"><div><p class="eyebrow">Acompanhamento</p><h3>Meus reports</h3></div><span class="tag">${mine.length} registro(s)</span></div><div class="scroll-list">${mine.map((report) => `<article class="report-row" data-report-id="${esc(report.id)}"><div class="report-status-line"><span class="report-friendly-id">${esc(report.friendlyId || report.id)}</span><span class="tag">${esc(reportStatusLabel(report.status))}</span><small>${esc(tsText(report.createdAt))}</small></div><strong>${esc(report.title || "Report")}</strong><p>${esc(report.description || "")}</p>${report.adminNote ? `<p><strong>Resposta do Oráculo:</strong> ${esc(report.adminNote)}</p>` : ""}</article>`).join("") || `<div class="empty-state">Nenhum report enviado.</div>`}</div></article>` : ""}
      ${tab === "faq" ? `<article class="panel span-12"><p class="eyebrow">Perguntas frequentes</p><div class="list">${(state.content.faqEntries || []).slice(0,20).map((entry) => `<details><summary>${esc(entry.name || entry.question || entry.id)}</summary><p>${esc(entry.answer || entry.description || "")}</p></details>`).join("") || `<div class="empty-state">FAQ ainda não carregado.</div>`}</div></article>` : ""}
    </div>`;
}


const ORACLE_ROUTE_DETAILS = Object.freeze({
  "admin-home": { eyebrow: "Núcleo de comando", title: "Conselho do Oráculo", description: "Uma leitura consolidada do mundo, das filas administrativas e dos sinais que exigem decisão." },
  "admin-users": { eyebrow: "Identidades registradas", title: "Contas e fichas", description: "Administre acesso, personagem, economia e cofre sem perder a trilha de auditoria." },
  "admin-content": { eyebrow: "Arquivo vivo", title: "Conteúdo e Forja", description: "Organize raças, classes, afinidades, itens, banners, mapas e registros canônicos." },
  "admin-rewards": { eyebrow: "Concessões", title: "Recompensas do Oráculo", description: "Entregue prêmios com alvo, origem e consequência claramente identificados." },
  "admin-economy": { eyebrow: "Tesouraria", title: "Economia, cofre e esforço", description: "Observe moedas, energia, fragmentos, companheiros e resultados de minigames." },
  "admin-mail": { eyebrow: "Correspondência", title: "Correio místico", description: "Envie mensagens administrativas preservando autoria e contexto." },
  "admin-requests": { eyebrow: "Câmara de decisões", title: "Validações e balanceamento", description: "Compare propostas, limites e contramedidas antes de registrar uma decisão." },
  "admin-ops": { eyebrow: "Observatório", title: "Auditoria e diagnóstico", description: "Acompanhe leituras, listeners, migrações, termos e manutenção da Interface." },
  "admin-chat": { eyebrow: "Vigília", title: "Comunicações", description: "Observe o fluxo social sem confundir moderação com narrativa." },
  "admin-missions": { eyebrow: "Mandatos", title: "Missões semanais", description: "Publique objetivos e recompensas sem alterar o cânone econômico fora da regra existente." },
  "admin-settings": { eyebrow: "Ciclo sazonal", title: "Temporada e temas", description: "Controle avisos, aparência e estado da temporada com ações críticas explicitamente separadas." },
  "admin-reports": { eyebrow: "Tribunal de moderação", title: "Reports e denúncias", description: "Classifique, investigue e responda registros técnicos ou sociais." },
  "ranking": { eyebrow: "Cartografia de prestígio", title: "Ranks sob observação", description: "Leia posições e diferenças sem modificar a fórmula de Prestígio." },
});

function oraclePendingCount() {
  return state.progressRequests.filter((request) => request.status === "pendente" || creationRequestStatus(request) === "em análise").length;
}

function oracleOpenReportCount() {
  return state.reports.filter((report) => !["resolvido", "fechado"].includes(reportStatusLabel(report.status))).length;
}

function oracleRouteMetrics(view) {
  const players = state.users.filter((user) => user.role !== "admin");
  const online = players.filter(isUserOnline).length;
  const activeAccounts = players.filter((user) => normalizedAccountStatus(user) === "active").length;
  const restricted = Math.max(0, players.length - activeAccounts);
  const totalCoins = state.characters.reduce((sum, character) => sum + Number(character.millenniumCoins || 0), 0);
  const totalGold = state.characters.reduce((sum, character) => sum + Number(character.gold || 0), 0);
  const catalogCount = Object.values(state.content || {}).reduce((sum, entries) => sum + (Array.isArray(entries) ? entries.length : 0), 0);
  const routeMap = {
    "admin-users": [["Contas", players.length], ["Online", online], ["Restritas", restricted], ["Fichas", state.characters.length]],
    "admin-content": [["Registros", catalogCount], ["Raças", state.content.races?.length || 0], ["Itens", state.content.items?.length || 0], ["Banners", state.content.gachaBanners?.length || 0]],
    "admin-economy": [["PO", totalGold.toLocaleString("pt-BR")], ["MC", totalCoins.toLocaleString("pt-BR")], ["Cofres", state.characters.reduce((sum, character) => sum + (character.gachaVault || []).length, 0)], ["Atividades", state.characters.reduce((sum, character) => sum + (character.activeActivities || []).length, 0)]],
    "admin-requests": [["Pendentes", oraclePendingCount()], ["Total", state.progressRequests.length], ["Players", players.length], ["Fichas", state.characters.length]],
    "admin-reports": [["Abertos", oracleOpenReportCount()], ["Total", state.reports.length], ["Online", online], ["Build", MILLENNIUM_BUILD.version]],
    "admin-ops": [["Listeners", totalActiveListeners()], ["Leituras", state.diagnostics.documentsRead], ["Escritas", state.diagnostics.writes], ["Build", MILLENNIUM_BUILD.version]],
    ranking: [["Players", players.length], ["Fichas", state.characters.length], ["Líder", Math.max(0, ...state.characters.map((character) => prestigeFor(character)))], ["Online", online]],
  };
  return routeMap[view] || [["Players", players.length], ["Online", online], ["Decisões", oraclePendingCount()], ["Reports", oracleOpenReportCount()]];
}

function renderOracleFrame(view, content) {
  const details = ORACLE_ROUTE_DETAILS[view] || { eyebrow: "Interface administrativa", title: VIEW_TITLES[view] || "Oráculo", description: "Autoridade, contexto e rastreabilidade para cada decisão." };
  const metrics = oracleRouteMetrics(view);
  const routeButtons = [
    ["admin-home", "Conselho"], ["admin-users", "Contas"], ["admin-content", "Conteúdo"],
    ["admin-economy", "Economia"], ["ranking", "Ranks"], ["admin-requests", "Decisões"],
    ["admin-reports", "Reports"], ["admin-ops", "Auditoria"],
  ];
  return `<section class="oracle-console" data-oracle-route="${esc(view)}">
    <header class="oracle-command-header">
      <div class="oracle-command-copy">
        <p class="eyebrow">${esc(details.eyebrow)}</p>
        <h2>${esc(details.title)}</h2>
        <p>${esc(details.description)}</p>
        <div class="oracle-command-status"><span class="oracle-status-dot" aria-hidden="true"></span><strong>Interface 3.6.4</strong><span>${state.demo ? "Ambiente demonstrativo" : "Sessão administrativa"}</span></div>
      </div>
      <div class="oracle-eye-constellation" aria-hidden="true"><span class="oracle-orbit orbit-a"></span><span class="oracle-orbit orbit-b"></span><span class="oracle-eye-core">◉</span><i></i><b></b></div>
      <div class="oracle-metric-grid" aria-label="Métricas desta área">${metrics.map(([label, value]) => `<article class="oracle-metric"><span>${esc(label)}</span><strong>${esc(value)}</strong></article>`).join("")}</div>
    </header>
    <nav class="oracle-route-nav" aria-label="Áreas principais do Oráculo">
      ${routeButtons.map(([target, label]) => `<button class="oracle-route-link ${view === target ? "active" : ""}" type="button" data-nav="${target}" ${view === target ? 'aria-current="page"' : ""}>${label}</button>`).join("")}
      <button class="oracle-route-link oracle-security-link" type="button" data-action="open-security-center">Segurança</button>
    </nav>
    <div class="oracle-route-content">${content}</div>
  </section>`;
}

function renderOracleCommandCard({ nav = "", action = "", icon = "◇", eyebrow = "Comando", title, description, badge = "" }) {
  const data = nav ? `data-nav="${esc(nav)}"` : `data-action="${esc(action)}"`;
  return `<button class="oracle-command-card" type="button" ${data}><span class="oracle-command-icon" aria-hidden="true">${esc(icon)}</span><span><small>${esc(eyebrow)}</small><strong>${esc(title)}</strong><em>${esc(description)}</em></span>${badge ? `<b>${esc(badge)}</b>` : ""}</button>`;
}

function renderAdminHome() {
  const players = state.users.filter((user) => user.role !== "admin");
  const reportsOpen = oracleOpenReportCount();
  const pendingRequests = oraclePendingCount();
  const totalRolls = state.characters.reduce((sum, character) => sum + Number(character.totalRolls || 0), 0);
  const totalCoins = state.characters.reduce((sum, character) => sum + Number(character.millenniumCoins || 0), 0);
  const totalGold = state.characters.reduce((sum, character) => sum + Number(character.gold || 0), 0);
  const activePets = state.characters.reduce((sum, character) => sum + (character.activeActivities || []).length, 0);
  const ranked = [...state.characters].sort((a, b) => prestigeFor(b) - prestigeFor(a)).slice(0, 5);
  const urgentRequests = state.progressRequests
    .filter((request) => request.status === "pendente" || creationRequestStatus(request) === "em análise")
    .sort((a, b) => timeValue(b.createdAt) - timeValue(a.createdAt)).slice(0, 4);
  const urgentReports = state.reports
    .filter((report) => !["resolvido", "fechado"].includes(reportStatusLabel(report.status)))
    .sort((a, b) => timeValue(b.createdAt) - timeValue(a.createdAt)).slice(0, 4);
  return `<div class="grid oracle-dashboard-grid">
    <article class="panel span-12 oracle-command-deck">
      <div class="oracle-section-heading"><div><p class="eyebrow">Comandos principais</p><h3>Escolha o domínio de intervenção</h3></div><span class="tag">Nenhuma ação automática</span></div>
      <div class="oracle-command-grid">
        ${renderOracleCommandCard({ nav: "admin-users", icon: "◇", eyebrow: "Identidades", title: "Contas e fichas", description: "Acesso, personagem, economia e cofre.", badge: `${players.length}` })}
        ${renderOracleCommandCard({ nav: "admin-economy", icon: "⌬", eyebrow: "Tesouraria", title: "Economia", description: "MC, PO, energia, fragmentos e atividades.", badge: `${totalCoins} MC` })}
        ${renderOracleCommandCard({ nav: "admin-content", icon: "✚", eyebrow: "Arquivo", title: "Conteúdo", description: "Raças, classes, afinidades, itens e mapas.", badge: `${state.content.items?.length || 0} itens` })}
        ${renderOracleCommandCard({ nav: "ranking", icon: "#", eyebrow: "Prestígio", title: "Ranks", description: "Posições, diferenças e projeções já calculadas.", badge: ranked[0] ? `${prestigeFor(ranked[0])}` : "—" })}
        ${renderOracleCommandCard({ nav: "admin-requests", icon: "✓", eyebrow: "Julgamento", title: "Decisões", description: "Poderes, técnicas, progressão e nerfs.", badge: `${pendingRequests}` })}
        ${renderOracleCommandCard({ action: "open-security-center", icon: "◉", eyebrow: "Integridade", title: "Segurança", description: "Incidentes, snapshots, quarentenas e recursos.", badge: window.MILLENNIUM_APP_CHECK_STATE?.enabled ? "Ativo" : "Pendente" })}
      </div>
    </article>
    <article class="panel span-8 oracle-priority-panel">
      <div class="oracle-section-heading"><div><p class="eyebrow">Fila crítica</p><h3>Registros que exigem decisão</h3></div><span class="oracle-count-badge">${pendingRequests + reportsOpen}</span></div>
      <div class="oracle-priority-columns">
        <section><h4>Validações</h4>${urgentRequests.map((request) => `<button class="oracle-priority-row" type="button" data-nav="admin-requests"><span>${esc(progressTypeLabel(request.type))}</span><strong>${esc(request.title || "Solicitação")}</strong><small>${esc(getUserName(request.uid))} · ${esc(tsText(request.createdAt))}</small></button>`).join("") || `<div class="empty-state">Nenhuma validação urgente.</div>`}</section>
        <section><h4>Reports</h4>${urgentReports.map((report) => `<button class="oracle-priority-row" type="button" data-nav="admin-reports"><span>${esc(reportStatusLabel(report.status))}</span><strong>${esc(report.title || "Report")}</strong><small>${esc(getUserName(report.reporterId))} · ${esc(tsText(report.createdAt))}</small></button>`).join("") || `<div class="empty-state">Nenhum report aberto.</div>`}</section>
      </div>
    </article>
    <article class="panel span-4 oracle-world-ledger">
      <div class="oracle-section-heading"><div><p class="eyebrow">Estado do mundo</p><h3>Recursos observados</h3></div></div>
      <dl><div><dt>PO em circulação</dt><dd>${totalGold.toLocaleString("pt-BR")}</dd></div><div><dt>Millennium Coins</dt><dd>${totalCoins.toLocaleString("pt-BR")}</dd></div><div><dt>Giros registrados</dt><dd>${totalRolls.toLocaleString("pt-BR")}</dd></div><div><dt>Pets em campo</dt><dd>${activePets}</dd></div><div><dt>Missões semanais</dt><dd>${state.weeklyMissions.length}</dd></div></dl>
    </article>
    <article class="panel span-7 oracle-rank-observatory">
      <div class="oracle-section-heading"><div><p class="eyebrow">Ranks</p><h3>Prestígio sob observação</h3></div><button class="ghost-button" type="button" data-nav="ranking">Abrir central</button></div>
      <div class="oracle-rank-list">${ranked.map((character, index) => { const score = prestigeFor(character); const leader = Math.max(1, prestigeFor(ranked[0] || {})); return `<button type="button" data-action="open-user-profile" data-user-id="${esc(character.ownerId || character.id)}"><b>#${index + 1}</b><span><strong>${esc(character.characterName || getUserName(character.ownerId || character.id))}</strong><small>${esc(getUserName(character.ownerId || character.id))}</small></span><em>${score}</em><i style="--oracle-rank-progress:${Math.max(4, Math.round(score / leader * 100))}%"></i></button>`; }).join("") || `<div class="empty-state">Sem dados de Prestígio.</div>`}</div>
    </article>
    <article class="panel span-5 oracle-audit-ledger">
      <div class="oracle-section-heading"><div><p class="eyebrow">Auditoria</p><h3>Últimos ecos administrativos</h3></div><button class="ghost-button" type="button" data-nav="admin-ops">Diagnóstico</button></div>
      <div class="scroll-list">${renderAuditRows()}</div>
    </article>
  </div>`;
}

function renderAdminEconomy() {
  const players = state.users.filter((user) => user.role !== "admin");
  const characters = players.map((user) => ({ user, character: getCharacterFor(user.id) }));
  const totalCoins = characters.reduce((sum, entry) => sum + Number(entry.character.millenniumCoins || 0), 0);
  const totalEnergy = characters.reduce((sum, entry) => sum + currentGachaEnergy(entry.character), 0);
  const totalFragments = characters.reduce((sum, entry) => sum + Object.values(entry.character.gachaFragments || {}).reduce((inner, amount) => inner + Number(amount || 0), 0), 0);
  const vaultItems = characters.flatMap((entry) => entry.character.gachaVault || []);
  const injured = vaultItems.filter((item) => item.status === "Ferido" || item.status === "Morto").length;
  const activeActivities = characters.flatMap((entry) => entry.character.activeActivities || []);
  const recentRuns = characters.flatMap(({ user, character }) => (character.minigameHistory || []).map((run) => ({ ...run, player: user.displayName || user.email, uid: user.id }))).sort((a, b) => timeValue(b.createdAt) - timeValue(a.createdAt)).slice(0, 12);
  return `
    <div class="grid">
      <article class="panel span-12 economy-hero">
        <div class="panel-heading"><div><p class="eyebrow">Economia viva</p><h2>Millennium Coins, cofre e esforço</h2></div><span class="tag">Visão do Oráculo</span></div>
        <div class="stat-grid compact-stat-grid">
          ${renderStat("Millennium Coins", totalCoins.toLocaleString("pt-BR"))}
          ${renderStat("Energia no servidor", `${totalEnergy}/${Math.max(1, players.length) * GACHA_ENERGY_MAX}`)}
          ${renderStat("Fragmentos", totalFragments.toLocaleString("pt-BR"))}
          ${renderStat("Cofres", vaultItems.length)}
          ${renderStat("Pets feridos", injured)}
          ${renderStat("Atividades", activeActivities.length)}
        </div>
      </article>
      <article class="panel span-12 admin-rotation-panel">
        ${(() => { const banner = activeGachaBanner("pets"); const next = WORLD.selectBalancedRotation(gachaPool("pets"), "pets", gachaNow() + 3600000); return `
          <div class="panel-heading"><div><p class="eyebrow">Banner de companheiros</p><h3>${esc(banner.configured ? "Destaque fixado pelo Oráculo" : "Rotação automática global")}</h3></div><span class="tag" data-gacha-countdown data-gacha-type="pets" data-gacha-ends="${banner.endsAt.getTime()}">${esc(WORLD.countdownParts(banner.endsAt, gachaNow()).label)}</span></div>
          <div class="rotation-admin-grid"><section><small>Agora</small><div>${banner.featured.map((pet) => `<span class="tag ${rarityClass(pet.rarity)}">${esc(pet.name)}</span>`).join("") || "Sem pets elegíveis"}</div></section><section><small>Prévia da próxima hora</small><div>${next.featured.map((pet) => `<span class="tag ${rarityClass(pet.rarity)}">${esc(pet.name)}</span>`).join("") || "Sem pets elegíveis"}</div></section></div>
          <p class="hint">Banners cadastrados e ativos na Forja substituem temporariamente a rotação automática. Ao expirar, o sistema volta para a seleção horária.</p>`; })()}
      </article>
      <article class="panel span-7">
        <div class="panel-heading"><div><p class="eyebrow">Jogadores</p><h3>Quem precisa de atenção</h3></div><span class="tag">Clique para abrir a ficha</span></div>
        <div class="economy-player-list">
          ${characters.map(({ user, character }) => {
            const vault = character.gachaVault || [];
            const hurt = vault.filter((item) => item.status === "Ferido" || item.status === "Morto").length;
            return `
              <button class="economy-player-row" type="button" data-action="open-admin-user" data-user-id="${esc(user.id)}">
                <span class="online-dot ${isUserOnline(user) ? "online" : ""}"></span>
                <div><strong>${esc(character.characterName || user.displayName || user.email)}</strong><small>${esc(user.displayName || user.email)} · ${vault.length} registro(s) no cofre</small></div>
                <div><b>${Number(character.millenniumCoins || 0)} MC</b><small>${currentGachaEnergy(character)}/${GACHA_ENERGY_MAX} energia · ${hurt ? `${hurt} pet(s) ferido(s)` : "cofre estável"}</small></div>
              </button>
            `;
          }).join("") || `<div class="empty-state">Nenhum player para observar.</div>`}
        </div>
      </article>
      <article class="panel span-5">
        <div class="panel-heading"><div><p class="eyebrow">Runs recentes</p><h3>Auditoria de minigames</h3></div></div>
        <div class="run-history">
          ${recentRuns.map((run) => `<div class="run-card"><span>${esc(run.player)} · ${esc(run.mode)} · ${esc(run.difficultyName || run.difficultyId)}</span><strong>Rank ${esc(run.grade || "-")} · ${Number(run.score || 0)} pts</strong><p>${Number(run.coins || 0)} MC · ${Number(run.fragments || 0)} ${esc(run.fragmentName || "fragmentos")}</p></div>`).join("") || `<div class="empty-state">Nenhuma run registrada ainda.</div>`}
        </div>
      </article>
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Incursões em andamento</p><h3>Pets fora do cofre</h3></div></div>
        <div class="content-grid">
          ${activeActivities.map((activity) => `<div class="content-card"><span>${esc(activity.difficultyName)} · ${esc(activity.type)}</span><h3>${esc(activity.petName)}</h3><p>${esc(activity.biome || activity.mapName || "Sem destino")} · risco ${Math.round(Number(activity.risk || 0) * 100)}%</p><button class="ghost-button" type="button" data-action="open-admin-user" data-user-id="${esc(characters.find((entry) => (entry.character.activeActivities || []).some((entryActivity) => entryActivity.id === activity.id))?.user.id || "")}">Abrir ficha</button></div>`).join("") || `<div class="empty-state">Nenhuma atividade em andamento.</div>`}
        </div>
      </article>
    </div>
  `;
}

function renderAdminUsers() {
  const selectedId = state.selectedUserId || state.users.find((user) => user.role !== "admin")?.id || state.users[0]?.id || "";
  state.selectedUserId = selectedId;
  const selectedUser = state.users.find((user) => user.id === selectedId);
  const character = selectedId ? getCharacterFor(selectedId) : null;
  const draft = state.adminUserDraft?.uid === selectedId ? state.adminUserDraft.values : null;
  const selectedStatus = normalizedAccountStatus(selectedUser || {});
  const affinityOptions = `<option value="">Sem afinidade</option>${optionList(state.content.affinities, draftValue(draft, "affinityId", character?.affinityId || ""))}`;
  return `
    <div class="grid">
      <article class="panel span-4">
        <div class="panel-heading"><div><p class="eyebrow">Players</p><h3>Escolhidos registrados</h3></div></div>
        <div class="scroll-list">
          ${state.users.map((user) => `
            <button class="user-row ${selectedId === user.id ? "active" : ""}" type="button" data-action="select-user" data-user-id="${esc(user.id)}">
              <strong>${esc(user.displayName || user.email)}</strong>
              <span>${esc(user.role || "player")} · ${esc(normalizedAccountStatus(user))} · ${isUserOnline(user) ? "online" : "offline"}</span>
            </button>
          `).join("")}
        </div>
        ${state.accountDeletionQueueEntries.length ? `<div class="pending-auth-deletions"><p class="eyebrow">Authentication pendente</p>${state.accountDeletionQueueEntries.map((entry) => `<div class="item-row"><strong>${esc(entry.displayName || entry.email || entry.id)}</strong><small>${esc(entry.email || "Sem e-mail")}</small><button class="unban-button" type="button" data-action="admin-auth-deletion-details" data-user-id="${esc(entry.id || entry.ownerId)}">Concluir</button></div>`).join("")}</div>` : ""}
      </article>
      <article class="panel span-8">
        ${selectedUser && character ? `
          <div class="panel-heading">
            <div>
              <p class="eyebrow">Vasculhar ficha</p>
              <h2>${esc(character.characterName || selectedUser.displayName || selectedUser.email)}</h2>
            </div>
            <span class="tag">${esc(selectedUser.role || "player")}</span>
          </div>
          <form class="form-grid" data-form="admin-user-edit">
            <input type="hidden" name="uid" value="${esc(selectedId)}" />
            <label><span>Nome exibido</span><input name="displayName" value="${esc(draftValue(draft, "displayName", selectedUser.displayName || ""))}" /></label>
            <label><span>Papel</span><select name="role"><option value="player" ${draftValue(draft, "role", selectedUser.role) !== "admin" ? "selected" : ""}>Player</option><option value="admin" ${draftValue(draft, "role", selectedUser.role) === "admin" ? "selected" : ""}>Oráculo</option></select></label>
            <div class="wide"><span>Status da conta</span><p><span class="account-status-chip ${esc(selectedStatus)}">${esc(selectedStatus === "active" ? "Ativa" : selectedStatus === "suspended" ? "Suspensa" : selectedStatus === "banned" ? "Banida" : selectedStatus === "deletion_pending" ? "Exclusão pendente" : selectedStatus)}</span></p><small>Suspensão, banimento e exclusão são controlados nos blocos abaixo e não por este formulário.</small></div>
            <label><span>PO</span><input name="gold" type="number" value="${Number(draftValue(draft, "gold", character.gold || 0))}" /></label>
            <label><span>Millennium Coins</span><input name="millenniumCoins" type="number" value="${Number(draftValue(draft, "millenniumCoins", character.millenniumCoins || 0))}" /></label>
            <label><span>Energia diária</span><input name="gachaEnergy" type="number" min="0" max="${GACHA_ENERGY_MAX}" value="${Number(draftValue(draft, "gachaEnergy", currentGachaEnergy(character)))}" /></label>
            <label><span>Fragmentos do Despertar</span><input name="awakeningFragments" type="number" min="0" value="${Number(draftValue(draft, "awakeningFragments", character.gachaFragments?.["Fragmentos do Despertar"] || 0))}" /></label>
            <label><span>Essências de roleta</span><input name="affinityAttempts" type="number" value="${Number(draftValue(draft, "affinityAttempts", character.affinityAttempts || 0))}" /></label>
            <label><span>Pity atual</span><input name="pityCounter" type="number" min="0" value="${Number(draftValue(draft, "pityCounter", character.pityCounter || 0))}" /></label>
            <label><span>Prestígio calculado automaticamente</span><input name="prestigeComputed" type="number" readonly value="${prestigeFor(character)}" /><small>Atualiza conforme nível, giros, raridades e PO registrados.</small></label>
            <label><span>Poder central</span><input value="1 slot fixo" readonly /><input name="powerSlots" type="hidden" value="1" /></label>
            <label><span>Raça</span><select name="raceId">${optionList(state.content.races, draftValue(draft, "raceId", character.raceId))}</select></label>
            <label><span>Classe</span><select name="classId">${optionList(state.content.classes, draftValue(draft, "classId", character.classId))}</select></label>
            <label><span>Afinidade</span><select name="affinityId">${affinityOptions}</select></label>
            <label><span>Perfil público</span><select name="profilePublic"><option value="true" ${draftValue(draft, "profilePublic", String(character.profilePublic !== false)) === "true" ? "selected" : ""}>Público</option><option value="false" ${draftValue(draft, "profilePublic", String(character.profilePublic !== false)) === "false" ? "selected" : ""}>Privado</option></select></label>
            <button class="primary-button wide" type="submit">Salvar alterações do player</button>
          </form>
          <section class="panel admin-progression-console" style="margin-top:18px">
            <div class="panel-heading"><div><p class="eyebrow">Evolução e correção</p><h3>Nível ${progressionFor(character).level} · ${progressionFor(character).progressXp}/${progressionFor(character).requiredXp} XP · ${Number(character.freePoints || 0)} ponto(s) livre(s)</h3></div><span class="tag">Auditoria obrigatória</span></div>
            <div class="action-row"><span class="tag">Redistribuição: ${esc(FOUNDATIONS.attributeRedistributionEligibility(character).used ? "concluída" : FOUNDATIONS.attributeRedistributionEligibility(character).eligible ? "disponível" : "não liberada")}</span><button class="ghost-button" type="button" data-action="release-attribute-redistribution" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || FOUNDATIONS.attributeRedistributionEligibility(character).used ? "disabled" : ""}>Liberar redistribuição única</button></div>
            <form class="form-grid" data-form="admin-progression-correction">
              <input type="hidden" name="uid" value="${esc(selectedId)}" />
              <label><span>Ajuste de XP</span><input name="xpDelta" type="number" step="1" value="0" /><small>Positivo adiciona XP e calcula níveis. Negativo corrige o total sem retirar níveis automaticamente.</small></label>
              <label><span>Definir nível final (opcional)</span><input name="levelOverride" type="number" min="1" max="${Number(state.settings.levelMax || 99)}" placeholder="Manter nível ${Number(character.level || 1)}" /></label>
              <label><span>Ajuste de pontos livres</span><input name="freePointsDelta" type="number" step="1" value="0" /><small>Use negativo para remover e positivo para devolver pontos.</small></label>
              <label><span>Atributo de desenvolvimento</span><select name="attributeKey"><option value="">Nenhum</option>${ATTRIBUTES.map((attribute) => `<option value="${attribute.key}">${esc(attribute.label)} (${esc(attribute.short)})</option>`).join("")}</select></label>
              <label><span>Ajuste no desenvolvimento</span><input name="attributeDelta" type="number" step="1" value="0" /><small>Adicionar consome pontos livres; remover devolve pontos.</small></label>
              <div></div>
              <label><span>Mover ponto-base de</span><select name="baseFrom"><option value="">Não corrigir base</option>${ATTRIBUTES.map((attribute) => `<option value="${attribute.key}">${esc(attribute.label)} (${Number(character.base?.[attribute.key] || 0)})</option>`).join("")}</select></label>
              <label><span>Para</span><select name="baseTo"><option value="">Escolha o destino</option>${ATTRIBUTES.map((attribute) => `<option value="${attribute.key}">${esc(attribute.label)}</option>`).join("")}</select></label>
              <label><span>Quantidade movida</span><input name="baseAmount" type="number" min="0" step="1" value="0" /></label>
              <label class="wide"><span>Motivo obrigatório</span><textarea name="reason" rows="4" maxlength="500" required placeholder="Explique a correção, a origem do XP ou a devolução de pontos."></textarea></label>
              <button class="primary-button wide" type="submit" ${selectedUser.role === "admin" || selectedId === state.user?.uid ? "disabled" : ""}>Aplicar correção auditada</button>
            </form>
          </section>
          <section class="account-management-grid ${state.adminOperationInProgress ? "operation-busy" : ""}" aria-label="Gestão administrativa da conta">
            <article class="account-management-card management">
              <p class="eyebrow">Gestão da ficha</p>
              <h3>Resetar ficha</h3>
              <p>Apaga o personagem e o progresso da ficha. A conta, o e-mail, a senha e as restrições são preservados.</p>
              <div class="action-row"><button class="warning-button" type="button" data-action="admin-reset-character" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || state.adminOperationInProgress ? "disabled" : ""}>↻ Resetar ficha</button></div>
            </article>
            <article class="account-management-card moderation">
              <p class="eyebrow">Moderação</p>
              <h3>Suspender ou banir</h3>
              <p>Bloqueia o acesso sem apagar ficha, inventário, mensagens ou progresso.</p>
              <div class="action-row">
                <button class="suspend-button" type="button" data-action="admin-suspend-account" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || state.adminOperationInProgress ? "disabled" : ""}>◷ Suspender acesso</button>
                <button class="danger-button" type="button" data-action="admin-ban-account" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || state.adminOperationInProgress ? "disabled" : ""}>⊘ Banir conta</button>
                <button class="unban-button" type="button" data-action="admin-remove-restriction" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || selectedStatus === "active" || state.adminOperationInProgress ? "disabled" : ""}>✓ Remover restrição</button>
              </div>
            </article>
            <article class="account-management-card danger">
              <p class="eyebrow">Zona perigosa</p>
              <h3>Excluir conta definitivamente</h3>
              <p>Remove os dados do Firestore. Para liberar o e-mail, a credencial ainda precisa ser apagada manualmente no Firebase Authentication.</p>
              <div class="action-row"><button class="delete-account-button" type="button" data-action="admin-delete-account" data-user-id="${esc(selectedId)}" ${selectedUser.role === "admin" || selectedId === state.user?.uid || state.adminOperationInProgress ? "disabled" : ""}>⚠ Excluir conta definitivamente</button></div>
            </article>
          </section>
          <section class="panel admin-stat-composition" style="margin-top:18px"><div class="panel-heading"><div><p class="eyebrow">Mesma leitura do player</p><h3>Composição oficial dos atributos</h3></div><span class="tag">Fonte única</span></div>${characterStatComposition(character)}</section>
          <div class="admin-attribute-diagnostic" style="margin-top:18px">${renderAttributeDiagnostic(character)}</div>
           <div class="grid" style="margin-top:18px">
            <div class="panel span-6">
              <p class="eyebrow">Adicionar item</p>
              <form class="form-stack" data-form="admin-add-item">
                <input type="hidden" name="uid" value="${esc(selectedId)}" />
                <select name="itemId">${optionList(state.content.items)}</select>
                <button class="primary-button" type="submit">Colocar item</button>
              </form>
            </div>
            <div class="panel span-6">
              <p class="eyebrow">Itens atuais</p>
              <div class="scroll-list">
                ${(character.inventory || []).map((item) => `
                  <div class="item-row">
                    <strong>${esc(item.name)}</strong>
                    <span>${esc(item.rarity || "Comum")}</span>
                    <button class="danger-button" type="button" data-action="admin-remove-item" data-user-id="${esc(selectedId)}" data-item-instance="${esc(item.instanceId || item.id)}">Remover</button>
                  </div>
                `).join("") || `<div class="empty-state">Sem itens.</div>`}
              </div>
             </div>
           </div>
           <div class="grid admin-vault-grid" style="margin-top:18px">
             <div class="panel span-7">
               <div class="panel-heading"><div><p class="eyebrow">Cofre dimensional</p><h3>Pets, itens e cosméticos invocados</h3></div><span class="tag">${(character.gachaVault || []).length} registro(s)</span></div>
               <div class="admin-vault-list">
                 ${(character.gachaVault || []).map((item) => `
                   <div class="admin-vault-row ${rarityClass(item.rarity)}">
                     <div><span>${esc(item.kind === "pet" ? "Pet" : "Item")} · ${esc(item.rarity || "Comum")}${item.shiny ? " · Radiante" : ""}</span><strong>${esc(item.name)}</strong><p>${"★".repeat(Math.max(1, Number(item.stars || 1)))} · ${esc(item.status || "Livre")} · Poder ${instancePower(item)}</p></div>
                     <div class="action-row">
                       <button class="ghost-button" type="button" data-action="admin-vault-star" data-user-id="${esc(selectedId)}" data-instance-id="${esc(item.instanceId)}" ${Number(item.stars || 1) >= MAX_GACHA_STARS ? "disabled" : ""}>+ estrela</button>
                       <button class="ghost-button" type="button" data-action="admin-vault-radiant" data-user-id="${esc(selectedId)}" data-instance-id="${esc(item.instanceId)}" ${item.shiny ? "disabled" : ""}>Radiante</button>
                       ${(item.status === "Ferido" || item.status === "Morto") ? `<button class="primary-button" type="button" data-action="admin-vault-heal" data-user-id="${esc(selectedId)}" data-instance-id="${esc(item.instanceId)}">Curar</button>` : ""}
                       <button class="danger-button" type="button" data-action="admin-vault-remove" data-user-id="${esc(selectedId)}" data-instance-id="${esc(item.instanceId)}">Remover</button>
                     </div>
                   </div>
                 `).join("") || `<div class="empty-state">Cofre vazio.</div>`}
               </div>
             </div>
             <div class="panel span-5">
               <div class="panel-heading"><div><p class="eyebrow">Atividades</p><h3>Incursões e descansos</h3></div></div>
               <div class="scroll-list">
                 ${(character.activeActivities || []).map((activity) => `<div class="item-row"><span>${esc(activity.type)} · ${esc(activity.difficultyName)}</span><strong>${esc(activity.petName)}</strong><p>${esc(activity.biome || activity.mapName || "Sem destino")}</p><button class="ghost-button" type="button" data-action="admin-clear-activity" data-user-id="${esc(selectedId)}" data-activity-id="${esc(activity.id)}">Liberar pet</button></div>`).join("") || `<div class="empty-state">Nenhuma atividade ativa.</div>`}
                 ${(character.gachaVault || []).filter((item) => item.status === "Ferido" || item.status === "Morto").map((item) => `<div class="item-row"><span>${esc(item.status)}</span><strong>${esc(item.name)}</strong><p>${item.status === "Morto" ? "Pet precisa de recuperação antes de voltar ao cofre." : "Pet ferido não pode entrar em uma incursão."}</p><button class="primary-button" type="button" data-action="admin-vault-heal" data-user-id="${esc(selectedId)}" data-instance-id="${esc(item.instanceId)}">Restaurar</button></div>`).join("")}
               </div>
             </div>
           </div>
         ` : `<div class="empty-state">Selecione um usuário.</div>`}
      </article>
    </div>
  `;
}

function renderAdminContent() {
  return `
    <div class="grid">
      <article class="panel span-12">
        <div class="tabs">
          ${[
            ["race", "Raças"],
            ["class", "Classes"],
            ["category", "Categorias de afinidade"],
            ["affinity", "Afinidades"],
            ["itemCategory", "Categorias de item"],
            ["item", "Itens"],
            ["biome", "Biomas"],
            ["kingdom", "Reinos"],
            ["region", "Regiões"],
            ["npc", "NPCs"],
            ["rules", "Regras"],
            ["faq", "FAQ"],
            ["tutorial", "Tutorial"],
            ["world", "Mundo e facções"],
            ["gacha", "Gacha e mapas"],
            ["epic", "Épicos"],
          ].map(([id, label]) => `<button class="tab ${state.contentTab === id ? "active" : ""}" type="button" data-action="content-tab" data-tab="${id}">${label}</button>`).join("")}
        </div>
      </article>
      ${renderContentEditor()}
    </div>
  `;
}

const VISUAL_FORGE_COLLECTIONS = new Set([
  "races", "classes", "affinityCategories", "affinities", "itemCategories", "items",
  "biomes", "kingdoms", "regions", "npcs", "rulesChapters", "faqEntries", "tutorialSteps",
  "gachaPets", "gachaItems", "gachaShardShops", "towerMaps", "gachaBanners",
  "marketListings", "auctionListings", "craftingRecipes", "worldLore", "worldEvents",
  "campaignPosts", "reputationFactions", "bestiary",
]);

function forgeBonusInputs(item = {}) {
  const bonus = item.bonus || {};
  return `
    <div class="forge-bonus-grid">
      ${ATTRIBUTES.map((attribute) => `<label><span>${attribute.short}</span><input name="bonus_${attribute.key}" type="number" value="${Number(bonus[attribute.key] || 0)}" /></label>`).join("")}
      <label><span>DEF</span><input name="bonus_def" type="number" value="${Number(bonus.def || 0)}" /></label>
    </div>
  `;
}

function forgeRaritySelect(value = "Comum") {
  return `<select name="rarity">${RARITIES.map((rarity) => `<option value="${rarity}" ${value === rarity ? "selected" : ""}>${rarity}</option>`).join("")}</select>`;
}

function forgeVisualFields(collection, item = {}) {
  if (collection === "races") {
    return `
      <label><span>Nome da raça</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Imagem da raça", item.imageUrl || "")}
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <label class="wide"><span>Passiva racial</span><textarea name="passive" rows="4">${esc(item.passive || "")}</textarea></label>
      <label class="wide"><span>Descrição e limites</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "classes") {
    return `
      <label><span>Nome da classe-base</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Imagem da classe", item.imageUrl || "")}
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <label class="wide"><span>Papel narrativo</span><textarea name="role" rows="3">${esc(item.role || "")}</textarea></label>
      <label class="wide"><span>Caminhos avançados</span><input name="paths" value="${esc(Array.isArray(item.paths) ? item.paths.join(", ") : item.paths || "")}" placeholder="Cavaleiro do Eclipse, Guardião do Véu..." /></label>
      <label class="wide"><span>Descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "affinityCategories") {
    return `
      <label><span>Nome da categoria</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Símbolo da categoria", item.imageUrl || "")}
      <label><span>Peso na roleta</span><input name="weight" type="number" min="0" step="0.1" value="${Number(item.weight || 0)}" /></label>
      <label><span>Raridade-base</span>${forgeRaritySelect(item.rarity || "Comum")}</label>
      <label><span>Cor ritual</span><input name="color" type="color" value="${esc(item.color || "#d8b45d")}" /></label>
      <label class="wide"><span>Regra e descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "affinities") {
    return `
      <label><span>Nome da afinidade</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Arte da afinidade", item.imageUrl || "")}
      <label><span>Categoria</span><select name="categoryId">${(state.content.affinityCategories || []).map((category) => `<option value="${esc(category.id)}" ${item.categoryId === category.id ? "selected" : ""}>${esc(category.name)}</option>`).join("")}</select></label>
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <label class="wide"><span>Domínio e passiva</span><textarea name="passive" rows="4">${esc(item.passive || "")}</textarea></label>
      <label class="wide"><span>Descrição, custo e limites</span><textarea name="description" rows="5">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "itemCategories") {
    return `<label><span>Nome da categoria</span><input name="name" value="${esc(item.name || "")}" required /></label>`;
  }
  if (collection === "items") {
    return `
      <label><span>Nome do item</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Imagem do item", item.imageUrl || "")}
      <label><span>Categoria</span><select name="categoryId">${(state.content.itemCategories || []).map((category) => `<option value="${esc(category.id)}" ${item.categoryId === category.id ? "selected" : ""}>${esc(category.name)}</option>`).join("")}</select></label>
      <label><span>Preço em PO</span><input name="price" type="number" min="0" value="${Number(item.price || 0)}" /></label>
      <label><span>Raridade</span>${forgeRaritySelect(item.rarity || "Comum")}</label>
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <label class="wide"><span>Descrição, tags e limites</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "biomes" || collection === "kingdoms" || collection === "regions" || collection === "npcs") {
    const label = collection === "biomes" ? "bioma" : collection === "kingdoms" ? "reino" : collection === "regions" ? "região" : "NPC";
    return `
      <label><span>Nome do ${label}</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", `Imagem do ${label}`, item.imageUrl || "")}
      ${collection === "biomes" ? `<label><span>Região maior</span><input name="region" value="${esc(item.region || "")}" /></label>` : ""}
      ${collection === "kingdoms" ? `<label><span>Governante</span><input name="ruler" value="${esc(item.ruler || "")}" /></label>` : ""}
      ${collection === "regions" ? `<label><span>Reino</span><select name="kingdomId"><option value="">Independente</option>${(state.content.kingdoms || []).map((kingdom) => `<option value="${esc(kingdom.id)}" ${item.kingdomId === kingdom.id ? "selected" : ""}>${esc(kingdom.name)}</option>`).join("")}</select></label>` : ""}
      ${collection === "npcs" ? `<label><span>Função</span><input name="role" value="${esc(item.role || "")}" /></label><label><span>Região</span><input name="region" value="${esc(item.region || "")}" /></label>` : ""}
      <label class="wide"><span>Descrição</span><textarea name="description" rows="6">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "rulesChapters") {
    return `<label><span>Título</span><input name="name" value="${esc(item.name || "")}" required /></label><label><span>Ordem</span><input name="order" type="number" min="1" value="${Number(item.order || 1)}" /></label><label class="wide"><span>Resumo</span><textarea name="summary" rows="3">${esc(item.summary || "")}</textarea></label><label class="wide"><span>Versão completa</span><textarea name="full" rows="8">${esc(item.full || "")}</textarea></label>`;
  }
  if (collection === "faqEntries") {
    return `<label><span>Pergunta</span><input name="name" value="${esc(item.name || "")}" required /></label><label><span>Categoria</span><input name="category" value="${esc(item.category || "FAQ")}" /></label><label class="wide"><span>Resposta</span><textarea name="answer" rows="7">${esc(item.answer || "")}</textarea></label>`;
  }
  if (collection === "tutorialSteps") {
    return `<label><span>Título da etapa</span><input name="name" value="${esc(item.name || "")}" required /></label><label><span>Ordem</span><input name="order" type="number" min="0" value="${Number(item.order || 0)}" /></label><label><span>Área de destino</span><input name="destination" value="${esc(item.destination || "")}" placeholder="Perfil, Codex, Missões..." /></label><label class="wide"><span>Descrição guiada</span><textarea name="description" rows="6">${esc(item.description || "")}</textarea></label><label class="wide"><span>Regra essencial</span><input name="rule" value="${esc(item.rule || "")}" /></label>`;
  }
  if (collection === "worldLore") {
    return `
      <label><span>Nome do registro</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Arte do registro", item.imageUrl || "")}
      <label><span>Era / categoria</span><input name="era" value="${esc(item.era || "")}" placeholder="Ex: Antes dos reinos" /></label>
      <label class="wide"><span>Resumo</span><textarea name="summary" rows="3">${esc(item.summary || "")}</textarea></label>
      <label class="wide"><span>Lore completa</span><textarea name="description" rows="7">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "reputationFactions") {
    return `
      <label><span>Nome da facção</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Brasão / arte da facção", item.imageUrl || "")}
      <label><span>Região</span><input name="region" value="${esc(item.region || "")}" /></label>
      <label><span>Níveis de reputação</span><input name="levels" value="${esc(item.levels || "Neutro, Aliado, Honrado")}" /></label>
      <label class="wide"><span>Descricao</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>
      <label class="wide"><span>Beneficios</span><textarea name="benefit" rows="3">${esc(item.benefit || "")}</textarea></label>
      <label class="wide"><span>Riscos</span><textarea name="risk" rows="3">${esc(item.risk || "")}</textarea></label>
      <label class="wide"><span>Frase da facção</span><input name="quote" value="${esc(item.quote || "")}" /></label>`;
  }
  if (collection === "worldEvents") {
    return `
      <label><span>Nome do evento</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Arte do evento", item.imageUrl || "")}
      <label><span>Estado</span><select name="status"><option value="Ativo" ${item.status === "Ativo" ? "selected" : ""}>Ativo</option><option value="Em breve" ${item.status === "Em breve" ? "selected" : ""}>Em breve</option><option value="Encerrado" ${item.status === "Encerrado" ? "selected" : ""}>Encerrado</option></select></label>
      <label><span>Raridade</span>${forgeRaritySelect(item.rarity || "Épico")}</label>
      <label><span>Mapa ligado</span><select name="mapId"><option value="">Mundo inteiro</option>${(state.content.towerMaps || []).map((map) => `<option value="${esc(map.id)}" ${item.mapId === map.id ? "selected" : ""}>${esc(map.name)}</option>`).join("")}</select></label>
      <label><span>Início</span><input name="startsAt" type="datetime-local" value="${esc(dateTimeLocalValue(item.startsAt))}" /></label>
      <label><span>Fim</span><input name="endsAt" type="datetime-local" value="${esc(dateTimeLocalValue(item.endsAt))}" /></label>
      <label class="wide"><span>Modificador de jogo</span><textarea name="modifier" rows="3">${esc(item.modifier || "")}</textarea></label>
      <label class="wide"><span>Recompensa</span><input name="reward" value="${esc(item.reward || "")}" /></label>
      <label class="wide"><span>Descrição narrativa</span><textarea name="description" rows="5">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "campaignPosts") {
    return `
      <label><span>Nome da fase / publicação</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Arte de divulgação", item.imageUrl || "")}
      <label><span>Canais</span><input name="channel" value="${esc(item.channel || "")}" placeholder="Discord, Reels, TikTok..." /></label>
      <label><span>Cadência</span><input name="cadence" value="${esc(item.cadence || "")}" placeholder="Ex: 3 dias antes" /></label>
      <label class="wide"><span>Chamada pronta</span><textarea name="cta" rows="3">${esc(item.cta || "")}</textarea></label>
      <label class="wide"><span>Plano da publicação</span><textarea name="description" rows="5">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "bestiary") {
    return `
      <label><span>Nome da criatura</span><input name="name" value="${esc(item.name || "")}" required /></label>
      ${mediaInput("imageUrl", "Arte da criatura", item.imageUrl || "")}
      <label><span>Raridade</span>${forgeRaritySelect(item.rarity || "Comum")}</label>
      <label><span>Região</span><input name="region" value="${esc(item.region || "")}" /></label>
      <label><span>Fraqueza</span><input name="weakness" value="${esc(item.weakness || "")}" /></label>
      <label><span>Drops</span><input name="drops" value="${esc(item.drops || "")}" /></label>
      <label class="wide"><span>Descrição</span><textarea name="description" rows="5">${esc(item.description || "")}</textarea></label>`;
  }
  const common = `
    <label><span>Nome</span><input name="name" value="${esc(item.name || "")}" required /></label>
    ${mediaInput("imageUrl", "Imagem exibida", item.imageUrl || "", { hint: "Anexe imagem, GIF ou cole um link. A prévia mostra o enquadramento usado no site." })}
    <label><span>Raridade</span>${forgeRaritySelect(item.rarity || "Comum")}</label>
  `;
  if (collection === "gachaPets") {
    return `${common}
      <label><span>Arquétipo</span><input name="archetype" value="${esc(item.archetype || "")}" placeholder="Ex: Guardião" /></label>
      <label><span>Elemento</span><input name="element" value="${esc(item.element || "")}" placeholder="Ex: Solar" /></label>
      <label class="wide"><span>Passiva / traço</span><textarea name="trait" rows="3">${esc(item.trait || "")}</textarea></label>
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <fieldset class="forge-fieldset wide"><legend>Tower Defense</legend><div class="forge-bonus-grid"><label><span>Dano</span><input name="td_damage" type="number" min="0" value="${Number(item.td?.damage || 10)}" /></label><label><span>Alcance</span><input name="td_range" type="number" min="0" value="${Number(item.td?.range || 80)}" /></label><label><span>Cooldown</span><input name="td_cooldown" type="number" min="0.1" step="0.1" value="${Number(item.td?.cooldown || 1.5)}" /></label></div></fieldset>
      <label class="wide"><span>Descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "gachaItems") {
    return `${common}
      <label><span>Categoria</span><select name="category"><option value="Equipamento" ${item.category === "Equipamento" ? "selected" : ""}>Equipamento</option><option value="Relíquia" ${item.category === "Relíquia" ? "selected" : ""}>Relíquia</option><option value="Cosmético" ${item.category === "Cosmético" ? "selected" : ""}>Cosmético</option><option value="Moldura" ${item.category === "Moldura" ? "selected" : ""}>Moldura</option><option value="Banner" ${item.category === "Banner" ? "selected" : ""}>Banner</option><option value="Artefato" ${item.category === "Artefato" ? "selected" : ""}>Artefato</option></select></label>
      <label class="wide"><span>Efeito no sistema</span><textarea name="effect" rows="3">${esc(item.effect || "")}</textarea></label>
      <fieldset class="forge-fieldset wide"><legend>Bônus de atributo</legend>${forgeBonusInputs(item)}</fieldset>
      <label class="wide"><span>Descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "gachaShardShops") {
    return `${common}
      <label><span>Moeda de fragmento</span><select name="shop"><option value="Fragmentos de Mira" ${item.shop === "Fragmentos de Mira" ? "selected" : ""}>Fragmentos de Mira</option><option value="Marcas de Caçada" ${item.shop === "Marcas de Caçada" ? "selected" : ""}>Marcas de Caçada</option><option value="Runas Partidas" ${item.shop === "Runas Partidas" ? "selected" : ""}>Runas Partidas</option><option value="Fragmentos do Despertar" ${item.shop === "Fragmentos do Despertar" ? "selected" : ""}>Fragmentos do Despertar</option></select></label>
      <label><span>Custo</span><input name="cost" type="number" min="1" value="${Number(item.cost || 100)}" /></label>
      <label><span>Entrega</span><select name="type"><option value="Cosmético" ${item.type === "Cosmético" ? "selected" : ""}>Cosmético</option><option value="Moldura" ${item.type === "Moldura" ? "selected" : ""}>Moldura</option><option value="Token" ${item.type === "Token" ? "selected" : ""}>Token</option><option value="Título" ${item.type === "Título" ? "selected" : ""}>Título</option><option value="Passe" ${item.type === "Passe" ? "selected" : ""}>Passe</option><option value="Item" ${item.type === "Item" ? "selected" : ""}>Item</option></select></label>
      <label class="wide"><span>Descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "towerMaps") {
    return `${common}
      <label><span>Tema do mapa</span><input name="theme" value="${esc(item.theme || "")}" placeholder="Ex: Cidade selada" /></label>
      <label><span>Rotas</span><input name="lanes" type="number" min="1" max="8" value="${Number(item.lanes || 3)}" /></label>
      <label><span>Espacos de torre</span><input name="slots" type="number" min="1" max="10" value="${Number(item.slots || 5)}" /></label>
      <label><span>Desenho da rota</span><select name="routeType"><option value="crossroads" ${item.routeType === "crossroads" ? "selected" : ""}>Cruzamento</option><option value="bridges" ${item.routeType === "bridges" ? "selected" : ""}>Pontes</option><option value="ring" ${item.routeType === "ring" ? "selected" : ""}>Circular</option><option value="portals" ${item.routeType === "portals" ? "selected" : ""}>Portais</option><option value="citadel" ${item.routeType === "citadel" ? "selected" : ""}>Cidadela</option><option value="marsh" ${item.routeType === "marsh" ? "selected" : ""}>Ilhas de pântano</option><option value="rails" ${item.routeType === "rails" ? "selected" : ""}>Trilhos industriais</option><option value="mirror" ${item.routeType === "mirror" ? "selected" : ""}>Rotas refletidas</option></select></label>
      <label><span>Faccao inimiga</span><input name="enemyFaction" value="${esc(item.enemyFaction || "")}" /></label>
      <label><span>Comportamento</span><select name="enemyTrait"><option value="split" ${item.enemyTrait === "split" ? "selected" : ""}>Divide ao morrer</option><option value="fast" ${item.enemyTrait === "fast" ? "selected" : ""}>Rapido</option><option value="armored" ${item.enemyTrait === "armored" ? "selected" : ""}>Blindado</option><option value="phase" ${item.enemyTrait === "phase" ? "selected" : ""}>Fase espiritual</option><option value="boss" ${item.enemyTrait === "boss" ? "selected" : ""}>Chefe</option></select></label>
      <label><span>Dificuldade indicada</span><select name="difficulty">${GACHA_DIFFICULTIES.map((difficulty) => `<option value="${difficulty.name}" ${item.difficulty === difficulty.name ? "selected" : ""}>${difficulty.name}</option>`).join("")}</select></label>
      <label class="wide"><span>Descrição do cenário</span><textarea name="description" rows="5">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "gachaBanners") {
    const type = item.type || "pets";
    const selected = new Set(Array.isArray(item.featuredIds) ? item.featuredIds : String(item.featuredIds || "").split(",").map((id) => id.trim()));
    const pool = type === "items" ? state.content.gachaItems : state.content.gachaPets;
    return `
      <label><span>Nome do banner</span><input name="name" value="${esc(item.name || "")}" required /></label>
      <label><span>Tipo</span><select name="bannerType"><option value="pets" ${type === "pets" ? "selected" : ""}>Pets</option><option value="items" ${type === "items" ? "selected" : ""}>Itens</option></select></label>
      <label><span>Estado</span><select name="enabled"><option value="true" ${item.enabled !== false ? "selected" : ""}>Ativo</option><option value="false" ${item.enabled === false ? "selected" : ""}>Pausado</option></select></label>
      <label><span>Rotação</span><select name="rotationMode"><option value="automatic" ${(item.rotationMode || "automatic") === "automatic" ? "selected" : ""}>Automática a cada hora</option><option value="fixed" ${item.rotationMode === "fixed" ? "selected" : ""}>Destaques fixos do Oráculo</option></select></label>
      <label><span>Início (opcional)</span><input name="startsAt" type="datetime-local" value="${esc(dateTimeLocalValue(item.startsAt))}" /></label>
      <label><span>Fim (opcional)</span><input name="endsAt" type="datetime-local" value="${esc(dateTimeLocalValue(item.endsAt))}" /></label>
      <fieldset class="forge-fieldset wide"><legend>Destaques em rate-up</legend><div class="forge-choice-grid">${pool.map((entry) => `<label><input data-featured-choice type="checkbox" value="${esc(entry.id)}" ${selected.has(entry.id) ? "checked" : ""} /> <span>${esc(entry.name)} · ${esc(entry.rarity)}</span></label>`).join("") || "<p>Cadastre pets ou itens antes de criar o banner.</p>"}</div></fieldset>
      <label class="wide"><span>Texto do banner</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  if (collection === "marketListings" || collection === "auctionListings" || collection === "craftingRecipes") {
    const auction = collection === "auctionListings";
    const crafting = collection === "craftingRecipes";
    return `${common}
      ${auction ? `<label><span>Lance mínimo (PO)</span><input name="minBid" type="number" min="0" value="${Number(item.minBid || 0)}" /></label><label><span>Encerra em</span><input name="endsAt" type="datetime-local" value="${esc(dateTimeLocalValue(item.endsAt))}" /></label>` : crafting ? `<label class="wide"><span>Materiais</span><input name="materials" value="${esc(item.materials || "")}" /></label><label class="wide"><span>Resultado</span><input name="result" value="${esc(item.result || "")}" /></label>` : `<label><span>Preço (PO)</span><input name="price" type="number" min="0" value="${Number(item.price || 0)}" /></label>`}
      <label class="wide"><span>Descrição</span><textarea name="description" rows="4">${esc(item.description || "")}</textarea></label>`;
  }
  return common;
}

function renderVisualForge(collection) {
  const labels = { gachaPets: "Pet de gacha", gachaItems: "Item de gacha", gachaShardShops: "Loja de fragmentos", towerMaps: "Mapa Tower Defense", gachaBanners: "Banner e rate-up", marketListings: "Oferta do mercado", auctionListings: "Leilão", craftingRecipes: "Receita de crafting", worldLore: "Registro de lore", worldEvents: "Evento mundial", campaignPosts: "Plano de divulgação", reputationFactions: "Facção e reputação", bestiary: "Criatura do bestiário" };
  return `
    <article class="panel span-5 forge-visual-panel">
      <p class="eyebrow">Forja visual</p>
      <h3>${esc(labels[collection] || "Novo conteúdo")}</h3>
      <p class="hint">Campos guiados: sem JSON, com imagem, prévia e parâmetros do sistema organizados.</p>
      <form class="form-stack" data-form="content-forge-visual">
        <input type="hidden" name="collection" value="${esc(collection)}" />
        ${forgeVisualFields(collection)}
        <button class="primary-button" type="submit">Criar na Forja</button>
      </form>
    </article>
    <article class="panel span-7">
      <div class="content-grid">${contentCards(state.content[collection] || [], (item) => `${item.rarity || item.theme || item.shop || ""} · ${item.description || item.trait || item.effect || item.result || ""}`, collection)}</div>
    </article>
  `;
}

function renderContentEditor() {
  const tab = state.contentTab;
  if (tab === "race") {
    return `
      <article class="panel span-5">${contentForm("content-race", "Nova raça", `
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem da raça")}
        <fieldset class="forge-fieldset"><legend>Bônus de atributo</legend>${forgeBonusInputs()}</fieldset>
        <label><span>Passiva</span><textarea name="passive" rows="4"></textarea></label>
        <label><span>Descrição</span><textarea name="description" rows="4"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.races, (item) => `${bonusToText(item.bonus)} · ${item.passive}`, "races")}</div></article>
    `;
  }
  if (tab === "class") {
    return `
      <article class="panel span-5">${contentForm("content-class", "Nova classe", `
        <p class="hint">Classes salvas aqui aparecem automaticamente no Codex, na criação de personagem, no painel do Oráculo e nos cálculos da ficha.</p>
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem da classe")}
        <fieldset class="forge-fieldset"><legend>Bônus de atributo</legend>${forgeBonusInputs()}</fieldset>
        <label><span>Papel e função</span><textarea name="role" rows="4" required></textarea></label>
        <label><span>Descrição</span><textarea name="description" rows="4" required></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.classes, (item) => `${bonusToText(item.bonus)} · ${item.role || "Sem função"} · ${classOwnerCount(item.id)} ficha(s)`, "classes")}</div></article>
    `;
  }
  if (tab === "category") {
    return `
      <article class="panel span-5">${contentForm("content-affinity-category", "Nova categoria", `
        <label><span>Nome</span><input name="name" required /></label>
        <label><span>Peso da roleta</span><input name="weight" type="number" min="0" value="10" required /></label>
        <label><span>Raridade</span><select name="rarity">${RARITIES.map((r) => `<option value="${r}">${r}</option>`).join("")}</select></label>
        <label><span>Cor</span><input name="color" value="#d8b45d" /></label>
        ${mediaInput("imageUrl", "Imagem da categoria")}
        <label><span>Descrição / regra de nerf</span><textarea name="description" rows="4"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.affinityCategories, (item) => `Peso ${item.weight} · ${item.rarity} · ${state.content.affinities.filter((affinity) => affinity.categoryId === item.id).length} afinidade(s) · ${categoryOwnerCount(item.id)} player(s)`, "affinityCategories")}</div></article>
    `;
  }
  if (tab === "affinity") {
    return `
      <article class="panel span-5">${contentForm("content-affinity", "Nova afinidade", `
        <label><span>Nome</span><input name="name" required /></label>
        <label><span>Categoria</span><select name="categoryId">${optionList(state.content.affinityCategories)}</select></label>
        ${mediaInput("imageUrl", "Imagem da afinidade")}
        <fieldset class="forge-fieldset"><legend>Bônus de atributo</legend>${forgeBonusInputs()}</fieldset>
        <label><span>Passiva</span><textarea name="passive" rows="4"></textarea></label>
        <label><span>Descrição / ajuste de balanceamento</span><textarea name="description" rows="4"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.affinities, (item) => `${getCategory(item.categoryId)?.name} · ${bonusToText(item.bonus)} · ${affinityOwnerCount(item.id)} player(s) · ${item.passive}`, "affinities")}</div></article>
    `;
  }
  if (tab === "itemCategory") {
    return `
      <article class="panel span-5">${contentForm("content-item-category", "Nova categoria de item", `<label><span>Nome</span><input name="name" required /></label>`)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.itemCategories, () => "Categoria de inventário", "itemCategories")}</div></article>
    `;
  }
  if (tab === "biome") {
    return `
      <article class="panel span-5">${contentForm("content-biome", "Novo bioma", `
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem do bioma")}
        <label><span>Região maior</span><input name="region" /></label>
        <label><span>Descrição</span><textarea name="description" rows="5"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.biomes, (item) => `${item.region || "Mundo"} · ${item.description || ""}`, "biomes")}</div></article>
    `;
  }
  if (tab === "kingdom") {
    return `
      <article class="panel span-5">${contentForm("content-kingdom", "Novo reino", `
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem do reino")}
        <label><span>Governante / facção</span><input name="ruler" /></label>
        <label><span>Descrição</span><textarea name="description" rows="5"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.kingdoms, (item) => `${item.ruler || "Sem governante"} · ${item.description || ""}`, "kingdoms")}</div></article>
    `;
  }
  if (tab === "region") {
    return `
      <article class="panel span-5">${contentForm("content-region", "Nova região", `
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem da região")}
        <label><span>Reino</span><select name="kingdomId"><option value="">Independente</option>${optionList(state.content.kingdoms)}</select></label>
        <label><span>Descrição</span><textarea name="description" rows="5"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.regions, (item) => `${state.content.kingdoms.find((kingdom) => kingdom.id === item.kingdomId)?.name || "Independente"} · ${item.description || ""}`, "regions")}</div></article>
    `;
  }
  if (tab === "npc") {
    return `
      <article class="panel span-5">${contentForm("content-npc", "Novo NPC importante", `
        <label><span>Nome</span><input name="name" required /></label>
        ${mediaInput("imageUrl", "Imagem do NPC")}
        <label><span>Função</span><input name="role" /></label>
        <label><span>Descrição</span><textarea name="description" rows="5"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.npcs, (item) => `${item.role || "NPC"} · ${item.description || ""}`, "npcs")}</div></article>
    `;
  }
  if (tab === "rules") {
    return `
      <article class="panel span-5">${contentForm("content-rule", "Novo capítulo de regra", `
        <label><span>Título</span><input name="name" required /></label>
        <label><span>Ordem</span><input name="order" type="number" value="1" /></label>
        <label><span>Resumo</span><textarea name="summary" rows="4"></textarea></label>
        <label><span>Versão completa</span><textarea name="full" rows="7"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.rulesChapters, (item) => `${item.summary || ""} ${item.full || ""}`, "rulesChapters")}</div></article>
    `;
  }
  if (tab === "faq") {
    return `
      <article class="panel span-5">${contentForm("content-faq", "Nova pergunta frequente", `
        <label><span>Pergunta</span><input name="name" required /></label>
        <label><span>Categoria</span><input name="category" /></label>
        <label><span>Resposta</span><textarea name="answer" rows="6"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.faqEntries, (item) => `${item.category || "FAQ"} · ${item.answer || ""}`, "faqEntries")}</div></article>
    `;
  }
  if (tab === "tutorial") {
    return `
      <article class="panel span-5">${contentForm("content-tutorial", "Novo passo de tutorial", `
        <label><span>Título</span><input name="name" required /></label>
        <label><span>Ordem</span><input name="order" type="number" value="1" /></label>
        <label><span>Descrição</span><textarea name="description" rows="6"></textarea></label>
      `)}</article>
      <article class="panel span-7"><div class="content-grid">${contentCards(state.content.tutorialSteps, (item) => `${item.order || 0} · ${item.description || ""}`, "tutorialSteps")}</div></article>
    `;
  }
  if (tab === "world") {
    const collections = [["worldLore", "Lore"], ["reputationFactions", "Facções"], ["worldEvents", "Eventos"], ["bestiary", "Bestiário"], ["campaignPosts", "Divulgação"]];
    const selected = collections.some(([id]) => id === state.epicCollection) ? state.epicCollection : "worldLore";
    return `
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Memória de Millennium</p><h3>Mundo, eventos e campanha sem JSON</h3></div><span class="tag">Codex em tempo real</span></div>
        <div class="tabs codex-tabs">${collections.map(([id, label]) => `<button class="tab ${selected === id ? "active" : ""}" type="button" data-action="epic-collection" data-collection="${id}">${label}</button>`).join("")}</div>
      </article>
      ${renderVisualForge(selected)}
    `;
  }
  if (tab === "gacha") {
    const collections = [
      ["gachaPets", "Pets"],
      ["gachaItems", "Itens"],
      ["gachaShardShops", "Fragmentos"],
      ["towerMaps", "Mapas Tower"],
      ["gachaBanners", "Banners"],
      ["marketListings", "Mercado"],
      ["auctionListings", "Leilão"],
      ["craftingRecipes", "Crafting"],
    ];
    const selected = collections.some(([id]) => id === state.epicCollection) ? state.epicCollection : "gachaPets";
    return `
      <article class="panel span-12">
        <div class="panel-heading"><div><p class="eyebrow">Sistemas de invocação</p><h3>Gacha, lojas, banners e mapas sem JSON</h3></div><span class="tag">Forja visual</span></div>
        <div class="tabs codex-tabs">${collections.map(([id, label]) => `<button class="tab ${selected === id ? "active" : ""}" type="button" data-action="epic-collection" data-collection="${id}">${label}</button>`).join("")}</div>
      </article>
      ${renderVisualForge(selected)}
    `;
  }
  if (tab === "epic") {
    const collections = [
      ["wantedBoard", "Quadro de procurados"],
      ["bestiary", "Bestiário"],
      ["marketListings", "Mercado"],
      ["auctionListings", "Leilão"],
      ["craftingRecipes", "Crafting"],
      ["techniqueLibrary", "Biblioteca de técnicas"],
      ["achievements", "Conquistas"],
      ["seasonPass", "Passe de temporada"],
      ["passMissions", "Missões do passe"],
      ["gachaPets", "Pets de gacha"],
      ["gachaItems", "Itens de gacha"],
      ["gachaShardShops", "Lojas de fragmentos"],
      ["towerMaps", "Mapas Tower Defense"],
      ["reputationFactions", "Reputações/facções"],
      ["worldEvents", "Eventos mundiais"],
      ["campaignPosts", "Plano de divulgação"],
    ];
    const selected = state.epicCollection || "wantedBoard";
    return `
      <article class="panel span-5">
        <p class="eyebrow">Forja épica</p>
        <h3>Criar qualquer módulo</h3>
        <form class="form-stack" data-form="content-generic">
          <label><span>Coleção</span><select name="collection">${collections.map(([id, label]) => `<option value="${id}" ${selected === id ? "selected" : ""}>${label}</option>`).join("")}</select></label>
          <label><span>JSON</span><textarea name="json" rows="14" required>{
  "name": "Novo registro",
  "rarity": "Comum",
  "description": "Descrição editável pelo Oráculo."
}</textarea></label>
          <button class="primary-button" type="submit">Salvar módulo</button>
        </form>
      </article>
      <article class="panel span-7">
        <div class="tabs codex-tabs">${collections.map(([id, label]) => `<button class="tab ${selected === id ? "active" : ""}" type="button" data-action="epic-collection" data-collection="${id}">${label}</button>`).join("")}</div>
        <div class="content-grid">${contentCards(state.content[selected] || [], (item) => `${item.rarity || item.category || item.region || ""} · ${item.description || item.reward || item.result || item.answer || ""}`, selected)}</div>
      </article>
    `;
  }
  return `
    <article class="panel span-5">${contentForm("content-item", "Novo item", `
      <label><span>Nome</span><input name="name" required /></label>
      <label><span>Categoria</span><select name="categoryId">${optionList(state.content.itemCategories)}</select></label>
      ${mediaInput("imageUrl", "Imagem do item")}
      <label><span>Preço</span><input name="price" type="number" value="0" /></label>
      <label><span>Raridade</span><select name="rarity">${RARITIES.map((r) => `<option value="${r}">${r}</option>`).join("")}</select></label>
      <fieldset class="forge-fieldset"><legend>Bônus de atributo</legend>${forgeBonusInputs()}</fieldset>
      <label><span>Descrição, tags e limites</span><textarea name="description" rows="4"></textarea></label>
    `)}</article>
    <article class="panel span-7"><div class="content-grid">${contentCards(state.content.items, (item) => `${item.rarity} · ${bonusToText(item.bonus)} · ${item.price || 0} PO`, "items")}</div></article>
  `;
}

function contentForm(formName, title, fields) {
  return `
    <p class="eyebrow">Adicionar pelo painel</p>
    <h3>${title}</h3>
    <form class="form-stack" data-form="${formName}">
      ${fields}
      <button class="primary-button" type="submit">Salvar</button>
    </form>
  `;
}

function contentCards(items, detail, collection = "") {
  if (!items.length) return `<div class="empty-state">Nada cadastrado.</div>`;
  return sortByName(items).map((item) => `
    <div class="content-card">
      ${item.imageUrl ? `<img class="content-image" src="${esc(item.imageUrl)}" alt="${esc(item.name || item.title || item.id)}" ${mediaAttrs("thumbnail")} />` : ""}
      <span>${esc(item.id)}</span>
      <h3>${esc(item.name || item.title || item.id)}</h3>
      <p>${esc(detail(item))}</p>
      ${collection ? `<div class="action-row"><button class="ghost-button" type="button" data-action="edit-content" data-collection="${esc(collection)}" data-id="${esc(item.id)}">Editar</button><button class="danger-button" type="button" data-action="delete-content" data-collection="${esc(collection)}" data-id="${esc(item.id)}">Excluir</button></div>` : ""}
    </div>
  `).join("");
}

