async function handleLogin(form) {
  const values = formValues(form);
  if (!state.firebaseReady) {
    setAuthNote("Firebase não carregou. Use o modo demo local.", "danger");
    toast("Firebase não carregou. Use o modo demo.");
    return;
  }
  setAuthNote("A Interface está verificando seu registro.", "neutral");
  await state.auth.signInWithEmailAndPassword(String(values.email || "").trim(), values.password);
}

async function handleRegister() {
  if (!state.firebaseReady) {
    setAuthNote("Firebase não carregou. A criação de conta real está indisponível nesta sessão.", "danger");
    toast("Firebase não carregou. Use o modo demo.");
    return;
  }
  const form = document.querySelector('[data-form="login"]');
  const values = formValues(form);
  if (!values.email || !values.password) {
    setAuthNote("Informe email e uma senha de pelo menos seis caracteres para criar a conta.", "danger");
    toast("Informe email e senha para criar conta.");
    return;
  }
  setAuthNote("Criando seu registro sem alterar o fluxo original do Firebase Auth.", "neutral");
  await state.auth.createUserWithEmailAndPassword(String(values.email).trim(), values.password);
}

async function handlePasswordRecovery() {
  if (!state.firebaseReady) {
    setAuthNote("Firebase Auth não carregou. A recuperação de senha está indisponível nesta sessão.", "danger");
    return;
  }
  const form = document.querySelector('[data-form="login"]');
  const email = String(formValues(form).email || "").trim();
  if (!email) {
    setAuthNote("Informe o email do registro antes de solicitar a recuperação.", "danger");
    form?.querySelector('[name="email"]')?.focus();
    return;
  }
  await state.auth.sendPasswordResetEmail(email);
  setAuthNote(`O Oráculo enviou as instruções de recuperação para ${email}.`, "success");
}

async function saveLegacyCharacter(form) {
  const values = formValues(form);
  const current = currentCharacter();
  const locked = current.creationLocked || Boolean(current.characterName && current.raceId && current.classId);
  if (locked) {
    toast("Atributos-base bloqueados não podem ser editados. Use Pontos de Desenvolvimento.");
    return;
  }

  const base = Object.fromEntries(ATTRIBUTES.map((attr) => [attr.key, Number(values[`base_${attr.key}`])]));
  const allocation = window.MILLENNIUM_CORE_31.validateBaseAllocation(base);
  if (!allocation.valid) {
    toast(allocation.errors[0] || "Distribua exatamente 20 pontos não negativos.");
    return;
  }

  await updateCharacter(state.user.uid, {
    playerName: values.playerName,
    displayName: values.playerName || state.profile?.displayName,
    characterName: values.characterName,
    characterAge: values.apparentAge === "" ? "" : Math.max(0, Number(values.apparentAge || 0)),
    characterDescription: values.characterDescription || "",
    pronouns: values.pronouns || "",
    originType: values.originType || "Retornado",
    apparentAge: values.apparentAge === "" ? "" : Math.max(0, Number(values.apparentAge || 0)),
    realAge: values.realAge === "" ? "" : Math.max(0, Number(values.realAge || 0)),
    culture: values.culture || "",
    kingdomId: values.kingdomId || "",
    profession: values.profession || "",
    objective: values.objective || "",
    fear: values.fear || "",
    playerLimits: values.playerLimits || "",
    currentLocation: values.currentLocation || "Limiar das Cortinas",
    avatarUrl: values.avatarUrl,
    bannerUrl: values.bannerUrl || "",
    avatarPosition: "center",
    bannerPosition: "center",
    avatarFocusX: Math.max(0, Math.min(100, Number(values.avatarFocusX || 50))),
    avatarFocusY: Math.max(0, Math.min(100, Number(values.avatarFocusY || 50))),
    avatarZoom: Math.max(1, Math.min(2.4, Number(values.avatarZoom || 1))),
    bannerFocusX: Math.max(0, Math.min(100, Number(values.bannerFocusX || 50))),
    bannerFocusY: Math.max(0, Math.min(100, Number(values.bannerFocusY || 50))),
    bannerZoom: Math.max(1, Math.min(2.4, Number(values.bannerZoom || 1))),
    raceId: values.raceId,
    classId: values.classId,
    creationLocked: true,
    creationStatus: "registered",
    technicalCreationComplete: true,
    attributeRulesVersion: 2,
    attributeRedistributionStatus: "not_required",
    attributeRedistributionUsed: false,
    base: allocation.normalized,
    story: values.story,
    personality: values.personality,
  });
  await writeDoc("users", state.user.uid, { displayName: values.playerName || state.profile?.displayName || state.user.email });
  state.characterDraft = null;
  toast("Ficha salva com a base protegida.");
}

