function monsterPowerForRankingProjection(character = currentCharacter()) {
  const api = monsterApi();
  const native = Array.isArray(character.monsterInstances) ? character.monsterInstances : [];
  if (!native.length || !api?.calculateMonsterStats) return petPowerForPrestige(character);
  const inventory = monsterItemsForCharacter(character);
  return native
    .map((entry) => api.normalizeMonsterInstance(entry))
    .reduce((sum, monster) => sum + Math.max(0, Number(api.calculateMonsterStats(monster, inventory).totalPower || 0)), 0);
}

function rankingProjection(character = currentCharacter()) {
  const level = Math.max(1, Number(character.level || 1), levelFromXp(character.xp || 0));
  const vault = character.gachaVault || [];
  const inventory = character.inventory || [];
  const ownerId = character.ownerId || state.user?.uid || "";
  const periods = ["daily", "weekly", "season", "all"];
  const periodCounts = (items, field = "createdAt") => Object.fromEntries(periods.map((period) => [
    period,
    items.filter((item) => period === "season" && !item?.[field] ? true : isWithinRankingRange(item, period, field)).length,
  ]));
  const periodBests = (items, mode) => Object.fromEntries(periods.map((period) => [
    period,
    Math.max(0, ...items.filter((item) => item.mode === mode && isWithinRankingRange(item, period)).map((item) => Number(item.score || 0))),
  ]));
  const rolls = [...(character.rollHistory || []), ...(character.gachaHistory || [])];
  const missions = (state.progressRequests || []).filter((request) => request.uid === ownerId && request.status === "aprovado" && ["mission", "guildMission", "training"].includes(request.type));
  const existingProjection = state.rankingProfiles.find((entry) => (entry.ownerId || entry.id) === ownerId) || {};
  const missionPeriods = periodCounts(missions, "reviewedAt");
  missionPeriods.all = Math.max(Number(missionPeriods.all || 0), Number(existingProjection.missions?.all || 0), Number(character.approvedMissionCount || 0));
  const views = (state.profileViews || []).filter((view) => view.targetId === ownerId);
  const invoked = [...vault, ...inventory.filter((item) => item.source === "Invocacao dimensional")];
  const secrets = invoked.filter((item) => rarityScore(item.rarity) >= rarityScore("Celestial"));
  const minigameHistory = character.minigameHistory || [];
  const projection = {
    ownerId,
    characterName: character.characterName || "",
    displayName: character.displayName || character.playerName || "Player",
    eligible: rankingEligible({ ...character, ownerId: character.ownerId || state.user?.uid }),
    level,
    xp: Math.max(0, Number(character.xp || 0)),
    gold: Math.max(0, Number(character.gold || 0)),
    coins: Math.max(0, Number(character.millenniumCoins || 0)),
    affinityId: character.affinityId || "",
    totalRares: Math.max(0, Number(character.totalRares || 0)),
    totalRolls: Math.max(0, Number(character.totalRolls || 0)),
    rolls: { ...periodCounts(rolls), all: Math.max(0, Number(character.totalRolls || rolls.length)) },
    missions: missionPeriods,
    minigameBest: Object.fromEntries(["aim", "hunt", "tower", "seals", "cartography", "alchemy"].map((mode) => {
      const best = periodBests(minigameHistory, mode);
      best.all = Math.max(best.all, Number(character.minigameStats?.[mode]?.bestScore || 0));
      best.season = Math.max(best.season, Number(character.minigameStats?.[mode]?.bestScore || 0));
      return [mode, best];
    })),
    views: periodCounts(views, "viewedAt"),
    petCount: monsterInstancesForCharacter(character).length,
    petPower: monsterPowerForRankingProjection(character),
    developmentPoints: ATTRIBUTES.reduce((sum, attribute) => sum + Math.max(0, Number(character.development?.[attribute.key] || 0)), 0),
    itemCount: inventory.length,
    passXp: Math.max(0, Number(character.seasonPassXp || 0)),
    premiumPassUnlocked: character.premiumPassUnlocked === true,
    achievementCount: derivedAchievementIds(character).size,
    collection: periodCounts(invoked, "obtainedAt"),
    secrets: periodCounts(secrets, "obtainedAt"),
    collectionCount: invoked.length,
    secretCount: secrets.length,
    powerCount: (character.powers || []).filter((item) => item?.name).length,
    techniqueCount: (character.techniques || []).filter((item) => item?.name).length,
  };
  projection.prestigeBreakdown = prestigeBreakdown({ ...projection, __rankingProjection: true });
  projection.prestige = projection.prestigeBreakdown.total;
  return projection;
}

function stableSerialize(value) {
  if (Array.isArray(value)) return `[${value.map(stableSerialize).join(",")}]`;
  if (value && typeof value === "object") {
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableSerialize(value[key])}`).join(",")}}`;
  }
  return JSON.stringify(value);
}

async function syncRankingProjection(character = currentCharacter()) {
  const uid = character.ownerId || state.user?.uid;
  if (!uid) return;
  const projection = rankingProjection({ ...character, ownerId: uid });
  const hash = stableSerialize(projection);
  if (uid === state.user?.uid && state.rankingProjectionHash === hash) return;
  const existing = state.rankingProfiles.find((entry) => (entry.ownerId || entry.id) === uid);
  if (existing) {
    const { id: _id, updatedAt: _updatedAt, ...comparable } = existing;
    if (stableSerialize(comparable) === hash) {
      if (uid === state.user?.uid) state.rankingProjectionHash = hash;
      return;
    }
  }
  if (state.demo) {
    state.rankingProfiles = state.rankingProfiles.filter((entry) => entry.id !== uid).concat({ id: uid, ...projection, updatedAt: new Date().toISOString() });
    if (uid === state.user?.uid) state.rankingProjectionHash = hash;
    return;
  }
  await state.db.collection("rankings").doc(uid).set({ ...projection, updatedAt: nowValue() });
  state.diagnostics.writes += 1;
  if (uid === state.user?.uid) state.rankingProjectionHash = hash;
}

async function rebuildRankingProjections() {
  if (state.role !== "admin") throw new Error("Apenas o Oráculo pode reconstruir o ranking.");
  const characters = (state.characters || []).filter((character) => character.ownerId || character.id);
  if (!characters.length) throw new Error("As fichas ainda estão carregando. Aguarde alguns segundos e tente novamente.");

  if (state.demo) {
    state.rankingProfiles = characters.map((character) => {
      const ownerId = character.ownerId || character.id;
      return { id: ownerId, ...rankingProjection({ ...character, ownerId }), updatedAt: new Date().toISOString() };
    }).filter((entry) => entry.eligible);
    scheduleRender({ route: state.view, preserveScroll: true });
    toast(`${state.rankingProfiles.length} ficha(s) reconstruída(s) no ranking demonstrativo.`);
    return;
  }

  const approvedMissionCountByOwner = new Map();
  const approvedSnapshot = await state.db.collection("progressRequests").where("status", "==", "aprovado").get();
  approvedSnapshot.forEach((document) => {
    const request = document.data() || {};
    if (!["mission", "guildMission", "training"].includes(request.type) || !request.uid) return;
    approvedMissionCountByOwner.set(request.uid, Number(approvedMissionCountByOwner.get(request.uid) || 0) + 1);
  });

  const batchSize = 400;
  let written = 0;
  for (let offset = 0; offset < characters.length; offset += batchSize) {
    const batch = state.db.batch();
    characters.slice(offset, offset + batchSize).forEach((character) => {
      const ownerId = character.ownerId || character.id;
      if (!ownerId) return;
      batch.set(state.db.collection("rankings").doc(ownerId), {
        ...rankingProjection({ ...character, ownerId, approvedMissionCount: approvedMissionCountByOwner.get(ownerId) || 0 }),
        updatedAt: nowValue(),
      });
      written += 1;
    });
    await batch.commit();
  }
  toast(`Ranking Spark reconstruído: ${written} ficha(s) processada(s).`);
}

function pickCharacterPatch(source, keys) {
  return Object.fromEntries(keys.filter((key) => source[key] !== undefined).map((key) => [key, source[key]]));
}

async function saveCharacterPatch(source, keys, options = {}) {
  const patch = pickCharacterPatch(source, keys);
  if (options.commit === false) return patch;
  await updateCharacter(options.uid || state.user.uid, patch);
  return patch;
}

function saveCharacterCorePatch(source, options = {}) {
  return saveCharacterPatch(source, ["playerName", "displayName", "characterName", "characterAge", "pronouns", "originType", "apparentAge", "realAge", "raceId", "classId"], options);
}

function saveCharacterOriginPatch(source, options = {}) {
  return saveCharacterPatch(source, ["kingdomId", "regionId", "cultureId", "culture", "professionId", "profession", "customCultureName", "customCultureSummary", "customProfessionName", "customProfessionSummary"], options);
}

function saveCharacterAttributesPatch(source, options = {}) {
  return saveCharacterPatch(source, ["base", "development", "freePoints"], options);
}

function saveCharacterMediaPatch(source, options = {}) {
  return saveCharacterPatch(source, ["avatarUrl", "bannerUrl", "characterDescription", "avatarPosition", "bannerPosition", "avatarFocusX", "avatarFocusY", "avatarZoom", "bannerFocusX", "bannerFocusY", "bannerZoom", "mediaFocus"], options);
}

function saveCharacterLocationPatch(source, options = {}) {
  return saveCharacterPatch(source, ["currentLocation", "physicalState", "essenceState"], options);
}

function saveCharacterStatePatch(source, options = {}) {
  return saveCharacterPatch(source, ["creationLocked", "creationStatus", "technicalCreationComplete", "narrativeCreationComplete", "attributeRulesVersion", "attributeRedistributionStatus", "attributeRedistributionUsed"], options);
}

async function saveCharacterLorePatch(source, options = {}) {
  const allowed = ["description", "personality", "virtues", "flaws", "habits", "beliefs", "history", "originWorld", "milestones", "importantPeople", "traumas", "secrets", "primaryGoal", "secondaryGoal", "fear", "desire", "internalConflict", "speech", "moralLimits", "initialRelations", "publicPhrase", "playerLimits", "warningThemes", "consentThemes", "forbiddenThemes", "progress"];
  const patch = pickCharacterPatch(source, allowed);
  if (options.commit === false) return patch;
  if (state.demo) {
    state.character = { ...currentCharacter(), lore: { ...(currentCharacter().lore || {}), ...patch }, narrativeCreationComplete: Number(patch.progress || 0) >= 100 };
    state.characters = state.characters.filter((item) => item.ownerId !== state.user.uid && item.id !== state.user.uid).concat(state.character);
    state.diagnostics.writes += 1;
    render();
    return patch;
  }
  const uid = options.uid || state.user.uid;
  await state.db.collection("characters").doc(uid).collection("lore").doc("main").set({ ...patch, updatedAt: nowValue() }, { merge: true });
  state.diagnostics.writes += 1;
  await updateCharacter(uid, { narrativeCreationComplete: Number(patch.progress || 0) >= 100 });
  await syncPublicProfileProjection({ ...currentCharacter(), ownerId: uid, narrativeCreationComplete: Number(patch.progress || 0) >= 100 }, { ...(state.characterLore || {}), ...patch });
  return patch;
}

function validateRegistrationStep(step, draft) {
  const required = (value) => Boolean(String(value ?? "").trim());
  if (step === 1) {
    if (!required(draft.playerName) || !required(draft.characterName)) return "Informe o nome do player e do personagem.";
    for (const key of ["apparentAge", "realAge"]) {
      if (draft[key] !== "" && (!Number.isInteger(Number(draft[key])) || Number(draft[key]) < 0)) return "Idades aceitam apenas números inteiros positivos.";
    }
  }
  if (step === 2 && !required(draft.raceId)) return "Escolha uma raça para continuar.";
  if (step === 3 && !required(draft.classId)) return "Escolha uma classe para continuar.";
  if (step === 4) {
    if (![draft.kingdomId, draft.regionId, draft.cultureId, draft.professionId].every(required)) return "Escolha reino, região, cultura e ofício.";
    if (draft.cultureId === "custom" && (!required(draft.customCultureName) || !required(draft.customCultureSummary))) return "Descreva a cultura personalizada.";
    if (draft.professionId === "custom" && (!required(draft.customProfessionName) || !required(draft.customProfessionSummary))) return "Descreva o ofício personalizado.";
  }
  if (step === 5) {
    const base = Object.fromEntries(ATTRIBUTES.map((attr) => [attr.key, Number(draft[`base_${attr.key}`])]));
    const allocation = window.MILLENNIUM_CORE_31.validateBaseAllocation(base);
    if (!allocation.valid) return allocation.errors[0] || "Distribua exatamente 20 pontos não negativos.";
  }
  return "";
}

function captureCharacterStep(form) {
  const values = form ? formValues(form) : {};
  state.characterDraft = { ...mergedCharacterDraft(currentCharacter()), ...values };
  if (form) saveLocalFormDraft(form);
  return state.characterDraft;
}

function moveCharacterStep(direction, form) {
  const draft = captureCharacterStep(form);
  if (direction > 0) {
    const error = validateRegistrationStep(state.characterStep, draft);
    if (error) {
      toast(error);
      form?.querySelector(":invalid")?.focus();
      return;
    }
  }
  state.characterStep = Math.max(1, Math.min(7, Number(state.characterStep || 1) + direction));
  scheduleRender({ critical: true, preserveScroll: false });
  window.scrollTo({ top: 0, behavior: "auto" });
}

function adjustRegistrationAttribute(attribute, delta, form) {
  if (!ATTRIBUTES.some((entry) => entry.key === attribute)) return;
  const draft = captureCharacterStep(form);
  const current = Math.max(0, Math.floor(Number(draft[`base_${attribute}`] ?? 4) || 0));
  const spent = ATTRIBUTES.reduce((sum, entry) => sum + Number(draft[`base_${entry.key}`] || 4), 0);
  if (delta > 0 && spent >= 20) return;
  if (delta < 0 && current <= 0) return;
  const next = current + Math.sign(delta);
  state.characterDraft[`base_${attribute}`] = next;
  const input = form?.elements?.namedItem?.(`base_${attribute}`);
  if (input) input.value = String(next);
  saveLocalFormDraft(form);
  scheduleRender({ critical: true, preserveScroll: true });
}

async function saveCharacter(form) {
  if (state.characterSaving || characterRegistrationLocked()) return;
  const values = captureCharacterStep(form);
  for (let step = 1; step <= 5; step += 1) {
    const error = validateRegistrationStep(step, values);
    if (error) {
      state.characterStep = step;
      toast(error);
      scheduleRender({ critical: true });
      return;
    }
  }
  const base = Object.fromEntries(ATTRIBUTES.map((attr) => [attr.key, Number(values[`base_${attr.key}`])]));
  const cultureEntry = characterCatalogEntry("cultures", values.cultureId);
  const professionEntry = characterCatalogEntry("professions", values.professionId);
  const normalized = {
    ...values,
    displayName: values.playerName || state.profile?.displayName || state.user.email,
    characterAge: values.apparentAge === "" ? "" : Number(values.apparentAge),
    apparentAge: values.apparentAge === "" ? "" : Number(values.apparentAge),
    realAge: values.realAge === "" ? "" : Number(values.realAge),
    culture: values.cultureId === "custom" ? `${values.customCultureName}: ${values.customCultureSummary}` : cultureEntry?.name || "",
    profession: values.professionId === "custom" ? `${values.customProfessionName}: ${values.customProfessionSummary}` : values.professionId === "none" ? "Sem ofício" : professionEntry?.name || "",
    currentLocation: values.currentLocation || characterCatalogEntry("regions", values.regionId)?.name || "Limiar das Cortinas",
    avatarUrl: values.avatarUrl || "",
    characterDescription: values.characterDescription || "",
    avatarPosition: "center",
    avatarFocusX: Math.max(0, Math.min(100, Number(values.avatarFocusX || 50))),
    avatarFocusY: Math.max(0, Math.min(100, Number(values.avatarFocusY || 50))),
    avatarZoom: Math.max(1, Math.min(2.4, Number(values.avatarZoom || 1))),
    base,
    creationLocked: true,
    creationStatus: "registered",
    technicalCreationComplete: true,
    attributeRulesVersion: 2,
    attributeRedistributionStatus: "not_required",
    attributeRedistributionUsed: false,
  };
  state.characterSaving = true;
  state.characterSaveStatus = "saving";
  scheduleRender({ critical: true, preserveScroll: true });
  try {
    const patch = {
      ...(await saveCharacterCorePatch(normalized, { commit: false })),
      ...(await saveCharacterOriginPatch(normalized, { commit: false })),
      ...(await saveCharacterAttributesPatch(normalized, { commit: false })),
      ...(await saveCharacterMediaPatch(normalized, { commit: false })),
      ...(await saveCharacterLocationPatch(normalized, { commit: false })),
      ...(await saveCharacterStatePatch(normalized, { commit: false })),
    };
    await updateCharacter(state.user.uid, patch);
    state.character = { ...currentCharacter(), ...patch, ownerId: state.user.uid };
    state.characterDraft = null;
    state.characterStep = 1;
    clearLocalFormDraft("character");
    state.characterSaveStatus = "saved";
    const secondary = await Promise.allSettled([
      writeDoc("users", state.user.uid, { displayName: normalized.displayName }),
      syncPublicProfileProjection({ ...state.character, ownerId: state.user.uid }),
    ]);
    const pending = secondary.filter((result) => result.status === "rejected").length;
    toast(pending ? `Ficha salva. ${pending} sincronização(ões) secundária(s) serão refeitas no próximo acesso.` : "Registro técnico concluído. Sua base agora está protegida.");
  } catch (error) {
    state.characterSaveStatus = "error";
    throw new Error(`A ficha não foi gravada. O rascunho foi preservado. ${firebaseErrorMessage(error)}`);
  } finally {
    state.characterSaving = false;
    scheduleRender({ critical: true });
  }
}

async function rollAffinity(qty = 1) {
  const character = currentCharacter();
  const amount = Math.max(1, Math.min(10, Number(qty || 1)));
  const attempts = Number(character.affinityAttempts ?? state.settings.defaultAffinityAttempts ?? 0);
  if (state.rolling) return;
  if (isCharacterBanned(character)) {
    toast("Esta ficha está bloqueada temporariamente pelo Oráculo.");
    return;
  }
  if (!state.content.affinities.length) {
    toast("Cadastre afinidades na Forja do Oráculo antes de girar.");
    return;
  }
  if (attempts < amount) {
    playSound("fail");
    toast(`Você precisa de ${amount} essência(s) para este giro.`);
    return;
  }

  state.rolling = true;
  state.lastRoll = null;
  state.lastRollResults = [];
  state.affinityChoices = [];
  render();
  playSound("rolling");

  const core = $("#rouletteCore");
  const coreText = core?.querySelector("strong") || core;
  const names = state.content.affinities.map((item) => item.name);
  let ticks = 0;
  const interval = window.setInterval(() => {
    ticks += 1;
    if (coreText) coreText.textContent = names[Math.floor(Math.random() * names.length)] || "?";
  }, amount > 1 ? 58 : 74);

  try {
    if (!state.demo && !MILLENNIUM_SPARK_MODE) {
      const server = await callTrustedOperation("affinity", { action: "roll", qty: amount });
      await delay(amount > 1 ? 3300 : 2200);
      window.clearInterval(interval);
      const results = Array.isArray(server?.results) ? server.results : [];
      if (!results.length) throw new Error("O servidor não retornou o resultado do giro.");
      const choices = (server.choices || []).map((choice) => ({ ...choice, bonus: bonusToText(choice.bonus || {}) }));
      const displayBest = results.slice().sort((a, b) => rarityScore(b.category?.rarity) - rarityScore(a.category?.rarity))[0];
      const chosen = results.find((item) => item.affinity?.id === server.chosenAffinityId)?.affinity || null;
      state.lastRoll = chosen || displayBest?.affinity || null;
      state.lastRollResults = results;
      state.affinityChoices = choices;
      if (results.some((item) => item.rare) || choices.some((choice) => isRareReward(choice.rarity))) playSound("rare");
      toast(choices.length ? "Giro concluído. Escolha uma das melhores afinidades reveladas." : `${results.length} giro(s) registrado(s) pelo Oráculo.`);
      openAffinityReveal(results, displayBest, choices.length > 0);
      return;
    }
    let pity = Number(character.pityCounter || 0);
    const results = [];
    for (let index = 0; index < amount; index += 1) {
      const result = buildRollResult(pity);
      if (result) {
        results.push(result);
        pity = result.pityAfter;
      }
    }

    await delay(amount > 1 ? 3300 : 2200);
    window.clearInterval(interval);

    if (!results.length) {
      playSound("fail");
      toast("Não encontrei afinidades para sortear.");
      return;
    }

    const rareResults = results.filter((result) => result.rare);
    const currentAffinity = getAffinity(character.affinityId);
    const currentCategory = currentAffinity ? getCategory(currentAffinity.categoryId) : null;
    const currentScore = currentAffinity ? rarityScore(currentCategory?.rarity) : 0;
    const bestScore = Math.max(...results.map((result) => rarityScore(result.category?.rarity)), currentScore);
    const bestResults = results
      .filter((result) => rarityScore(result.category?.rarity) === bestScore)
      .filter((result, index, list) => list.findIndex((item) => item.affinity.id === result.affinity.id) === index);
    const resultChoice = (result, current = false) => ({
      affinityId: result.affinity.id,
      name: result.affinity.name,
      categoryName: result.category?.name || "",
      rarity: result.category?.rarity || "Comum",
      bonus: bonusToText(result.affinity.bonus || {}),
      current,
    });
    const currentChoice = currentAffinity ? {
      affinityId: currentAffinity.id,
      name: currentAffinity.name,
      categoryName: currentCategory?.name || "",
      rarity: currentCategory?.rarity || "Comum",
      bonus: bonusToText(currentAffinity.bonus || {}),
      current: true,
    } : null;
    const hasNewBest = bestResults.some((result) => result.affinity.id !== currentAffinity?.id);
    const shouldChoose = amount >= 10 && bestScore >= currentScore && bestResults.length > 0
      && (bestResults.length > 1 || (currentChoice && bestScore === currentScore && hasNewBest));
    const choices = shouldChoose
      ? [
        ...(currentChoice && bestScore === currentScore ? [currentChoice] : []),
        ...bestResults.map((result) => resultChoice(result)).filter((choice) => choice.affinityId !== currentChoice?.affinityId),
      ]
      : [];
    const chosenResult = choices.length
      ? null
      : bestScore >= currentScore
        ? (bestResults.find((result) => result.affinity.id !== currentAffinity?.id) || bestResults[0] || null)
        : null;
    const displayBest = bestResults[0] || results.slice().sort((a, b) => rarityScore(b.category?.rarity) - rarityScore(a.category?.rarity))[0];
    const totalRolls = Number(character.totalRolls || 0) + results.length;
    const totalRares = Number(character.totalRares || 0) + rareResults.length;
    const level = Number(character.level || levelFromXp(character.xp || 0));
    const prestige = totalRolls * 10 + totalRares * 250 + level * 20 + Math.floor(Number(character.gold || 0) / 10);
    const history = [
      ...(character.rollHistory || []),
      ...results.map((result) => ({
        id: result.id,
        affinityId: result.affinity.id,
        affinityName: result.affinity.name,
        categoryId: result.category?.id || "",
        categoryName: result.category?.name || "",
        rarity: result.category?.rarity || "Comum",
        rare: result.rare,
        forced: result.forced,
        createdAt: result.createdAt,
      })),
    ].slice(-60);

    state.lastRoll = chosenResult?.affinity || displayBest.affinity;
    state.lastRollResults = results;
    state.affinityChoices = choices;

    const patch = {
      affinityAttempts: attempts - results.length,
      pityCounter: pity,
      totalRolls,
      totalRares,
      prestige,
      rollHistory: history,
    };
    if (chosenResult) {
      patch.affinityId = chosenResult.affinity.id;
      patch.affinitySnapshot = { ...chosenResult.affinity, categoryName: chosenResult.category?.name || "", rarity: chosenResult.category?.rarity || "" };
    }
    await updateCharacter(state.user.uid, patch);

    if (chosenResult && isRareReward(chosenResult.category?.rarity)) {
      playSound("rare");
      await announceRareReward(state.user.uid, chosenResult.affinity.name, chosenResult.category?.rarity, "afinidade");
    } else if (rareResults.length || choices.some((choice) => isRareReward(choice.rarity))) {
      playSound("rare");
    }

    if (choices.length) {
      toast("Giro 10x concluído. Escolha qual afinidade da melhor raridade ficará na ficha.");
    } else if (chosenResult) {
      toast(`${results.length} giro(s): afinidade definida como ${chosenResult.affinity.name} (${chosenResult.category?.rarity || "Comum"}).`);
    } else {
      toast(`${results.length} giro(s): ${displayBest.affinity.name} saiu, mas sua afinidade atual é mais rara e foi mantida.`);
    }
    openAffinityReveal(results, displayBest, choices.length > 0);
  } catch (error) {
    state.lastRoll = null;
    state.lastRollResults = [];
    state.affinityChoices = [];
    playSound("fail");
    toast(error?.message?.includes("permission")
      ? "O Firestore recusou o giro. Nenhuma essência foi consumida e nenhuma afinidade foi aplicada."
      : "Não foi possível concluir o giro. Atualize a página e tente novamente.");
  } finally {
    window.clearInterval(interval);
    state.rolling = false;
    render();
  }
}

function openAffinityReveal(results = [], bestResult = null, needsChoice = false) {
  const highest = bestResult || results.slice().sort((a, b) => rarityScore(b.category?.rarity) - rarityScore(a.category?.rarity))[0];
  const great = rarityScore(highest?.category?.rarity) >= rarityScore("Épico");
  $("#modalContent").innerHTML = `
    <section class="affinity-reveal ${great ? "great-reveal" : ""}">
      <div class="affinity-reveal-runes" aria-hidden="true"></div>
      <p class="eyebrow">Leitura do Oráculo</p>
      <h2>${great ? "A realidade respondeu." : "A essência encontrou um caminho."}</h2>
      <p>${needsChoice ? "Ecos da mesma raridade exigem uma escolha." : "A melhor afinidade foi preservada pela interface."}</p>
      <div class="affinity-reveal-list ${results.length > 1 ? "tenfold" : ""}">
        ${results.map((result, index) => `
          <article class="affinity-reveal-card ${rarityClass(result.category?.rarity)}" style="--reveal-delay:${index * 120}ms">
            <span>${esc(result.category?.rarity || "Comum")}</span>
            <strong>${esc(result.affinity?.name || "Afinidade")}</strong>
            <small>${esc(result.category?.name || "Categoria")} · ${esc(bonusToText(result.affinity?.bonus || {}))}</small>
          </article>
        `).join("")}
      </div>
      <div class="gacha-reveal-footer"><span>${needsChoice ? "Abra a escolha no painel da roleta ao continuar." : `${esc(highest?.affinity?.name || "Afinidade")} deixou sua marca.`}</span><button class="primary-button intense" type="button" data-action="close-modal">Continuar</button></div>
    </section>
  `;
  $("#modal").hidden = false;
  (state.gachaRevealTimers || []).forEach((timer) => window.clearTimeout(timer));
  state.gachaRevealTimers = results.map((result, index) => window.setTimeout(() => playSound(rarityScore(result.category?.rarity) >= rarityScore("Mítico") ? "legendary" : rarityScore(result.category?.rarity) >= rarityScore("Raro") ? "rare" : "common"), 240 + index * 130));
}

async function chooseAffinity(affinityId) {
  const choices = state.affinityChoices || [];
  const choice = choices.find((item) => item.affinityId === affinityId);
  if (!choice) return;
  if (choice.current) {
    if (!state.demo && !MILLENNIUM_SPARK_MODE) await callTrustedOperation("affinity", { action: "choose", affinityId });
    state.affinityChoices = [];
    toast("Afinidade atual mantida.");
    render();
    return;
  }
  const affinity = getAffinity(affinityId);
  if (!affinity) return;
  const category = getCategory(affinity.categoryId);
  const affinityPatch = {
    affinityId: affinity.id,
    affinitySnapshot: { ...affinity, categoryName: category?.name || "", rarity: category?.rarity || "" },
  };
  if (!state.demo && !MILLENNIUM_SPARK_MODE) await callTrustedOperation("affinity", { action: "choose", affinityId });
  else await updateCharacter(state.user.uid, affinityPatch);
  await syncPublicProfileProjection({ ...currentCharacter(), ...affinityPatch });
  state.affinityChoices = [];
  state.lastRoll = affinity;
  if (isRareReward(category?.rarity)) {
    playSound("rare");
    await announceRareReward(state.user.uid, affinity.name, category?.rarity, "afinidade");
  }
  toast(`Afinidade escolhida: ${affinity.name}.`);
  render();
}

async function toggleProfilePublic() {
  const character = currentCharacter();
  const patch = { profilePublic: !character.profilePublic };
  await updateCharacter(state.user.uid, patch);
  await syncPublicProfileProjection({ ...character, ...patch });
}

async function joinFaction(form) {
  if (!state.settings.factionsUnlocked) {
    toast("Os juramentos de facção ainda não foram abertos nesta temporada.");
    return;
  }
  const character = currentCharacter();
  if (character.factionId) {
    toast("Seu juramento já foi registrado. Apenas o Oráculo pode alterá-lo.");
    return;
  }
  const values = formValues(form);
  const faction = getFaction(values.factionId);
  if (!faction) {
    toast("Escolha uma facção válida.");
    return;
  }
  await updateCharacter(state.user.uid, {
    factionId: faction.id,
    factionReputation: 0,
    factionJoinedAt: new Date().toISOString(),
  });
  toast(`Juramento selado com ${faction.name}.`);
}

async function equipTitle(titleId) {
  const character = currentCharacter();
  const removing = character.activeTitleId === titleId;
  const exists = (character.titles || []).some((title) => (title.id || slug(title.name)) === titleId);
  if (!removing && !exists) throw new Error("Título não encontrado na ficha.");
  await updateCharacter(state.user.uid, { activeTitleId: removing ? "" : titleId });
  toast(removing ? "Título removido do perfil." : "Título equipado.");
}

async function claimPendingGift() {
  const character = currentCharacter();
  const gift = character.pendingGift;
  if (!gift || typeof gift !== "object") {
    toast("Nenhum presente disponível para resgate.");
    return;
  }
  const giftId = String(gift.id || gift.receiptId || `gift:${gift.createdAt || gift.sentAt || JSON.stringify(gift)}`);
  const claimKeys = [...new Set(character.giftClaimKeys || [])].slice(-79);
  if (claimKeys.includes(giftId)) {
    toast("Este presente já foi confirmado.");
    return;
  }
  await updateCharacter(state.user.uid, {
    pendingGift: null,
    giftClaimKeys: [...claimKeys, giftId],
    giftHistory: [{ ...gift, id: giftId, claimedAt: new Date().toISOString(), status: "claimed" }, ...(character.giftHistory || [])].slice(0, 40),
  });
  toast("Presente confirmado e arquivado no correio.");
}

async function toggleEquip(instanceId) {
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    await callTrustedOperation("inventory", { action: "equip", instanceId });
    return;
  }
  const character = currentCharacter();
  const target = (character.inventory || []).find((item) => (item.instanceId || item.id) === instanceId);
  const targetText = normalize(`${target?.category || ""} ${target?.categoryId || ""} ${target?.name || ""}`);
  const cosmeticGroup = /moldura|aura|perfil/.test(targetText) ? "frame" : /banner/.test(targetText) ? "banner" : "";
  const inventory = (character.inventory || []).map((item) => {
    const id = item.instanceId || item.id;
    if (id === instanceId) return { ...item, equipped: !item.equipped };
    if (!target?.equipped && cosmeticGroup) {
      const text = normalize(`${item.category || ""} ${item.categoryId || ""} ${item.name || ""}`);
      const group = /moldura|aura|perfil/.test(text) ? "frame" : /banner/.test(text) ? "banner" : "";
      if (group === cosmeticGroup) return { ...item, equipped: false };
    }
    return item;
  });
  await updateCharacter(state.user.uid, { inventory });
}

async function invokeGacha(type = "monsters", qty = 1) {
  const api = monsterApi();
  const character = currentCharacter();
  const amount = Math.max(1, Math.min(10, Number(qty || 1)));
  const cost = gachaCost("monsters", amount);
  if (state.rolling) return;
  if (Number(character.millenniumCoins || 0) < cost) {
    toast("Millennium Coins insuficientes para esta invocação.");
    return;
  }
  state.rolling = true;
  state.lastGachaResults = [];
  render();
  playSound("rolling");
  try {
    await delay(amount >= 10 ? 1100 : 780);
    const seed = `${state.user?.uid || "local"}:${Date.now()}:${(character.monsterGachaHistory || []).length}:${amount}`;
    const invocation = api.rollMonsterInvocation({
      quantity: amount,
      seed,
      pity: Number(character.monsterGachaPity?.rareMonster || 0),
      pityMax: Number(state.settings.pityMax || character.monsterGachaPity?.max || api.monsterPityMax || 30),
    });
    const owned = new Set(monsterInstancesForCharacter(character).map((entry) => entry.speciesId));
    const results = invocation.rewards.map((reward) => {
      const duplicate = reward.category === "monster" && owned.has(reward.speciesId);
      if (reward.category === "monster" && !duplicate) owned.add(reward.speciesId);
      return { ...reward, duplicate };
    });
    const applied = api.applyInvocationRewards(character, { ...invocation, rewards: results }, { cost });
    if (!applied.ok) throw new Error(applied.reason || "A economia recusou a invocação.");

    await updateCharacter(state.user.uid, applied.patch, { securityAction: `monster-gacha-${amount}x` });
    state.lastGachaResults = results;
    const rare = results.find((item) => item.category === "monster" && (rarityScore(item.rarity) >= rarityScore("Mítico") || item.shiny));
    if (rare) announceRareReward(state.user.uid, rare.name, rare.rarity, "Monstro Vinculado").catch(() => {});
    render();
    openGachaReveal(results, "monsters", applied.summary);
  } catch (error) {
    state.lastGachaResults = [];
    state.diagnostics.lastGachaError = String(error?.code || error?.message || "erro desconhecido").slice(0, 300);
    console.error("Falha na Invocação dos Monstros:", error);
    playSound("fail");
    if (error?.code === "millennium/security-quarantine") toast(error.message);
    else if (error?.code === "permission-denied" || String(error?.message || "").toLowerCase().includes("permission")) toast("O Firestore recusou a invocação. Nenhuma moeda foi consumida e nenhum prêmio foi entregue.");
    else toast(`A invocação não foi concluída. Seu saldo permanece preservado. ${firebaseErrorMessage(error)}`);
  } finally {
    state.rolling = false;
    if (document.querySelector("#modal")?.hidden !== false) render();
  }
}

function gachaRevealSound(item) {
  const score = rarityScore(item?.rarity || "Quebrado");
  if (score >= rarityScore("Celestial") || item?.shiny) return "secret";
  if (score >= rarityScore("Mítico")) return "legendary";
  if (score >= rarityScore("Épico")) return "rare";
  return "common";
}

function openGachaReveal(results, kind = "monsters", summary = {}) {
  const rarest = [...results].sort((a, b) => rarityScore(b.rarity) - rarityScore(a.rarity))[0];
  const isGreat = rarest && (rarityScore(rarest.rarity) >= rarityScore("Mítico") || rarest.shiny);
  $("#modalContent").innerHTML = `<section class="gacha-reveal ${isGreat ? "great-reveal" : ""}"><div class="gacha-reveal-sky" aria-hidden="true"></div><p class="eyebrow">Invocação dos Monstros</p><h2>${isGreat ? "O portal respondeu com força." : "O vínculo deixou novos ecos."}</h2><p class="gacha-reveal-copy">Monstros novos entram no bestiário. Duplicatas viram fragmentos. Itens e recursos seguem para o inventário exclusivo.</p><div class="gacha-reveal-results ${results.length > 1 ? "tenfold" : ""}">${results.map((item, index) => { const image = item.image || (item.category === "monster" ? monsterApi().assetBundleForSpecies(item.speciesId).thumbnail : ""); return `<article class="gacha-reveal-card ${rarityClass(item.rarity)} ${item.shiny ? "shiny" : ""}" data-reveal-index="${index}"><div class="gacha-card-veil"></div><div class="gacha-reveal-art">${image ? `<img src="${esc(image)}" alt="${esc(item.name)}" />` : `<span>${esc((item.name || "M").slice(0, 1))}</span>`}</div><small>${esc(item.rarity)} · ${esc(item.category)}${item.forced ? " · garantia" : ""}</small><strong>${esc(item.name)}</strong><p>${esc(item.duplicate ? `Duplicata convertida · ${monsterApi().duplicateFragments[item.rarity] || 10} fragmentos` : monsterInvocationResultDescription(item))}</p></article>`; }).join("")}</div><div class="monster-economy-summary" style="margin-top:1rem"><div><small>Novas espécies</small><strong>${Number(summary.newMonsters || 0)}</strong></div><div><small>Duplicatas</small><strong>${Number(summary.duplicates || 0)}</strong></div><div><small>Fragmentos</small><strong>${Number(summary.fragments || 0)}</strong></div><div><small>Itens</small><strong>${Number(summary.items || 0)}</strong></div><div><small>PO</small><strong>+${Number(summary.gold || 0)}</strong></div><div><small>MC devolvidas</small><strong>+${Number(summary.coins || 0)}</strong></div></div><div class="gacha-reveal-footer"><span>A operação foi persistida em um único patch econômico antes desta revelação.</span><button class="primary-button intense" type="button" data-action="close-modal">Continuar</button></div></section>`;
  $("#modal").hidden = false;
  (state.gachaRevealTimers || []).forEach((timer) => window.clearTimeout(timer));
  state.gachaRevealTimers = results.map((item, index) => window.setTimeout(() => { const card = document.querySelector(`[data-reveal-index="${index}"]`); if (!card) return; card.classList.add("revealed"); playSound(gachaRevealSound(item)); }, 220 + index * (results.length > 1 ? 150 : 0)));
}

async function toggleVaultEquip(instanceId) {
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    await callTrustedOperation("inventory", { action: "vault-toggle", instanceId });
    return;
  }
  const character = currentCharacter();
  const vault = (character.gachaVault || []).map((item) => {
    if (item.instanceId !== instanceId || petBusy(item)) return item;
    return { ...item, equipped: !item.equipped, status: item.equipped ? "Livre" : "Equipado" };
  });
  await updateCharacter(state.user.uid, { gachaVault: vault });
}

async function fuseVaultItem(instanceId) {
  const character = currentCharacter();
  const vault = [...(character.gachaVault || [])];
  const item = vault.find((entry) => entry.instanceId === instanceId);
  if (!item) return;
  if (item.locked || item.equipped || petBusy(item)) {
    toast("Desbloqueie, desequipe e deixe o companheiro livre antes da fusão.");
    return;
  }
  if (Number(item.stars || 1) >= MAX_GACHA_STARS) {
    toast("Este registro já está no máximo de estrelas.");
    return;
  }
  const identity = normalize(item.sourceId || item.baseName || item.name);
  const duplicate = vault.find((entry) => entry.instanceId !== instanceId
    && normalize(entry.sourceId || entry.baseName || entry.name) === identity
    && entry.kind === item.kind
    && rarityKey(entry.rarity) === rarityKey(item.rarity)
    && Number(entry.stars || 1) === Number(item.stars || 1)
    && Boolean(entry.shiny) === Boolean(item.shiny)
    && !entry.locked
    && !entry.equipped
    && !petBusy(entry));
  if (!duplicate) {
    toast(`Você precisa de outro ${item.baseName || item.name} com ${Number(item.stars || 1)} estrela(s) e a mesma raridade.`);
    return;
  }
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const result = await callTrustedOperation("inventory", { action: "fuse", instanceId });
    toast(`${item.name} subiu para ${Number(result?.stars || Number(item.stars || 1) + 1)} estrela(s).`);
    return;
  }
  const next = vault
    .filter((entry) => entry.instanceId !== duplicate.instanceId)
    .map((entry) => entry.instanceId === instanceId ? { ...entry, stars: Math.min(MAX_GACHA_STARS, Number(entry.stars || 1) + 1) } : entry);
  await updateCharacter(state.user.uid, { gachaVault: next });
  toast(`${item.name} subiu para ${Number(item.stars || 1) + 1} estrela(s).`);
}

async function shardVaultItem(instanceId) {
  const character = currentCharacter();
  const item = (character.gachaVault || []).find((entry) => entry.instanceId === instanceId);
  if (!item || item.locked || petBusy(item)) return;
  const fragmentName = gachaFragmentName(item);
  const amount = fragmentGainFor(item);
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const result = await callTrustedOperation("inventory", { action: "shard", instanceId });
    toast(`${result?.name || item.name} virou ${Number(result?.amount || amount)} ${result?.fragmentName || fragmentName}.`);
    return;
  }
  await updateCharacter(state.user.uid, {
    gachaVault: (character.gachaVault || []).filter((entry) => entry.instanceId !== instanceId),
    gachaFragments: withFragments(character, fragmentName, amount),
  });
  toast(`${item.name} virou ${amount} ${fragmentName}.`);
}

async function sendVaultMain(instanceId) {
  const character = currentCharacter();
  const item = (character.gachaVault || []).find((entry) => entry.instanceId === instanceId);
  if (!item) return;
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const result = await callTrustedOperation("inventory", { action: "export", instanceId });
    toast(result?.kind === "pet" ? "Pet enviado para a vitrine do perfil." : "Item enviado para o inventário principal.");
    return;
  }
  const vault = (character.gachaVault || []).map((entry) => entry.instanceId === instanceId ? { ...entry, exported: true } : entry);
  if (item.kind === "pet") {
    await updateCharacter(state.user.uid, {
      pets: [...(character.pets || []), { ...item, id: item.instanceId, source: "Cofre dimensional" }],
      gachaVault: vault,
    });
    toast("Pet enviado para a vitrine do perfil.");
    return;
  }
  await updateCharacter(state.user.uid, {
    inventory: [...(character.inventory || []), {
      ...item,
      instanceId: cryptoRandom(),
      categoryId: "especial",
      source: "Cofre dimensional",
      equipped: false,
    }],
    gachaVault: vault,
  });
  toast("Item enviado para o inventário principal.");
}

async function recoverPet(instanceId) {
  const character = currentCharacter();
  const item = (character.gachaVault || []).find((entry) => entry.instanceId === instanceId && entry.kind === "pet");
  const cost = petRecoveryCost(item);
  if (!item || !cost) return;
  if (Number(character.millenniumCoins || 0) < cost) {
    toast(`Você precisa de ${cost} Millennium Coins para recuperar este pet.`);
    return;
  }
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const result = await callTrustedOperation("inventory", { action: "recover", instanceId });
    toast(`${result?.name || item.name} voltou a ficar livre por ${Number(result?.cost || cost)} Millennium Coins.`);
    return;
  }
  const vault = (character.gachaVault || []).map((entry) => entry.instanceId === instanceId
    ? { ...entry, status: "Livre", activityId: "", injuredAt: "", recoveredAt: new Date().toISOString() }
    : entry);
  await updateCharacter(state.user.uid, {
    millenniumCoins: Number(character.millenniumCoins || 0) - cost,
    gachaVault: vault,
  });
  toast(`${item.name} voltou a ficar livre.`);
}

async function redeemShardShop(shopId) {
  const character = currentCharacter();
  const shopItem = (state.content.gachaShardShops || []).find((item) => item.id === shopId);
  if (!shopItem) return;
  const fragmentName = shopItem.shop || "Fragmentos do Despertar";
  const cost = Number(shopItem.cost || 0);
  const balance = Number(character.gachaFragments?.[fragmentName] || 0);
  if (balance < cost) {
    toast(`Você precisa de ${cost} ${fragmentName}.`);
    return;
  }
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const result = await callTrustedOperation("inventory", { action: "redeem", shopId });
    toast(`${result?.name || shopItem.name} resgatado.`);
    return;
  }
  const fragments = { ...(character.gachaFragments || {}), [fragmentName]: balance - cost };
  const rewardType = String(shopItem.type || "").toLowerCase();
  const patch = {
    gachaFragments: fragments,
    shopHistory: [
      {
        id: cryptoRandom(),
        name: shopItem.name,
        shop: fragmentName,
        cost,
        type: shopItem.type || "Recompensa",
        createdAt: new Date().toISOString(),
      },
      ...(character.shopHistory || []),
    ].slice(0, 30),
  };
  if (rewardType.includes("passe")) {
    patch.premiumPassUnlocked = true;
  } else if (rewardType.includes("título") || rewardType.includes("titulo")) {
    patch.titles = [...(character.titles || []), { id: cryptoRandom(), name: shopItem.name, rarity: shopItem.rarity || "Comum", description: shopItem.description || "Obtido na loja de fragmentos." }];
  } else if (rewardType.includes("token")) {
    patch.tokens = [...(character.tokens || []), { id: cryptoRandom(), name: shopItem.name, rarity: shopItem.rarity || "Comum", description: shopItem.description || "Obtido na loja de fragmentos." }];
  } else if (rewardType.includes("pet") || rewardType.includes("companheiro")) {
    const source = (state.content.gachaPets || []).find((item) => item.id === shopItem.rewardId || item.id === shopItem.id) || {};
    patch.gachaVault = [...(character.gachaVault || []), {
      ...source,
      id: source.id || shopItem.id,
      sourceId: source.id || shopItem.id,
      instanceId: cryptoRandom(),
      kind: "pet",
      name: shopItem.name,
      rarity: shopItem.rarity || source.rarity || "Comum",
      stars: 1,
      status: "Livre",
      equipped: false,
      obtainedAt: new Date().toISOString(),
      description: shopItem.description || source.description || "Obtido na loja de fragmentos.",
    }];
  } else {
    patch.inventory = [...(character.inventory || []), {
      id: shopItem.id,
      instanceId: cryptoRandom(),
      name: shopItem.name,
      rarity: shopItem.rarity || "Comum",
      categoryId: "sazonal",
      description: shopItem.description || "",
      source: fragmentName,
      equipped: false,
    }];
  }
  await updateCharacter(state.user.uid, patch);
  toast(`${shopItem.name} resgatado.`);
}

function minigameGrade(score, difficulty) {
  const ratio = Number(score || 0) / Math.max(1, Number(difficulty.minScore || 1));
  if (ratio >= 1.5) return { id: "s", label: "S", multiplier: 1.45, passed: true };
  if (ratio >= 1.2) return { id: "a", label: "A", multiplier: 1.22, passed: true };
  if (ratio >= 1) return { id: "b", label: "B", multiplier: 1, passed: true };
  if (ratio >= 0.65) return { id: "c", label: "C", multiplier: 0.72, passed: false };
  return { id: "d", label: "D", multiplier: 0.42, passed: false };
}

function minigameReward(difficultyId, score = 0, mode = "aim", level = 1) {
  const difficulty = difficultyById(difficultyId);
  const stage = FOUNDATIONS.minigameLevels[FOUNDATIONS.clampLevel(level) - 1] || FOUNDATIONS.minigameLevels[0];
  const target = FOUNDATIONS.minigameTarget(difficulty, stage.id);
  const grade = minigameGrade(score, { ...difficulty, minScore: target });
  const passed = grade.passed;
  const coinCap = 8 + stage.id * 4;
  const baseCoins = passed
    ? Math.min(coinCap, Math.max(1, Math.round((1 + score / 1600) * Math.sqrt(difficulty.multiplier) * grade.multiplier * Number(stage.rewardFactor || 1))))
    : 0;
  const fragmentName = mode === "hunt" ? "Marcas de Caçada" : mode === "tower" ? "Runas Partidas" : mode === "seals" ? "Ecos de Selo" : mode === "cartography" ? "Fragmentos Cartográficos" : mode === "alchemy" ? "Resíduos Alquímicos" : "Fragmentos de Mira";
  const fragments = Math.max(1, Math.round((passed ? 4 : 2) * difficulty.multiplier * grade.multiplier * Number(stage.rewardFactor || 1)));
  const rareDrop = passed && Math.random() < 0.012 * difficulty.multiplier * grade.multiplier;
  const loot = [...(baseCoins ? [`${baseCoins} Millennium Coins`] : []), `${fragments} ${fragmentName}`];
  if (rareDrop) loot.push("Fragmento do Herói Quebrado");
  return { passed, grade: grade.label, coins: baseCoins, fragmentName, fragments, loot, rareDrop, level: stage.id, target };
}

function stopActiveAimGame(reason = "cancelled") {
  const session = state.activeAimSession;
  if (!session) return;
  session.finished = true;
  (session.timers || []).forEach((timer) => {
    window.clearTimeout(timer);
    window.clearInterval(timer);
  });
  if (session.frame) window.cancelAnimationFrame(session.frame);
  if (session.keyHandler) window.removeEventListener("keydown", session.keyHandler);
  if (session.resizeHandler) window.removeEventListener("resize", session.resizeHandler);
  if (session.lifecycle?.can?.("cancelled")) session.lifecycle.transition("cancelled", reason);
  state.activeAimSession = null;
}

async function spendGachaEnergy(cost) {
  const character = currentCharacter();
  const refresh = refreshGachaEnergy(character);
  const energy = Object.prototype.hasOwnProperty.call(refresh, "gachaEnergy") ? refresh.gachaEnergy : Number(character.gachaEnergy ?? GACHA_ENERGY_MAX);
  if (energy < cost) {
    toast("Energia insuficiente para este desafio.");
    return null;
  }
  return { ...refresh, gachaEnergy: energy - cost, gachaEnergyUpdatedAt: new Date().toISOString() };
}

async function applyMinigameReward(mode, difficultyId, score = 0, extraPatch = {}, runId = "", level = state.minigameLevel) {
  const character = currentCharacter();
  const difficulty = difficultyById(difficultyId);
  const stage = FOUNDATIONS.clampLevel(level);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(character, mode, difficulty.id, stage)) throw new Error(`O nível ${stage} ainda está bloqueado para este jogo.`);
  const completionKey = String(runId || `${mode}:${difficulty.id}:${Date.now()}`);
  const completionKeys = [...new Set(character.minigameCompletionKeys || [])].slice(-79);
  if (completionKeys.includes(completionKey)) {
    toast("Esta partida já foi resolvida. Nenhuma recompensa duplicada foi aplicada.");
    return { duplicate: true, passed: false, grade: "-", coins: 0, fragments: 0, fragmentName: "", loot: [] };
  }
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    const session = ({
      aim: state.activeAimSession,
      seals: state.activeSealSession,
      cartography: state.activeCartographySession,
      alchemy: state.activeAlchemySession,
      tower: state.activeTowerSession,
    })[mode];
    await session?.serverRunPromise;
    const reward = await callTrustedOperation("minigame", { mode, difficultyId, score, runId: completionKey, level: stage });
    toast(`${reward.passed ? "Desafio concluído" : "Falha parcial"} · Nível ${stage} · Rank ${reward.grade}: ${(reward.loot || []).join(" · ")}${reward.unlockedNext ? ` · Nível ${stage + 1} liberado` : ""}`);
    return reward;
  }
  const energyPatch = await spendGachaEnergy(difficulty.cost);
  if (!energyPatch) return null;
  const reward = minigameReward(difficultyId, score, mode, stage);
  const progression = FOUNDATIONS.recordMinigameProgress(character, mode, difficulty, stage, score);
  reward.passed = progression.passed;
  reward.target = progression.target;
  reward.unlockedNext = progression.unlockedNext;
  const fragments = withFragments(character, reward.fragmentName, reward.fragments);
  if (reward.rareDrop) fragments["Fragmentos do Despertar"] = Number(fragments["Fragmentos do Despertar"] || 0) + 1;
  await updateCharacter(state.user.uid, {
    ...energyPatch,
    millenniumCoins: Number(character.millenniumCoins || 0) + reward.coins,
    gachaFragments: fragments,
    minigameCompletionKeys: [...completionKeys, completionKey],
    minigameProgress: progression.progress,
    minigameStats: {
      ...(character.minigameStats || {}),
      [mode]: {
        bestScore: Math.max(Number(character.minigameStats?.[mode]?.bestScore || 0), score),
        plays: Number(character.minigameStats?.[mode]?.plays || 0) + 1,
        [`${difficulty.id}Best`]: Math.max(Number(character.minigameStats?.[mode]?.[`${difficulty.id}Best`] || 0), score),
      },
    },
    minigameHistory: [
      {
        id: cryptoRandom(),
        completionKey,
        mode,
        difficultyId: difficulty.id,
        difficultyName: difficulty.name,
        level: stage,
        target: progression.target,
        score,
        grade: reward.grade,
        coins: reward.coins,
        fragments: reward.fragments,
        fragmentName: reward.fragmentName,
        rareDrop: reward.rareDrop,
        createdAt: new Date().toISOString(),
      },
      ...(character.minigameHistory || []),
    ].slice(0, 30),
    ...extraPatch,
    ...minigameEventAttemptPatch(mode, character),
  });
  if (reward.rareDrop) await announceRareReward(state.user.uid, "Fragmento do Herói Quebrado", "Celestial", "drop secreto");
  toast(`${reward.passed ? "Desafio concluído" : "Falha parcial"} · Nível ${stage} · Rank ${reward.grade}: ${reward.loot.join(" · ")}${reward.unlockedNext ? ` · Nível ${stage + 1} liberado` : ""}`);
  return reward;
}

function stopActiveSealRitual(reason = "cancelled") {
  const session = state.activeSealSession;
  if (!session) return;
  session.finished = true;
  (session.timers || []).forEach((timer) => window.clearTimeout(timer));
  if (session.keyHandler) window.removeEventListener("keydown", session.keyHandler);
  if (session.lifecycle?.can?.("cancelled")) session.lifecycle.transition("cancelled", reason);
  state.activeSealSession = null;
}

function refreshSealProgress(session) {
  const progress = document.querySelector("[data-seal-progress]");
  if (progress) progress.innerHTML = session.sequence.map((_, index) => `<i class="${index < session.input.length ? "done" : ""}"></i>`).join("");
  const rounds = document.querySelector("[data-seal-rounds]");
  if (rounds) rounds.innerHTML = Array.from({ length: session.maxRounds }, (_, index) => `<i class="${index < session.round - 1 ? "done" : ""}"></i>`).join("");
  const corruption = document.querySelector("[data-seal-corruption]");
  if (corruption) {
    corruption.style.setProperty("--corruption", `${Math.min(100, session.corruption)}%`);
    corruption.setAttribute("aria-valuenow", String(Math.min(100, session.corruption)));
  }
  const status = document.querySelector("[data-seal-status]");
  if (status) status.textContent = session.phase === "showing"
    ? `Rodada ${session.round}/${session.maxRounds} · observe os sigilos.`
    : `Rodada ${session.round}/${session.maxRounds} · ${session.input.length}/${session.sequence.length} símbolos · corrupção ${session.corruption}%`;
}


function presentSealRound(session) {
  if (!session || session.finished) return;
  session.phase = "showing";
  session.input = [];
  session.sequence = WORLD.sealSequence(`${session.id}:round:${session.round}`, session.config.baseLength + session.round - 1);
  refreshSealProgress(session);
  document.querySelectorAll("[data-seal-symbol]").forEach((button) => { button.disabled = true; button.classList.remove("active"); });
  session.sequence.forEach((symbol, index) => {
    const on = window.setTimeout(() => {
      if (session.finished) return;
      const button = [...document.querySelectorAll("[data-seal-symbol]")].find((entry) => entry.dataset.sealSymbol === symbol);
      button?.classList.add("active");
      playSound("common");
    }, 450 + index * 560);
    const off = window.setTimeout(() => {
      document.querySelectorAll("[data-seal-symbol]").forEach((button) => button.classList.remove("active"));
      if (index === session.sequence.length - 1 && !session.finished) {
        session.phase = "input";
        if (session.lifecycle?.can?.("running")) session.lifecycle.transition("running", "sequence-hidden");
        document.querySelectorAll("[data-seal-symbol]").forEach((button) => { button.disabled = false; });
        refreshSealProgress(session);
      }
    }, 800 + index * 560);
    session.timers.push(on, off);
  });
}

async function resolveSealRitual(session, success) {
  if (!session || session.finished) return;
  session.finished = true;
  if (session.lifecycle?.can?.("resolving")) session.lifecycle.transition("resolving", success ? "ritual-complete" : "corruption-complete");
  const symbolsResolved = Number(session.totalSymbols || 0);
  const baseScore = symbolsResolved * 980 + Math.max(0, 100 - session.corruption) * 32;
  const score = Math.round(baseScore * session.difficulty.multiplier * session.config.scoreMultiplier);
  try {
    const reward = await applyMinigameReward("seals", session.difficulty.id, score, {
      lastSealRun: {
        id: session.id,
        score,
        rounds: session.round - (success ? 0 : 1),
        corruption: session.corruption,
        success,
        eventNames: session.config.eventNames,
        createdAt: new Date().toISOString(),
      },
    }, session.id, session.level);
    if (session.lifecycle?.can?.("completed")) session.lifecycle.transition("completed", "reward-applied");
    state.activeSealSession = null;
    showMinigameResult({
      mode: "Ritual dos Selos",
      difficulty: session.difficulty,
      score,
      reward,
      detail: success
        ? `${session.maxRounds} círculos selados · corrupção final ${session.corruption}%`
        : `O altar foi consumido com ${session.corruption}% de corrupção`,
    });
  } catch (error) {
    if (session.lifecycle?.can?.("failed")) session.lifecycle.transition("failed", error?.message || "reward-error");
    state.activeSealSession = null;
    throw error;
  }
}

function handleSealInput(symbol) {
  const session = state.activeSealSession;
  if (!session || session.finished || session.phase !== "input") return;
  const expected = session.sequence[session.input.length];
  const button = [...document.querySelectorAll("[data-seal-symbol]")].find((entry) => entry.dataset.sealSymbol === symbol);
  button?.classList.add("active");
  window.setTimeout(() => button?.classList.remove("active"), 180);
  if (symbol !== expected) {
    session.corruption = Math.min(100, session.corruption + session.config.corruptionPerError);
    session.input = [];
    playSound("fail");
    refreshSealProgress(session);
    if (session.corruption >= 100) {
      resolveSealRitual(session, false).catch((error) => toast(error?.message || "Não foi possível resolver o ritual."));
      return;
    }
    session.phase = "showing";
    const retry = window.setTimeout(() => presentSealRound(session), 700);
    session.timers.push(retry);
    return;
  }
  session.input.push(symbol);
  session.totalSymbols += 1;
  playSound("common");
  refreshSealProgress(session);
  if (session.input.length !== session.sequence.length) return;
  session.round += 1;
  if (session.round > session.maxRounds) {
    resolveSealRitual(session, true).catch((error) => toast(error?.message || "Não foi possível resolver o ritual."));
    return;
  }
  session.phase = "showing";
  const nextRound = window.setTimeout(() => presentSealRound(session), 650);
  session.timers.push(nextRound);
}

function startSealRitual(difficultyId) {
  if (!canStartMinigameEvent("seals")) return;
  const difficulty = difficultyById(difficultyId);
  const level = FOUNDATIONS.clampLevel(state.minigameLevel);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(currentCharacter(), "seals", difficulty.id, level)) return toast(`Conclua o nível ${level - 1} deste jogo primeiro.`);
  if (currentGachaEnergy() < difficulty.cost) return toast("Energia insuficiente para o Ritual dos Selos.");
  stopActiveSealRitual("new-run");
  const id = `seals:${state.user?.uid || "demo"}:${cryptoRandom()}`;
  const config = VIVID.createSealConfig(id, difficulty, level, state.settings.minigameEvents || []);
  const symbols = ["◇", "△", "✦", "◈", "⌁", "✥"];
  const session = {
    id,
    difficulty,
    level,
    config,
    sequence: [],
    input: [],
    round: 1,
    maxRounds: config.rounds,
    corruption: 0,
    totalSymbols: 0,
    phase: "showing",
    timers: [],
    finished: false,
    lifecycle: POLISH.createLifecycle("preparing"),
  };
  state.activeSealSession = session;
  beginTrustedMinigame(session, "seals").catch((error) => { session.serverRunError = error; });
  $("#modalContent").innerHTML = `
    <section class="seal-session vivid-session" aria-labelledby="seal-title">
      <div class="vivid-game-head"><div><p class="eyebrow">Ritual dos Selos · ${esc(difficulty.name)} · Nível ${level}</p><h2 id="seal-title">Feche os círculos antes que a corrupção alcance o altar.</h2>${config.eventNames.length ? `<p class="vivid-event-note">Evento: ${esc(config.eventNames.join(" · "))}</p>` : ""}</div><button class="aim-exit" type="button" data-action="close-modal">Sair</button></div>
      <p class="seal-status" data-seal-status role="status" aria-live="polite"></p>
      <div class="seal-rounds" data-seal-rounds aria-label="Rodadas"></div>
      <div class="seal-corruption"><small>Corrupção</small><div class="seal-corruption-track" data-seal-corruption role="progressbar" aria-valuemin="0" aria-valuemax="100" aria-valuenow="0"><i></i></div></div>
      <div class="seal-altar">
        <div class="seal-progress" data-seal-progress></div>
        <div class="seal-board vivid-seals" role="group" aria-label="Sigilos do ritual">${symbols.map((symbol, index) => `<button class="seal-button" type="button" data-action="seal-input" data-seal-symbol="${esc(symbol)}" aria-label="Sigilo ${index + 1}, tecla ${index + 1}">${esc(symbol)}</button>`).join("")}</div>
      </div>
      <p class="hint">Use toque, clique ou as teclas 1–6. Um erro aumenta a corrupção e repete a rodada.</p>
    </section>`;
  $("#modal").hidden = false;
  focusModal();
  session.keyHandler = (event) => {
    if (event.repeat || session.finished) return;
    const index = Number(event.key) - 1;
    if (index >= 0 && index < symbols.length) handleSealInput(symbols[index]);
  };
  window.addEventListener("keydown", session.keyHandler);
  presentSealRound(session);
}

function stopActiveCartography(reason = "cancelled") {
  const session = state.activeCartographySession;
  if (!session) return;
  session.finished = true;
  if (session.timer) window.clearInterval(session.timer);
  if (session.keyHandler) window.removeEventListener("keydown", session.keyHandler);
  state.activeCartographySession = null;
}

function renderCartographyBoard(session) {
  const host = document.querySelector("[data-cartography-board]");
  if (!host || !session) return;
  host.style.setProperty("--map-size", session.size);
  host.innerHTML = session.cells.map((cell) => {
    const isPlayer = cell.x === session.player.x && cell.y === session.player.y;
    const isExit = cell.x === session.exit.x && cell.y === session.exit.y;
    const visible = cell.discovered || isPlayer;
    const classes = ["cartography-cell", visible ? cell.type : "fog", cell.collected ? "collected" : "", isPlayer ? "player" : "", isExit ? "exit" : ""].filter(Boolean).join(" ");
    const glyph = !visible ? "" : isExit ? "⌂" : cell.type === "wall" ? "▦" : cell.type === "trap" ? "⚠" : cell.type === "relic" && !cell.collected ? "✦" : "·";
    return `<div class="${classes}" aria-label="${visible ? `${cell.type}${isExit ? ", saída" : ""}` : "Área coberta pela névoa"}">${glyph}</div>`;
  }).join("");
  const status = document.querySelector("[data-cartography-status]");
  if (status) status.textContent = `${session.moves} movimentos · ${session.relics}/${session.relicTarget} relíquias · ${session.damage} ferimentos · ${session.remaining}s`;
  const log = document.querySelector("[data-cartography-log]");
  if (log) log.textContent = session.message || "Explore a névoa, recupere as relíquias e alcance a saída.";
}

async function resolveCartography(session, solved) {
  if (!session || session.finished) return;
  session.finished = true;
  if (session.timer) window.clearInterval(session.timer);
  if (session.keyHandler) window.removeEventListener("keydown", session.keyHandler);
  const base = session.relics * 1800 + session.remaining * 42 - session.moves * 18 - session.damage * 650 + (solved ? 5200 : 0);
  const score = Math.max(100, Math.round(base * session.difficulty.multiplier * session.scoreMultiplier));
  try {
    const reward = await applyMinigameReward("cartography", session.difficulty.id, score, {
      lastCartographyRun: {
        id: session.id,
        mapName: session.mapName,
        moves: session.moves,
        relics: session.relics,
        damage: session.damage,
        solved,
        score,
        eventNames: session.eventNames,
        createdAt: new Date().toISOString(),
      },
    }, session.id, session.level);
    state.activeCartographySession = null;
    showMinigameResult({
      mode: "Cartografia Perdida",
      difficulty: session.difficulty,
      score,
      reward,
      detail: solved
        ? `${session.mapName}: saída encontrada com ${session.relics} relíquia(s) e ${session.damage} ferimento(s)`
        : `A névoa fechou o mapa após ${session.moves} movimentos`,
    });
  } catch (error) {
    state.activeCartographySession = null;
    throw error;
  }
}

function handleCartographyMove(direction) {
  const session = state.activeCartographySession;
  if (!session || session.finished) return;
  const result = VIVID.moveCartography(session, String(direction || ""));
  if (!result.moved) {
    session.message = result.blocked ? "Uma ruína bloqueia esse caminho." : "Não é possível avançar nessa direção.";
    renderCartographyBoard(session);
    playSound("fail");
    return;
  }
  session.message = result.event === "relic"
    ? "Uma Relíquia Cartográfica foi recuperada."
    : result.event === "trap"
      ? "Uma armadilha atravessou a expedição."
      : result.reachedExit && session.relics < session.relicTarget
        ? `A saída foi localizada, mas faltam ${session.relicTarget - session.relics} relíquia(s).`
        : "A névoa recua ao redor do explorador.";
  playSound(result.event === "relic" ? "rare" : result.event === "trap" ? "fail" : "common");
  renderCartographyBoard(session);
  if (result.complete) resolveCartography(session, true).catch((error) => toast(error?.message || "Não foi possível registrar o mapa."));
}

function startCartography(difficultyId) {
  if (!canStartMinigameEvent("cartography")) return;
  const difficulty = difficultyById(difficultyId);
  const level = FOUNDATIONS.clampLevel(state.minigameLevel);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(currentCharacter(), "cartography", difficulty.id, level)) return toast(`Conclua o nível ${level - 1} deste jogo primeiro.`);
  if (currentGachaEnergy() < difficulty.cost) return toast("Energia insuficiente para Cartografia Perdida.");
  stopActiveCartography("new-run");
  const maps = state.content.towerMaps || [];
  const id = `cartography:${state.user?.uid || "demo"}:${cryptoRandom()}`;
  const selected = maps[VIVID.hashSeed ? VIVID.hashSeed(id) % Math.max(1, maps.length) : 0] || { name: "Cruzamento das Cortinas" };
  const session = {
    id,
    difficulty,
    level,
    mapName: selected.name,
    ...VIVID.createCartographyExpedition(id, difficulty, level, state.settings.minigameEvents || []),
    timer: 0,
    finished: false,
    message: "Explore a névoa, recupere as relíquias e alcance a saída.",
  };
  state.activeCartographySession = session;
  beginTrustedMinigame(session, "cartography").catch((error) => { session.serverRunError = error; });
  $("#modalContent").innerHTML = `
    <section class="cartography-session vivid-session">
      <div class="vivid-game-head"><div><p class="eyebrow">Cartografia Perdida · ${esc(difficulty.name)} · Nível ${level}</p><h2>${esc(session.mapName)}</h2>${session.eventNames.length ? `<p class="vivid-event-note">Evento: ${esc(session.eventNames.join(" · "))}</p>` : ""}</div><button class="aim-exit" type="button" data-action="close-modal">Sair</button></div>
      <p data-cartography-status role="status" aria-live="polite"></p>
      <div class="cartography-expedition">
        <div class="cartography-map" data-cartography-board aria-label="Mapa de exploração"></div>
        <aside class="cartography-side">
          <div class="cartography-log" data-cartography-log></div>
          <div class="cartography-dpad" aria-label="Direções">
            <button class="ghost-button up" type="button" data-action="cartography-move" data-direction="up" aria-label="Mover para cima">▲</button>
            <button class="ghost-button left" type="button" data-action="cartography-move" data-direction="left" aria-label="Mover para esquerda">◀</button>
            <button class="ghost-button down" type="button" data-action="cartography-move" data-direction="down" aria-label="Mover para baixo">▼</button>
            <button class="ghost-button right" type="button" data-action="cartography-move" data-direction="right" aria-label="Mover para direita">▶</button>
          </div>
          <p class="hint">Teclas WASD e setas também funcionam. Recupere relíquias antes de sair.</p>
        </aside>
      </div>
    </section>`;
  $("#modal").hidden = false;
  focusModal();
  session.keyHandler = (event) => {
    const direction = ({ ArrowUp: "up", w: "up", W: "up", ArrowDown: "down", s: "down", S: "down", ArrowLeft: "left", a: "left", A: "left", ArrowRight: "right", d: "right", D: "right" })[event.key];
    if (!direction || session.finished) return;
    event.preventDefault();
    handleCartographyMove(direction);
  };
  window.addEventListener("keydown", session.keyHandler);
  renderCartographyBoard(session);
  session.timer = window.setInterval(() => {
    if (session.finished || session.runtimePaused || document.hidden) return;
    session.remaining -= 1;
    renderCartographyBoard(session);
    if (session.remaining <= 0) resolveCartography(session, false).catch((error) => toast(error?.message || "Não foi possível registrar o mapa."));
  }, 1000);
}

function stopActiveAlchemy() {
  const session = state.activeAlchemySession;
  if (!session) return;
  session.finished = true;
  state.activeAlchemySession = null;
}

function refreshAlchemySelection(session) {
  if (!session) return;
  const byId = Object.fromEntries(session.ingredients.map((item) => [item.id, item]));
  const host = document.querySelector("[data-alchemy-selection]");
  if (host) host.innerHTML = session.selection.map((id, index) => `<span>${index + 1}. ${esc(byId[id]?.name || id)}</span>`).join("") || `<span class="muted-text">Escolha a ordem dos ingredientes.</span>`;
  document.querySelectorAll("[data-alchemy-id]").forEach((button) => { button.disabled = session.selection.includes(button.dataset.alchemyId) || session.finished; });
  const heat = document.querySelector("[data-alchemy-heat]");
  const stability = document.querySelector("[data-alchemy-stability]");
  const essence = document.querySelector("[data-alchemy-essence]");
  if (heat) { heat.style.setProperty("--gauge", `${session.heat}%`); heat.closest(".alchemy-gauge")?.querySelector("b")?.replaceChildren(document.createTextNode(`${Math.round(session.heat)}°`)); }
  if (stability) { stability.style.setProperty("--gauge", `${session.stability}%`); stability.closest(".alchemy-gauge")?.querySelector("b")?.replaceChildren(document.createTextNode(`${Math.round(session.stability)}%`)); }
  if (essence) { essence.style.setProperty("--gauge", `${Math.min(100, session.essence * 6)}%`); essence.closest(".alchemy-gauge")?.querySelector("b")?.replaceChildren(document.createTextNode(String(session.essence))); }
}

async function resolveAlchemy(session) {
  if (!session || session.finished) return;
  if (session.selection.length !== session.recipe.length) return toast("Adicione todos os ingredientes antes de selar a mistura.");
  session.finished = true;
  const result = VIVID.evaluateAlchemyLab(session);
  const score = Math.round(result.score * session.difficulty.multiplier);
  const lab = document.querySelector(".alchemy-lab");
  lab?.classList.add(result.passed ? "success" : "exploded");
  try {
    const reward = await applyMinigameReward("alchemy", session.difficulty.id, score, {
      lastAlchemyRun: {
        id: session.id,
        correct: result.correct,
        total: result.total,
        passed: result.passed,
        heat: session.heat,
        targetHeat: session.targetHeat,
        stability: session.stability,
        score,
        eventNames: session.eventNames,
        createdAt: new Date().toISOString(),
      },
    }, session.id, session.level);
    state.activeAlchemySession = null;
    window.setTimeout(() => showMinigameResult({
      mode: "Alquimia Instável",
      difficulty: session.difficulty,
      score,
      reward,
      detail: result.passed
        ? `Reação estável · ${Math.round(session.heat)}° · estabilidade ${Math.round(session.stability)}%`
        : `${result.correct}/${result.total} posições corretas · distância térmica ${Math.round(result.heatDistance)}°`,
    }), 420);
  } catch (error) {
    state.activeAlchemySession = null;
    throw error;
  }
}

function handleAlchemyIngredient(id) {
  const session = state.activeAlchemySession;
  if (!session || session.finished || session.selection.includes(id)) return;
  VIVID.addAlchemyIngredient(session, id);
  playSound("common");
  refreshAlchemySelection(session);
}

function resetAlchemySelection() {
  const session = state.activeAlchemySession;
  if (!session || session.finished) return;
  session.selection = [];
  session.heat = 35;
  session.stability = 50;
  session.essence = 0;
  refreshAlchemySelection(session);
}


function adjustAlchemyHeat(delta) {
  const session = state.activeAlchemySession;
  if (!session || session.finished) return;
  VIVID.adjustAlchemyHeat(session, Number(delta || 0));
  playSound("common");
  refreshAlchemySelection(session);
}

function startAlchemy(difficultyId) {
  if (!canStartMinigameEvent("alchemy")) return;
  const difficulty = difficultyById(difficultyId);
  const level = FOUNDATIONS.clampLevel(state.minigameLevel);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(currentCharacter(), "alchemy", difficulty.id, level)) return toast(`Conclua o nível ${level - 1} deste jogo primeiro.`);
  if (currentGachaEnergy() < difficulty.cost) return toast("Energia insuficiente para Alquimia Instável.");
  stopActiveAlchemy();
  const id = `alchemy:${state.user?.uid || "demo"}:${cryptoRandom()}`;
  const labData = VIVID.createAlchemyLab(id, difficulty, level, state.settings.minigameEvents || []);
  const session = { id, difficulty, level, ...labData, finished: false };
  state.activeAlchemySession = session;
  beginTrustedMinigame(session, "alchemy").catch((error) => { session.serverRunError = error; });
  $("#modalContent").innerHTML = `
    <section class="alchemy-session vivid-session">
      <div class="vivid-game-head"><div><p class="eyebrow">Alquimia Instável · ${esc(difficulty.name)} · Nível ${level}</p><h2>Controle a reação, não apenas a ordem.</h2>${session.eventNames.length ? `<p class="vivid-event-note">Evento: ${esc(session.eventNames.join(" · "))}</p>` : ""}</div><button class="aim-exit" type="button" data-action="close-modal">Sair</button></div>
      <div class="alchemy-lab">
        <div class="alchemy-cauldron-stage" data-alchemy-drop tabindex="0" aria-label="Área do caldeirão. Solte ingredientes aqui ou use os botões da bancada.">
          <div class="alchemy-cauldron" aria-label="Caldeirão alquímico"><i class="alchemy-bubble b1"></i><i class="alchemy-bubble b2"></i><i class="alchemy-bubble b3"></i></div>
          <div class="alchemy-gauges">
            <div class="alchemy-gauge"><span>Calor</span><div class="alchemy-gauge-track" data-alchemy-heat style="--gauge:${session.heat}%"><i></i></div><b>${session.heat}°</b></div>
            <div class="alchemy-gauge"><span>Estabilidade</span><div class="alchemy-gauge-track" data-alchemy-stability style="--gauge:${session.stability}%"><i></i></div><b>${session.stability}%</b></div>
            <div class="alchemy-gauge"><span>Essência</span><div class="alchemy-gauge-track" data-alchemy-essence style="--gauge:0%"><i></i></div><b>0</b></div>
          </div>
        </div>
        <div class="alchemy-workbench">
          <ol class="alchemy-clues">${session.clues.map((clue) => `<li>${esc(clue)}</li>`).join("")}</ol>
          <div class="alchemy-ingredients vivid">${session.ingredients.map((ingredient) => `<button class="ghost-button alchemy-ingredient-card" type="button" draggable="true" data-action="alchemy-ingredient" data-alchemy-id="${esc(ingredient.id)}"><b>${esc(ingredient.glyph)}</b><span><strong>${esc(ingredient.name)}</strong><small>Calor ${ingredient.heat > 0 ? "+" : ""}${ingredient.heat} · estabilidade ${ingredient.stability > 0 ? "+" : ""}${ingredient.stability}</small></span></button>`).join("")}</div>
          <div class="alchemy-order" data-alchemy-selection aria-live="polite"></div>
          <div class="alchemy-heat-controls"><button class="ghost-button" type="button" data-action="alchemy-heat" data-delta="-5">Reduzir 5°</button><button class="ghost-button" type="button" data-action="alchemy-heat" data-delta="5">Aumentar 5°</button><button class="link-button" type="button" data-action="alchemy-reset">Recomeçar</button><button class="primary-button intense" type="button" data-action="alchemy-brew">Selar mistura</button></div>
        </div>
      </div>
    </section>`;
  $("#modal").hidden = false;
  focusModal();
  document.querySelectorAll("[data-alchemy-id]").forEach((button) => button.addEventListener("dragstart", (event) => {
    event.dataTransfer?.setData("text/plain", button.dataset.alchemyId || "");
    if (event.dataTransfer) event.dataTransfer.effectAllowed = "copy";
  }));
  const dropZone = document.querySelector("[data-alchemy-drop]");
  dropZone?.addEventListener("dragover", (event) => { event.preventDefault(); dropZone.classList.add("drag-over"); });
  dropZone?.addEventListener("dragleave", () => dropZone.classList.remove("drag-over"));
  dropZone?.addEventListener("drop", (event) => {
    event.preventDefault();
    dropZone.classList.remove("drag-over");
    const ingredientId = event.dataTransfer?.getData("text/plain");
    if (ingredientId) handleAlchemyIngredient(ingredientId);
  });
  refreshAlchemySelection(session);
}

function startAimGame(difficultyId) {
  if (!canStartMinigameEvent("aim")) return;
  const difficulty = difficultyById(difficultyId);
  const level = FOUNDATIONS.clampLevel(state.minigameLevel);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(currentCharacter(), "aim", difficulty.id, level)) return toast(`Conclua o nível ${level - 1} deste jogo primeiro.`);
  if (currentGachaEnergy() < difficulty.cost) return toast("Energia insuficiente para a Prova da Mira.");
  stopActiveAimGame("new-run");
  const id = `aim:${state.user?.uid || "demo"}:${cryptoRandom()}`;
  const config = VIVID.createAimConfig(id, difficulty, level, state.settings.minigameEvents || []);
  const session = {
    id,
    config,
    difficulty,
    level,
    score: 0,
    remaining: config.seconds,
    combo: 0,
    bestCombo: 0,
    misses: 0,
    shots: 0,
    hits: 0,
    ammo: config.magazine,
    reloading: false,
    targets: [],
    spawnCount: 0,
    aimX: .5,
    aimY: .5,
    timers: [],
    frame: 0,
    finished: false,
    lastFrame: performance.now(),
    lifecycle: POLISH.createLifecycle("preparing"),
  };
  session.lifecycle.transition("running", "range-ready");
  state.activeAimSession = session;
  beginTrustedMinigame(session, "aim").catch((error) => { session.serverRunError = error; });
  $("#modalContent").innerHTML = `
    <section class="aim-session vivid-session aim-fps-shell difficulty-${esc(difficulty.id)}" aria-labelledby="aim-title">
      <div class="vivid-game-head"><div><p class="eyebrow">Prova da Mira · ${esc(difficulty.name)} · Nível ${level}</p><h2 id="aim-title">Estande de precisão em primeira pessoa.</h2>${config.eventNames.length ? `<p class="vivid-event-note">Evento: ${esc(config.eventNames.join(" · "))}</p>` : ""}<p class="sr-only" id="aim-instructions">Mova a mira com mouse ou toque. Clique ou use Espaço para disparar. Use R para recarregar.</p></div><button class="aim-exit" type="button" data-action="close-modal">Sair</button></div>
      <div class="aim-fps-hud" role="status" aria-live="polite"><span data-aim-score>0 pontos</span><span data-aim-combo>Combo 0</span><span data-aim-misses>Erros 0</span><span data-aim-time>${config.seconds}s</span><span data-aim-ammo>${config.magazine}/${config.magazine}</span><span data-aim-accuracy>Precisão 0%</span></div>
      <div class="aim-fps-stage" data-aim-stage aria-describedby="aim-instructions"><canvas data-aim-canvas></canvas><div class="aim-fps-crosshair" data-aim-crosshair aria-hidden="true"><i></i></div></div>
      <div class="aim-fps-controls"><button class="primary-button intense aim-fire-button" type="button" data-aim-fire>Disparar</button><button class="ghost-button" type="button" data-aim-reload>Recarregar</button><span class="hint">Mouse/toque · Espaço dispara · R recarrega · Esc pausa saindo</span></div>
    </section>`;
  $("#modal").hidden = false;
  focusModal();

  const stage = document.querySelector("[data-aim-stage]");
  const canvas = document.querySelector("[data-aim-canvas]");
  const context = canvas.getContext("2d");
  const crosshair = document.querySelector("[data-aim-crosshair]");
  const scoreEl = document.querySelector("[data-aim-score]");
  const comboEl = document.querySelector("[data-aim-combo]");
  const missesEl = document.querySelector("[data-aim-misses]");
  const timeEl = document.querySelector("[data-aim-time]");
  const ammoEl = document.querySelector("[data-aim-ammo]");
  const accuracyEl = document.querySelector("[data-aim-accuracy]");

  const resize = () => {
    const rect = stage.getBoundingClientRect();
    const ratio = Math.min(2, window.devicePixelRatio || 1);
    canvas.width = Math.max(320, Math.round(rect.width * ratio));
    canvas.height = Math.max(360, Math.round(rect.height * ratio));
    context.setTransform(ratio, 0, 0, ratio, 0, 0);
  };
  session.resizeHandler = resize;
  window.addEventListener("resize", resize);
  resize();

  const refreshHud = () => {
    scoreEl.textContent = `${Math.max(0, session.score)} pontos`;
    comboEl.textContent = `Combo ${session.combo}`;
    missesEl.textContent = `Erros ${session.misses}`;
    timeEl.textContent = `${session.remaining}s`;
    ammoEl.textContent = session.reloading ? "Recarregando…" : `${session.ammo}/${config.magazine}`;
    accuracyEl.textContent = `Precisão ${session.shots ? Math.round(session.hits / session.shots * 100) : 0}%`;
  };

  const spawnTarget = () => {
    if (session.finished || session.runtimePaused || document.hidden || session.targets.length >= config.maxTargets) return;
    const random = VIVID.randomFromSeed ? VIVID.randomFromSeed(`${id}:spawn:${session.spawnCount++}`) : Math.random;
    const roll = random();
    const type = roll < .1 && difficulty.id !== "noob" ? "trap" : roll < .23 ? "rare" : roll < .34 ? "time" : "normal";
    session.targets.push({
      id: `target-${cryptoRandom()}`,
      x: random() * 1.7 - .85,
      y: random() * .72 - .32,
      z: .95 + random() * .22,
      drift: (random() - .5) * config.drift,
      type,
      bornAt: performance.now(),
      life: config.targetLifeMs * (.82 + random() * .4),
    });
  };

  const reload = () => {
    if (session.finished || session.reloading || session.ammo === config.magazine) return;
    session.reloading = true;
    stage.classList.add("reloading");
    refreshHud();
    const timer = window.setTimeout(() => {
      if (session.finished) return;
      session.ammo = config.magazine;
      session.reloading = false;
      stage.classList.remove("reloading");
      refreshHud();
      playSound("common");
    }, config.reloadMs);
    session.timers.push(timer);
  };

  const finish = async () => {
    if (session.finished) return;
    session.finished = true;
    session.timers.forEach((timer) => { window.clearTimeout(timer); window.clearInterval(timer); });
    if (session.frame) window.cancelAnimationFrame(session.frame);
    if (session.keyHandler) window.removeEventListener("keydown", session.keyHandler);
    if (session.resizeHandler) window.removeEventListener("resize", session.resizeHandler);
    if (session.lifecycle.can("resolving")) session.lifecycle.transition("resolving", "time-ended");
    const finalScore = Math.max(0, Math.round(session.score * config.scoreMultiplier));
    try {
      const reward = await applyMinigameReward("aim", difficulty.id, finalScore, {
        lastAimRun: {
          id: session.id,
          score: finalScore,
          streak: session.bestCombo,
          misses: session.misses,
          shots: session.shots,
          hits: session.hits,
          accuracy: session.shots ? session.hits / session.shots : 0,
          eventNames: config.eventNames,
          difficultyId: difficulty.id,
          createdAt: new Date().toISOString(),
        },
      }, session.id, level);
      if (session.lifecycle.can("completed")) session.lifecycle.transition("completed", "reward-applied");
      state.activeAimSession = null;
      showMinigameResult({ mode: "Prova da Mira", difficulty, score: finalScore, reward, detail: `${session.hits}/${session.shots} acertos · precisão ${session.shots ? Math.round(session.hits / session.shots * 100) : 0}% · combo ${session.bestCombo}` });
    } catch (error) {
      if (session.lifecycle.can("failed")) session.lifecycle.transition("failed", error?.message || "reward-error");
      state.activeAimSession = null;
      throw error;
    }
  };

  const fire = () => {
    if (session.finished || session.reloading) return;
    if (session.ammo <= 0) { reload(); playSound("fail"); return; }
    session.ammo -= 1;
    session.shots += 1;
    const rect = stage.getBoundingClientRect();
    const hitX = session.aimX * rect.width;
    const hitY = session.aimY * rect.height;
    let best = null;
    session.targets.forEach((target) => {
      if (!target.screen) return;
      const distance = Math.hypot(target.screen.x - hitX, target.screen.y - hitY);
      if (distance <= target.screen.radius && (!best || distance < best.distance)) best = { target, distance };
    });
    if (!best) {
      session.combo = 0;
      session.misses += 1;
      session.score = Math.max(0, session.score - Math.round(45 * difficulty.multiplier));
      playSound("fail");
    } else {
      const target = best.target;
      session.targets = session.targets.filter((item) => item.id !== target.id);
      if (target.type === "trap") {
        session.combo = 0;
        session.misses += 1;
        session.score = Math.max(0, session.score - Math.round(220 * difficulty.multiplier));
        playSound("fail");
      } else {
        session.hits += 1;
        session.combo += 1;
        session.bestCombo = Math.max(session.bestCombo, session.combo);
        const comboBonus = Math.min(2.6, 1 + session.combo * .06);
        if (target.type === "time") session.remaining = Math.min(config.seconds + 6, session.remaining + 3);
        session.score += Math.round((target.type === "rare" ? 360 : target.type === "time" ? 180 : 105) * difficulty.multiplier * comboBonus / Math.max(.45, target.z));
        playSound(target.type === "rare" ? "rare" : "common");
      }
      const flash = document.createElement("i");
      flash.className = "aim-hit-flash";
      flash.style.setProperty("--hit-x", `${session.aimX * 100}%`);
      flash.style.setProperty("--hit-y", `${session.aimY * 100}%`);
      stage.appendChild(flash);
      window.setTimeout(() => flash.remove(), 260);
    }
    if (session.ammo <= 0) reload();
    refreshHud();
  };

  const moveAim = (event) => {
    const rect = stage.getBoundingClientRect();
    session.aimX = Math.max(0, Math.min(1, (event.clientX - rect.left) / rect.width));
    session.aimY = Math.max(0, Math.min(1, (event.clientY - rect.top) / rect.height));
    crosshair.style.left = `${session.aimX * 100}%`;
    crosshair.style.top = `${session.aimY * 100}%`;
  };
  stage.addEventListener("pointermove", moveAim);
  stage.addEventListener("pointerdown", (event) => { moveAim(event); fire(); });
  document.querySelector("[data-aim-fire]")?.addEventListener("click", fire);
  document.querySelector("[data-aim-reload]")?.addEventListener("click", reload);
  session.keyHandler = (event) => {
    if (event.code === "Space") { event.preventDefault(); fire(); }
    if (event.key.toLowerCase() === "r") reload();
  };
  window.addEventListener("keydown", session.keyHandler);

  const draw = (now) => {
    if (session.finished) return;
    if (session.runtimePaused || document.hidden) { session.frame = 0; return; }
    const dt = Math.min(.05, (now - session.lastFrame) / 1000);
    session.lastFrame = now;
    const width = canvas.clientWidth;
    const height = canvas.clientHeight;
    context.clearRect(0, 0, width, height);
    const horizon = height * .48;
    const gradient = context.createLinearGradient(0, 0, 0, height);
    gradient.addColorStop(0, "#07101e");
    gradient.addColorStop(.5, "#101527");
    gradient.addColorStop(.51, "#211724");
    gradient.addColorStop(1, "#09080d");
    context.fillStyle = gradient;
    context.fillRect(0, 0, width, height);
    context.strokeStyle = "rgba(216,181,91,.12)";
    context.lineWidth = 1;
    for (let i = -5; i <= 5; i += 1) {
      context.beginPath();
      context.moveTo(width / 2, horizon);
      context.lineTo(width / 2 + i * width * .22, height);
      context.stroke();
    }
    for (let row = 1; row <= 6; row += 1) {
      const y = horizon + (height - horizon) * (row / 6) ** 1.7;
      context.beginPath(); context.moveTo(0, y); context.lineTo(width, y); context.stroke();
    }
    session.targets = session.targets.filter((target) => {
      target.z -= dt * (.12 + difficulty.multiplier * .018);
      target.x += target.drift * dt;
      const age = now - target.bornAt;
      if (target.z <= .08 || age > target.life) {
        if (target.type !== "trap") { session.combo = 0; session.misses += 1; }
        return false;
      }
      const scale = 1 / Math.max(.18, target.z);
      const x = width / 2 + target.x * width * .28 * scale;
      const y = horizon - target.y * height * .45 * scale + (1 - target.z) * height * .12;
      const radius = Math.max(13, Math.min(54, 19 * scale));
      target.screen = { x, y, radius };
      context.save();
      context.translate(x, y);
      context.fillStyle = target.type === "trap" ? "#a13b4c" : target.type === "rare" ? "#f2cc62" : target.type === "time" ? "#6bc4d1" : "#d9d4c5";
      context.strokeStyle = target.type === "trap" ? "#ff9ba8" : "#fff0a9";
      context.lineWidth = 3;
      context.beginPath(); context.arc(0, 0, radius, 0, Math.PI * 2); context.fill(); context.stroke();
      context.fillStyle = "#16121a";
      context.font = `700 ${Math.max(16, radius * .7)}px system-ui`;
      context.textAlign = "center"; context.textBaseline = "middle";
      context.fillText(target.type === "trap" ? "×" : target.type === "rare" ? "✦" : target.type === "time" ? "⌁" : "•", 0, 1);
      context.restore();
      return true;
    });
    session.frame = window.requestAnimationFrame(draw);
  };

  session.drawFrame = draw;
  const spawn = window.setInterval(spawnTarget, config.spawnMs);
  const timer = window.setInterval(() => {
    if (session.finished || session.runtimePaused || document.hidden) return;
    session.remaining -= 1;
    refreshHud();
    if (session.remaining <= 0) finish().catch((error) => toast(error?.message || "Não foi possível registrar a Prova da Mira."));
  }, 1000);
  session.timers.push(spawn, timer);
  for (let i = 0; i < 3; i += 1) spawnTarget();
  refreshHud();
  session.frame = window.requestAnimationFrame(draw);
}

function showMinigameResult({ mode, difficulty, score, reward, detail = "" }) {
  $("#modalContent").innerHTML = `
    <section class="minigame-result ${reward?.passed ? "victory" : "partial"}">
      <p class="eyebrow">${esc(mode)} · ${esc(difficulty.name)} · Nível ${Number(reward?.level || state.minigameLevel || 1)}</p>
      <span class="minigame-grade">${esc(reward?.grade || "D")}</span>
      <h2>${reward?.passed ? "Você sobreviveu ao desafio." : "O portal cobrou seu preço."}</h2>
      <p>${esc(detail)}</p>
      <p class="minigame-target-result">Meta para avançar: ${Number(reward?.target || 0).toLocaleString("pt-BR")} pontos${reward?.unlockedNext ? ` · Nível ${Number(reward.level || 1) + 1} liberado` : ""}</p>
      <div class="result-reward-grid">
        ${renderStat("Score", score)}
        ${renderStat("Millennium Coins", reward?.coins || 0)}
        ${renderStat(reward?.fragmentName || "Fragmentos", reward?.fragments || 0)}
      </div>
      <p class="result-loot">${esc((reward?.loot || ["Nenhuma recompensa"]).join(" · "))}</p>
      <button class="primary-button intense" type="button" data-action="close-modal">Voltar ao grimório</button>
    </section>
  `;
  $("#modal").hidden = false;
  playSound(reward?.passed ? (reward.grade === "S" ? "legendary" : "rare") : "fail");
}

function huntLootFor(biome = {}, difficulty = {}, pet = {}, cancelled = false) {
  const biomeKey = String(biome.id || "").toLowerCase();
  const pools = {
    vidro: [{ id: "vidro-abissal", name: "Vidro abissal", rarity: "Raro" }, { id: "sal-lunar", name: "Sal lunar", rarity: "Incomum" }, { id: "estilhaco-vitreo", name: "Estilhaço vítreo", rarity: "Comum" }],
    pantano: [{ id: "bronze-funebre", name: "Bronze fúnebre", rarity: "Incomum" }, { id: "ervas-de-pantano", name: "Ervas de pântano", rarity: "Comum" }, { id: "perola-de-eco", name: "Pérola de Eco", rarity: "Raro" }],
    ferrugem: [{ id: "sucata-arcana", name: "Sucata arcana", rarity: "Comum" }, { id: "nucleo-opaco", name: "Núcleo opaco", rarity: "Raro" }, { id: "liga-ferruginea", name: "Liga ferrugínea", rarity: "Incomum" }],
    folhas: [{ id: "seiva-memorial", name: "Seiva memorial", rarity: "Incomum" }, { id: "madeira-viva", name: "Madeira viva", rarity: "Raro" }, { id: "semente-dourada", name: "Semente dourada", rarity: "Comum" }],
    carne: [{ id: "fibra-viva", name: "Fibra viva", rarity: "Raro" }, { id: "glandula-divina", name: "Glândula divina", rarity: "Épico" }, { id: "fruto-pulsante", name: "Fruto pulsante", rarity: "Incomum" }],
    cinzas: [{ id: "cinza-nominal", name: "Cinza nominal", rarity: "Incomum" }, { id: "pedra-juramento", name: "Pedra de juramento", rarity: "Raro" }, { id: "cinza-fria", name: "Cinza fria", rarity: "Comum" }],
    gelo: [{ id: "couro-palido", name: "Couro pálido", rarity: "Raro" }, { id: "galhada-lunar", name: "Galhada lunar", rarity: "Épico" }, { id: "gelo-eterno", name: "Gelo eterno", rarity: "Incomum" }],
    default: [{ id: "fibra-de-eco", name: "Fibra de Eco", rarity: "Comum" }, { id: "tecido-ritual", name: "Tecido ritual", rarity: "Incomum" }, { id: "cinza-fria", name: "Cinza fria", rarity: "Incomum" }],
  };
  const poolKey = biomeKey.includes("vidro") ? "vidro" : biomeKey.includes("pantano") || biomeKey.includes("afogad") ? "pantano" : biomeKey.includes("ferrugem") ? "ferrugem" : biomeKey.includes("folhas") || biomeKey.includes("bosque") ? "folhas" : biomeKey.includes("carne") ? "carne" : biomeKey.includes("cinza") || biomeKey.includes("nomes") ? "cinzas" : biomeKey.includes("frio") || biomeKey.includes("dente") ? "gelo" : "default";
  const materialPool = pools[poolKey];
  const multiplier = Math.max(1, Math.round(Number(difficulty.multiplier || 1)));
  const routeBonus = biome.huntRoute === "deep" ? 2 : biome.huntRoute === "cautious" ? -1 : 0;
  const quantity = Math.max(1, (cancelled ? 1 : 2) + routeBonus + Math.floor(multiplier / 1.4) + Math.floor(rarityScore(pet.rarity) / 3));
  const material = materialPool[Math.floor(Math.random() * materialPool.length)];
  const drops = [{ ...material, quantity, categoryId: "especial", bonus: {}, source: "Pet Hunt" }];
  if (!cancelled && materialPool.length > 1 && Math.random() < 0.48) {
    const extra = materialPool.find((entry) => entry.id !== material.id) || material;
    drops.push({ ...extra, quantity: Math.max(1, Math.floor(quantity / 2)), categoryId: "especial", bonus: {}, source: "Pet Hunt" });
  }
  if (!cancelled && ["hard", "pesadelo", "god-slayer"].includes(difficulty.id) && Math.random() < 0.36) {
    drops.push({ id: "ferro-de-juramento", name: "Ferro de juramento", rarity: "Épico", quantity: Math.max(1, multiplier - 1), categoryId: "especial", bonus: {}, source: "Pet Hunt" });
  }
  if (!cancelled && ["pesadelo", "god-slayer"].includes(difficulty.id) && Math.random() < 0.2) {
    drops.push({ id: "selo-partido", name: "Selo partido", rarity: "Lendário", quantity: 1, categoryId: "especial", bonus: {}, source: "Pet Hunt" });
  }
  if (!cancelled && Math.random() < 0.42 + Math.min(0.18, rarityScore(pet.rarity) * 0.02)) {
    drops.push({ id: "reliquia-empoeirada", name: "Reliquia Empoeirada", rarity: "Raro", quantity: 1, categoryId: "especial", bonus: {}, source: "Pet Hunt", description: "Material ritual encontrado durante uma incursao." });
  }
  if (!cancelled && ["pesadelo", "god-slayer"].includes(difficulty.id) && Math.random() < 0.16) {
    drops.push({ id: "fragmento-do-heroi-quebrado", name: "Fragmento do Heroi Quebrado", rarity: "Celestial", quantity: 1, categoryId: "especial", bonus: {}, source: "Pet Hunt", description: "Uma parte rara da lenda da temporada." });
  }
  return drops;
}

function mergeInventoryLoot(inventory = [], drops = []) {
  const next = [...inventory];
  drops.forEach((drop) => {
    const index = next.findIndex((item) => item.sourceId === drop.id && item.source === drop.source && item.rarity === drop.rarity);
    if (index >= 0) next[index] = { ...next[index], quantity: Number(next[index].quantity || 1) + Number(drop.quantity || 1) };
    else next.push({ ...drop, instanceId: cryptoRandom(), sourceId: drop.id, equipped: false, quantity: Number(drop.quantity || 1), obtainedAt: new Date().toISOString() });
  });
  return next;
}

async function startPetHunt(form) {
  const values = formValues(form);
  const character = currentCharacter();
  const difficulty = difficultyById(values.difficulty || state.minigameDifficulty);
  const level = FOUNDATIONS.clampLevel(values.stageLevel || state.minigameLevel);
  if (!FOUNDATIONS.isMinigameLevelUnlocked(character, "hunt", difficulty.id, level)) return toast(`Conclua o nível ${level - 1} da Pet Hunt primeiro.`);
  const pet = (character.gachaVault || []).find((item) => item.instanceId === values.petId && item.kind === "pet");
  if (!pet || petBusy(pet)) {
    toast("Escolha um pet livre para a Hunt.");
    return;
  }
  const energyPatch = await spendGachaEnergy(difficulty.cost);
  if (!energyPatch) return;
  const biome = (state.content.biomes || []).find((item) => item.id === values.biome) || state.content.biomes?.[0] || {};
  const requestedDuration = Math.max(15, Math.min(60, Number(values.durationMinutes || 15)));
  const route = values.route || "balanced";
  const routeRisk = route === "deep" ? 1.45 : route === "cautious" ? 0.62 : 1;
  const durationRisk = requestedDuration >= 60 ? 1.35 : requestedDuration >= 30 ? 1.12 : 1;
  const duration = requestedDuration * 60000;
  const risk = Math.min(0.9, difficulty.risk * routeRisk * durationRisk * (1 + (level - 1) * 0.22) * Math.max(0.18, 1.15 - rarityScore(pet.rarity) * 0.08 - Number(pet.stars || 1) * 0.035));
  const activity = {
    id: cryptoRandom(),
    type: "Pet Hunt",
    petId: pet.instanceId,
    petSourceId: pet.sourceId || pet.id,
    petName: pet.name,
    petRarity: pet.rarity || "Comum",
    petImageUrl: petImageFor(pet),
    difficultyId: difficulty.id,
    difficultyName: difficulty.name,
    stageLevel: level,
    biome: biome.name || "Campo desconhecido",
    biomeId: biome.id || "",
    route,
    durationMinutes: requestedDuration,
    risk,
    startedAt: new Date().toISOString(),
    endsAt: new Date(Date.now() + duration).toISOString(),
    loot: huntLootFor({ ...biome, huntRoute: route }, difficulty, pet, false).map((item) => `${item.name} x${item.quantity}`),
    events: [
      `Saiu por ${biome.name || "uma rota desconhecida"} em rota ${route === "deep" ? "profunda" : route === "cautious" ? "cautelosa" : "equilibrada"}`,
      difficulty.id === "god-slayer" ? "A presença de um chefe foi sentida." : "Pegadas recentes cruzam o caminho.",
      Math.random() < 0.28 ? "Um baú antigo foi avistado entre as ruínas." : "Algo observa entre as sombras.",
      "A rota de retorno já pode ser traçada.",
    ],
  };
  const vault = (character.gachaVault || []).map((item) => item.instanceId === pet.instanceId ? { ...item, status: "Em Hunt", activityId: activity.id, equipped: false } : item);
  if (!state.demo && !MILLENNIUM_SPARK_MODE) {
    await beginTrustedMinigame({ id: activity.id, difficulty, level, petId: pet.instanceId, activity }, "hunt");
    delete state.minigameDrafts["pet-hunt"];
    form.reset();
    toast(`${pet.name} partiu para ${activity.biome}.`);
    return;
  }
  await updateCharacter(state.user.uid, {
    ...energyPatch,
    gachaVault: vault,
    activeActivities: [...(character.activeActivities || []), activity],
  });
  delete state.minigameDrafts["pet-hunt"];
  form.reset();
  toast(`${pet.name} partiu para ${activity.biome}.`);
}

async function completeActivity(activityId, cancelled = false) {
  if (!activityId || state.resolvingActivityIds.has(activityId)) {
    if (activityId) toast("Esta expedição já está sendo resolvida.");
    return;
  }
  state.resolvingActivityIds.add(activityId);
  try {
    const character = currentCharacter();
    const activity = (character.activeActivities || []).find((item) => item.id === activityId);
    if (!activity) return;
    const completionKeys = [...new Set(character.huntCompletionKeys || [])].slice(-79);
    if (completionKeys.includes(activityId)) {
      toast("Esta expedição já foi coletada.");
      return;
    }
    const ready = Date.now() >= (dateFromValue(activity.endsAt)?.getTime() || 0);
    const difficulty = difficultyById(activity.difficultyId);
    const pet = (character.gachaVault || []).find((item) => item.instanceId === activity.petId);
    const level = FOUNDATIONS.clampLevel(activity.stageLevel || 1);
    const score = Math.round((instancePower(pet || {}) * (cancelled ? 0.35 : ready ? 1 : 0.55)) * difficulty.multiplier * (1 + (level - 1) * 0.18));
    if (!state.demo && !MILLENNIUM_SPARK_MODE) {
      const reward = await callTrustedOperation("minigame", { mode: "hunt", difficultyId: difficulty.id, score, runId: activityId, level, cancelled });
      toast(`${activity.petName} voltou${reward.petStatus && reward.petStatus !== "Livre" ? ` ${String(reward.petStatus).toLowerCase()}` : ""}: ${(reward.loot || []).join(" · ")}${reward.unlockedNext ? ` · Nível ${level + 1} liberado` : ""}`);
      return;
    }
    const reward = minigameReward(activity.difficultyId, score, "hunt", level);
    const progression = FOUNDATIONS.recordMinigameProgress(character, "hunt", difficulty, level, score);
    const danger = Number(activity.risk || difficulty.risk);
    const deathRisk = cancelled ? danger * 0.08 : danger * (difficulty.id === "god-slayer" ? 0.34 : difficulty.id === "pesadelo" ? 0.18 : 0.08);
    const injuryRisk = cancelled ? danger * 0.25 : danger;
    const died = Math.random() < deathRisk && ["hard", "pesadelo", "god-slayer"].includes(difficulty.id);
    const fell = !died && Math.random() < injuryRisk && difficulty.id !== "noob";
    const status = died ? "Morto" : fell ? "Ferido" : "Livre";
    const fragments = withFragments(character, reward.fragmentName, reward.fragments + (cancelled ? 0 : 2));
    if (reward.rareDrop) fragments["Fragmentos do Despertar"] = Number(fragments["Fragmentos do Despertar"] || 0) + 1;
    fragments["Marcas de Caçada"] = Number(fragments["Marcas de Caçada"] || 0) + Math.max(1, Math.floor(Number(reward.fragments || 1) * (cancelled ? 0.5 : 1)));
    const biome = (state.content.biomes || []).find((item) => item.name === activity.biome) || {};
    const huntLoot = huntLootFor({ ...biome, huntRoute: activity.route || "balanced" }, difficulty, pet || {}, cancelled);
    const vault = (character.gachaVault || []).map((item) => item.instanceId === activity.petId ? { ...item, status, activityId: "", injuredAt: fell ? new Date().toISOString() : item.injuredAt || "" } : item);
    await updateCharacter(state.user.uid, {
      gachaVault: vault,
      activeActivities: (character.activeActivities || []).filter((item) => item.id !== activityId),
      huntCompletionKeys: [...completionKeys, activityId],
      minigameProgress: progression.progress,
      minigameStats: {
        ...(character.minigameStats || {}),
        hunt: {
          bestScore: Math.max(Number(character.minigameStats?.hunt?.bestScore || 0), score),
          plays: Number(character.minigameStats?.hunt?.plays || 0) + 1,
          [`${difficulty.id}Best`]: Math.max(Number(character.minigameStats?.hunt?.[`${difficulty.id}Best`] || 0), score),
        },
      },
      minigameHistory: [{ id: cryptoRandom(), completionKey: activityId, mode: "hunt", difficultyId: difficulty.id, difficultyName: difficulty.name, level, target: progression.target, score, grade: reward.grade, coins: reward.coins, fragments: reward.fragments, fragmentName: reward.fragmentName, createdAt: new Date().toISOString() }, ...(character.minigameHistory || [])].slice(0, 30),
      millenniumCoins: Number(character.millenniumCoins || 0) + (cancelled ? Math.floor(reward.coins * 0.35) : reward.coins),
      gachaFragments: fragments,
      inventory: mergeInventoryLoot(character.inventory || [], huntLoot),
      huntHistory: [{ id: cryptoRandom(), completionKey: activityId, biome: activity.biome, difficultyId: difficulty.id, petName: activity.petName, loot: huntLoot.map((item) => `${item.name} x${item.quantity}`), status, createdAt: new Date().toISOString() }, ...(character.huntHistory || [])].slice(0, 60),
    });
    if (reward.rareDrop) await announceRareReward(state.user.uid, "Fragmento do Herói Quebrado", "Celestial", "drop secreto");
    toast(`${activity.petName} voltou${died ? " morto" : fell ? " ferido" : ""}: ${[...reward.loot, ...huntLoot.map((item) => `${item.name} x${item.quantity}`)].join(" · ")}${progression.unlockedNext ? ` · Nível ${level + 1} liberado` : ""}`);
  } finally {
    state.resolvingActivityIds.delete(activityId);
  }
}

function routeLabel(type = "") {
  return ({ crossroads: "três ruas cruzadas", bridges: "pontes suspensas", ring: "uma arena circular", portals: "portais instáveis", citadel: "os andares da cidadela", marsh: "ilhas e marés", rails: "trilhos industriais", mirror: "duas rotas refletidas" })[type] || "uma rota desconhecida";
}

