          const selected = document.querySelector(`#codex-tab-${CSS.escape(state.codexTab)}`);
          selected?.focus({ preventScroll: true });
          window.scrollTo({ top: Number(state.codexScrollByTab[state.codexTab] || 0), behavior: "auto" });
